export const FICHES_DATA = [
  // ===== ANATOMIE =====
  { id: 'anatomie-osteologie', subject: 'anatomie', title: 'Ostéologie et arthrologie', summary: 'Les os du squelette humain, leur classification et les articulations.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Ostéologie : les os du squelette</h3><p class="mb-3">Le squelette humain adulte comprend <strong>206 os</strong>, répartis en squelette axial (80 os) et appendiculaire (126 os).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Classification des os</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Os longs</strong> : diaphyse + 2 épiphyses (fémur, humérus). Moelle jaune.</li><li><strong>Os courts</strong> : dimensions égales (carpe, tarse).</li><li><strong>Os plats</strong> : protection (pariétal, sternum, scapula). Moelle rouge.</li><li><strong>Os irréguliers</strong> : formes complexes (vertèbres, sphénoïde).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">La colonne vertébrale</h4><p class="mb-3">33-34 vertèbres : <strong>7 cervicales</strong> (C1 atlas, C2 axis), <strong>12 thoraciques</strong>, <strong>5 lombaires</strong>, <strong>5 sacrées</strong> (fusionnées), <strong>4-5 coccygiennes</strong>.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Arthrologie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Synarthroses</strong> (immobiles) : sutures crâniennes.</li><li><strong>Amphiarthroses</strong> (semi-mobiles) : symphyse pubienne.</li><li><strong>Diarthroses</strong> (mobiles) : genou, épaule, hanche. Liquide synovial.</li></ul><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé : Le fémur est l'os le plus long du corps. L'os hyoïde est le seul os non articulé avec un autre.</p></div>` },
  { id: 'anatomie-myologie', subject: 'anatomie', title: 'Myologie', summary: 'Les muscles squelettiques, leur classification et fonction motrice.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Myologie : les muscles</h3><p class="mb-3">Environ <strong>600 muscles squelettiques</strong> (40% masse corporelle). Motricité, posture et thermogenèse.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Types de muscles</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Striés squelettiques</strong> : contraction volontaire, rattachés aux os.</li><li><strong>Strié cardiaque</strong> : contraction involontaire (myocarde).</li><li><strong>Lisses</strong> : involontaire, parois des viscères et vaisseaux.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Membre supérieur</h4><p class="mb-3"><strong>Biceps brachial</strong> : fléchisseur. <strong>Triceps</strong> : extenseur. <strong>Deltoïde</strong> : abducteur. <strong>Coiffe des rotateurs</strong> : stabilisateurs de l'épaule.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Membre inférieur</h4><p class="mb-3"><strong>Quadriceps</strong> : extenseur du genou. <strong>Ischio-jambiers</strong> : fléchisseurs. <strong>Triceps sural</strong> : flexion plantaire.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé : L'unité motrice = 1 motoneurone + ses fibres musculaires. Le sarcomère (actine + myosine) est l'unité de contraction.</p></div>` },
  { id: 'anatomie-angiologie', subject: 'anatomie', title: 'Angiologie', summary: 'Le système cardiovasculaire et le réseau lymphatique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Angiologie : système vasculaire</h3><p class="mb-3">Deux circulations : <strong>systémique</strong> (grande) et <strong>pulmonaire</strong> (petite).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Artères principales</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Aorte</strong> : naît du ventricule gauche. Ascendante → crosse → descendante.</li><li><strong>Carotides</strong> : vascularisation cérébrale (interne) et face (externe).</li><li><strong>Coronaires</strong> : vascularisation du myocarde.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Système veineux</h4><p class="mb-3"><strong>Veines caves</strong> supérieure et inférieure → oreillette droite. Valvules anti-reflux.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Système lymphatique</h4><p class="mb-3">Drainage du liquide interstitiel, transport des lipides, immunité. <strong>Canal thoracique</strong> : principal collecteur.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé : Le polygone de Willis assure la suppléance vasculaire cérébrale. Les artères pulmonaires transportent du sang désoxygéné.</p></div>` },
  { id: 'anatomie-neuroanatomie', subject: 'anatomie', title: 'Neuroanatomie', summary: 'Le système nerveux central et périphérique, les nerfs crâniens.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Neuroanatomie</h3><p class="mb-3"><strong>SNC</strong> (encéphale + moelle spinale) et <strong>SNP</strong> (nerfs crâniens/spinaux + ganglions).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">L'encéphale</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Cerveau</strong> : 2 hémisphères, 4 lobes (frontal, pariétal, temporal, occipital).</li><li><strong>Cervelet</strong> : coordination motrice, équilibre.</li><li><strong>Tronc cérébral</strong> : fonctions vitales (respiration, rythme cardiaque).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">12 paires de nerfs crâniens</h4><p class="mb-3">I Olfactif, II Optique, III Oculomoteur, IV Trochléaire, V Trijumeau, VI Abducens, VII Facial, VIII Vestibulocochléaire, IX Glossopharyngien, X Vague, XI Accessoire, XII Hypoglosse.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Moelle spinale</h4><p class="mb-3">C1 à L1-L2. 31 paires de nerfs spinaux. Substance grise centrale (en H) + blanche périphérique.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé : Le nerf vague (X) est le plus long nerf crânien — innerve cœur, poumons et tube digestif.</p></div>` },
  { id: 'anatomie-splanchnologie', subject: 'anatomie', title: 'Splanchnologie', summary: 'Anatomie des organes thoraciques, abdominaux et pelviens.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Splanchnologie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Appareil digestif</h4><p class="mb-3">Bouche → pharynx → œsophage → estomac → intestin grêle (duodénum, jéjunum, iléon) → côlon → rectum. Glandes : foie, pancréas, glandes salivaires.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Appareil respiratoire</h4><p class="mb-3">Voies aériennes sup. et inf. → trachée → bronches → bronchioles → alvéoles. Poumon droit : 3 lobes. Gauche : 2 lobes. Surface d'échange : ~70 m².</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Appareil urinaire</h4><p class="mb-3"><strong>Reins</strong> (filtration 180L/jour → 1.5L urine) → uretères → vessie → urètre. Néphron = unité fonctionnelle.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé : Organes intrapéritonéaux (estomac, jéjunum) vs rétropéritonéaux (reins, pancréas, duodénum).</p></div>` },
  { id: 'anatomie-tete-cou', subject: 'anatomie', title: 'Anatomie de la tête et du cou', summary: 'Os du crâne, muscles masticateurs et régions cervicales.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Tête et cou</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le crâne</h4><p class="mb-3"><strong>Neurocrâne</strong> (8 os) : frontal, pariétaux, temporaux, occipital, sphénoïde, ethmoïde. <strong>Viscérocrâne</strong> (14 os). La mandibule est le seul os mobile du crâne.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Régions du cou</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Triangle antérieur</strong> : trachée, œsophage, thyroïde, carotides.</li><li><strong>Triangle postérieur</strong> : plexus brachial, artère subclavière.</li><li><strong>Muscle SCM</strong> : repère anatomique majeur.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Thyroïde</h4><p class="mb-3">Glande en papillon (C5-T1). Produit T3, T4 (métabolisme) et calcitonine (calcium).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé : Le nerf laryngé récurrent innerve les cordes vocales — sa lésion en chirurgie thyroïdienne cause une dysphonie.</p></div>` },

  // ===== CHIMIE / BIOCHIMIE =====
  { id: 'chimie-atomistique', subject: 'chimie', title: 'Atomistique et liaisons chimiques', summary: 'Structure atomique, configuration électronique et types de liaisons.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Atomistique et liaisons</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Structure de l'atome</h4><p class="mb-3">Noyau (protons Z+ et neutrons) + électrons. A = Z + N. Isotopes : même Z, N différent.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Configuration électronique</h4><p class="mb-3">Klechkowski : 1s² 2s² 2p⁶ 3s² 3p⁶ 4s² 3d¹⁰... Pauli : max 2 e⁻/orbitale. Hund : remplissage parallèle.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Types de liaisons</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Covalente</strong> : partage d'e⁻ (~150-400 kJ/mol). Polarisée si ΔEN > 0.4.</li><li><strong>Ionique</strong> : transfert d'e⁻ (ΔEN > 1.7).</li><li><strong>Hydrogène</strong> : ~10-40 kJ/mol. Essentielle en biochimie.</li><li><strong>Van der Waals</strong> : ~1-10 kJ/mol.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé : F est le plus électronégatif (4.0 Pauling). L'électronégativité croît → droite et ↑ haut du tableau.</p></div>` },
  { id: 'chimie-thermo', subject: 'chimie', title: 'Thermodynamique chimique', summary: 'Enthalpie, entropie, énergie libre de Gibbs et équilibres.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Thermodynamique chimique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Grandeurs fondamentales</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>ΔH</strong> (enthalpie) : < 0 = exothermique.</li><li><strong>ΔS</strong> (entropie) : > 0 = plus de désordre.</li><li><strong>ΔG = ΔH - TΔS</strong> : réaction spontanée si <strong>ΔG < 0</strong>.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Équilibres chimiques</h4><p class="mb-3">K = produits/réactifs. Q < K : directe. Q > K : inverse. <strong>Le Chatelier</strong> : le système s'oppose aux perturbations.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Acido-basique</h4><p class="mb-3">pH = -log[H⁺]. <strong>Henderson-Hasselbalch</strong> : pH = pKa + log([A⁻]/[AH]). Pouvoir tampon max quand pH = pKa.</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé : Le tampon bicarbonate (H₂CO₃/HCO₃⁻) maintient le pH sanguin à 7.4.</p></div>` },
  { id: 'chimie-organique', subject: 'chimie', title: 'Chimie organique fonctionnelle', summary: 'Fonctions organiques, stéréochimie et mécanismes réactionnels.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Chimie organique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Fonctions principales</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Alcool</strong> (-OH), <strong>Aldéhyde</strong> (-CHO), <strong>Cétone</strong> (C=O)</li><li><strong>Acide carboxylique</strong> (-COOH), <strong>Amine</strong> (-NH₂)</li><li><strong>Ester</strong> (-COO-), <strong>Amide</strong> (-CONH-) → liaison peptidique</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Stéréochimie</h4><p class="mb-3">C* (carbone asymétrique) : 4 substituants différents → chiralité. R/S (CIP). Les AA naturels sont L.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Mécanismes</h4><p class="mb-3"><strong>SN1</strong> : carbocation, racémisation. <strong>SN2</strong> : inversion de Walden. <strong>E1/E2</strong> : éliminations.</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé : La liaison peptidique (amide) est plane et rigide — caractère partiel de double liaison.</p></div>` },
  { id: 'chimie-biochimie-struct', subject: 'chimie', title: 'Biochimie structurale', summary: 'Glucides, lipides et protéines : structure et propriétés.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Biochimie structurale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Glucides</h4><p class="mb-3"><strong>Oses</strong> : glucose, fructose, galactose. <strong>Osides</strong> : saccharose, lactose, maltose. <strong>Polyosides</strong> : glycogène, amidon, cellulose.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lipides</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>AG saturés vs insaturés. Triglycérides = réserve énergétique.</li><li>Phospholipides = membranes. Cholestérol = précurseur hormonal.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Protéines</h4><p class="mb-3">20 AA. 4 niveaux : primaire (séquence), secondaire (hélice α, feuillet β), tertiaire (3D), quaternaire (sous-unités).</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé : 9 AA essentiels (non synthétisables) : His, Ile, Leu, Lys, Met, Phe, Thr, Trp, Val.</p></div>` },
  { id: 'chimie-enzymologie', subject: 'chimie', title: 'Enzymologie', summary: 'Cinétique de Michaelis-Menten et régulation enzymatique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Enzymologie</h3><p class="mb-3">Les enzymes sont des <strong>catalyseurs biologiques</strong> qui abaissent l'énergie d'activation.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Michaelis-Menten</h4><p class="mb-3"><strong>V = Vmax × [S] / (Km + [S])</strong>. Km = affinité (bas = forte). Lineweaver-Burk : 1/V vs 1/[S].</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Inhibitions</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Compétitive</strong> : site actif. Km↑, Vmax inchangée.</li><li><strong>Non compétitive</strong> : site allostérique. Km inchangé, Vmax↓.</li><li><strong>Incompétitive</strong> : complexe ES. Km↓ et Vmax↓.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé : Les enzymes allostériques ont une courbe sigmoïde (pas michaelienne).</p></div>` },
  { id: 'chimie-metabolisme', subject: 'chimie', title: 'Métabolisme énergétique', summary: 'Glycolyse, cycle de Krebs, chaîne respiratoire et β-oxydation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Métabolisme énergétique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Glycolyse (cytoplasme)</h4><p class="mb-3">Glucose → 2 Pyruvates. <strong>2 ATP + 2 NADH</strong>. Enzymes clés : hexokinase, PFK-1 (limitante), pyruvate kinase.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Cycle de Krebs (matrice mitochondriale)</h4><p class="mb-3">Acétyl-CoA → 2 CO₂. Par tour : <strong>3 NADH + 1 FADH₂ + 1 GTP</strong>.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Chaîne respiratoire</h4><p class="mb-3">NADH → complexes I-IV → O₂. ATP synthase (complexe V). 1 NADH ≈ 2.5 ATP, 1 FADH₂ ≈ 1.5 ATP.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">β-oxydation</h4><p class="mb-3">AG → acétyl-CoA. Chaque cycle : 1 NADH + 1 FADH₂ + 1 acétyl-CoA.</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé : 1 glucose = ~30-32 ATP (oxydation complète).</p></div>` },

  // ===== BIOLOGIE CELLULAIRE =====
  { id: 'biocell-membrane', subject: 'biocell', title: 'Membrane plasmique et transport', summary: 'Structure membranaire et mécanismes de transport.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Membrane et transport</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Structure</h4><p class="mb-3"><strong>Mosaïque fluide</strong> : bicouche phospholipidique + protéines + cholestérol (fluidité).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Transports passifs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Diffusion simple</strong> : O₂, CO₂ à travers la bicouche.</li><li><strong>Diffusion facilitée</strong> : canaux ioniques, GLUT (glucose).</li><li><strong>Osmose</strong> : eau via aquaporines.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Transports actifs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Pompe Na⁺/K⁺</strong> : 3 Na⁺ out, 2 K⁺ in par ATP.</li><li><strong>Endocytose/Exocytose</strong> : transport vésiculaire.</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé : La pompe Na⁺/K⁺ consomme ~30% de l'ATP au repos. Maintient le potentiel de repos (-70 mV).</p></div>` },
  { id: 'biocell-organites', subject: 'biocell', title: 'Organites cellulaires', summary: 'RE, Golgi, mitochondries, lysosomes et leurs fonctions.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Organites cellulaires</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">RE</h4><p class="mb-3"><strong>REG</strong> (ribosomes) : synthèse protéique. <strong>REL</strong> : lipides, détox, stockage Ca²⁺.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Appareil de Golgi</h4><p class="mb-3">Citernes cis → trans. Maturation (glycosylation), tri et adressage des protéines.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Mitochondries</h4><p class="mb-3">Double membrane. Crêtes = chaîne respiratoire. Matrice = Krebs. ADN propre circulaire. <strong>Héritage maternel.</strong></p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lysosomes</h4><p class="mb-3">pH ~5, hydrolases. Dégradation (autophagie, hétérophagie).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé : Maladies lysosomales = déficit enzymatique (Gaucher, Tay-Sachs).</p></div>` },
  { id: 'biocell-cycle', subject: 'biocell', title: 'Cycle cellulaire et mitose', summary: 'Phases du cycle, points de contrôle et division mitotique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Cycle cellulaire et mitose</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Phases</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>G1</strong> : croissance. Point de restriction R.</li><li><strong>S</strong> : réplication ADN (2n → 4n).</li><li><strong>G2</strong> : vérification.</li><li><strong>M</strong> : mitose + cytocinèse.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Mitose</h4><p class="mb-3"><strong>Prophase</strong> → <strong>Métaphase</strong> (plaque équatoriale) → <strong>Anaphase</strong> (séparation) → <strong>Télophase</strong>.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Régulation</h4><p class="mb-3"><strong>CDK + cyclines</strong> contrôlent la progression. <strong>p53</strong> = gardien du génome.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé : Mitose = 2 cellules filles identiques (2n). Cancer = perte de contrôle du cycle.</p></div>` },
  { id: 'biocell-meiose', subject: 'biocell', title: 'Méiose et gamétogenèse', summary: 'Division réductionnelle, brassage génétique et gamètes.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Méiose et gamétogenèse</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Méiose I (réductionnelle)</h4><p class="mb-3">Séparation des homologues (2n → n). <strong>Crossing-over</strong> en prophase I. Brassage interchromosomique en métaphase I.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Méiose II (équationnelle)</h4><p class="mb-3">Séparation des chromatides sœurs → <strong>4 cellules haploïdes</strong> différentes.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Gamétogenèse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Spermatogenèse</strong> : 1 spermatogonie → 4 spermatozoïdes (~74 jours).</li><li><strong>Ovogenèse</strong> : 1 ovogonie → 1 ovocyte + 3 globules polaires.</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé : 2²³ ≈ 8.4 millions de combinaisons par brassage interchromosomique seul.</p></div>` },
  { id: 'biocell-signalisation', subject: 'biocell', title: 'Signalisation cellulaire', summary: 'Voies de signalisation, récepteurs et seconds messagers.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Signalisation cellulaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Types</h4><p class="mb-3">Endocrine (hormones), paracrine (voisines), autocrine (soi-même), synaptique (neurotransmetteurs).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">RCPG</h4><p class="mb-3">7 domaines TM. Protéines G (Gs, Gi, Gq) → seconds messagers : AMPc, IP3, DAG, Ca²⁺.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">RTK</h4><p class="mb-3">Dimérisation → autophosphorylation → voie Ras/MAPK (prolifération) ou PI3K/Akt (survie).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Récepteurs nucléaires</h4><p class="mb-3">Ligands lipophiles (stéroïdes) → régulation de la transcription.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé : AMPc → active PKA → phosphoryle des protéines cibles.</p></div>` },
  { id: 'biocell-biomol', subject: 'biocell', title: 'Biologie moléculaire', summary: 'ADN → ARN → Protéine : le dogme central.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Biologie moléculaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">ADN</h4><p class="mb-3">Double hélice antiparallèle. A=T (2 liaisons H), G≡C (3 liaisons H). 3.2 milliards de pb.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Réplication</h4><p class="mb-3">Semi-conservative. ADN pol III (5'→3'). Brin directeur (continu) vs retardé (Okazaki). ADN ligase.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Transcription</h4><p class="mb-3">ARN pol II → ARNm. Maturation : coiffe 5', poly-A 3', épissage (introns excisés).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Traduction</h4><p class="mb-3">Ribosome lit les codons. AUG = start (Met). UAA/UAG/UGA = stop. Code dégénéré et universel.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé : ADN → ARNm → Protéine. Exception : rétrovirus (transcriptase inverse).</p></div>` },

  // ===== BIOSTATISTIQUES =====
  { id: 'biostats-descriptives', subject: 'biostats', title: 'Statistiques descriptives', summary: 'Tendance centrale, dispersion et loi normale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Statistiques descriptives</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Tendance centrale</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Moyenne</strong> : sensible aux extrêmes.</li><li><strong>Médiane</strong> : robuste aux outliers.</li><li><strong>Mode</strong> : valeur la plus fréquente.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Dispersion</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Variance</strong> (σ²) et <strong>écart-type</strong> (σ).</li><li><strong>IQR</strong> = Q3 - Q1 (50% centraux).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi normale</h4><p class="mb-3">Cloche (Gauss). 68% dans [μ±σ], 95% dans [μ±2σ], 99.7% dans [μ±3σ].</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé : CV = σ/x̄ × 100 permet de comparer des dispersions d'unités différentes.</p></div>` },
  { id: 'biostats-probabilites', subject: 'biostats', title: 'Probabilités et lois', summary: 'Calcul de probabilités, Bernoulli, binomiale, Poisson et loi normale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Probabilités</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Fondamentaux</h4><p class="mb-3">P(A∪B) = P(A)+P(B)-P(A∩B). Indépendance : P(A∩B)=P(A)×P(B). <strong>Bayes</strong> : P(A|B) = P(B|A)×P(A)/P(B).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lois discrètes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Bernoulli</strong> : succès (p) / échec (1-p).</li><li><strong>Binomiale</strong> B(n,p) : E=np, V=np(1-p).</li><li><strong>Poisson</strong> P(λ) : événements rares. E=V=λ.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi normale</h4><p class="mb-3">N(μ,σ²). Centrée réduite : Z = (X-μ)/σ ~ N(0,1).</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé : Théorème central limite — la moyenne d'un grand échantillon suit ~N(μ, σ²/n).</p></div>` },
  { id: 'biostats-tests', subject: 'biostats', title: 'Tests statistiques', summary: 'Tests d\'hypothèse, t de Student, Chi-2 et ANOVA.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Tests statistiques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">H0 vs H1. Statistique de test → p-value. Si p < 0.05 : on rejette H0.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Choix du test</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>t de Student</strong> : 2 moyennes.</li><li><strong>Chi-2</strong> : proportions, variables qualitatives.</li><li><strong>ANOVA</strong> : 3+ moyennes (test F).</li><li><strong>Non paramétriques</strong> : Mann-Whitney, Kruskal-Wallis.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Erreurs</h4><p class="mb-3">Type I (α) : faux positif. Type II (β) : faux négatif. Puissance = 1-β.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé : La p-value n'est PAS la probabilité que H0 soit vraie.</p></div>` },
  { id: 'biostats-epidemio', subject: 'biostats', title: 'Épidémiologie', summary: 'Prévalence, incidence, RR, OR et types d\'études.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Épidémiologie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Fréquence</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Prévalence</strong> : cas existants / population (photo).</li><li><strong>Incidence</strong> : nouveaux cas / population à risque (film).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Association</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>RR</strong> (cohorte) : risque exposés / non exposés.</li><li><strong>OR</strong> (cas-témoins) : cote exposés / non exposés. OR ≈ RR si maladie rare.</li><li>=1 : pas d'association. >1 : risque. <1 : protecteur.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Études</h4><p class="mb-3">Essai randomisé > cohorte > cas-témoins > transversale. Biais : sélection, classement, confusion.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé : La randomisation contrôle les facteurs de confusion.</p></div>` },
  { id: 'biostats-lecture', subject: 'biostats', title: 'Lecture critique d\'articles', summary: 'Analyser et critiquer un article de recherche médicale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Lecture critique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Structure IMRAD</h4><p class="mb-3"><strong>I</strong>ntroduction, <strong>M</strong>éthodes, <strong>R</strong>ésultats, <strong>D</strong>iscussion.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Questions clés</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Objectif clair ? Type d'étude adapté ?</li><li>Population représentative ? Critères d'inclusion pertinents ?</li><li>Tests statistiques appropriés ?</li><li>Résultats cliniquement significatifs ?</li><li>Biais identifiés et discutés ?</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Niveaux de preuve</h4><p class="mb-3">1 : méta-analyses/essais randomisés. 2 : cohortes. 3 : cas-témoins. 4 : séries de cas. 5 : avis d'expert.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé : L'IC à 95% est plus informatif que la p-value — il donne la précision et la taille de l'effet.</p></div>` },
  { id: 'biostats-sensibilite', subject: 'biostats', title: 'Sensibilité, spécificité, VPP, VPN', summary: 'Performances des tests diagnostiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Tests diagnostiques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Paramètres intrinsèques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Sensibilité</strong> = VP/(VP+FN) : détecter les malades. SnNout.</li><li><strong>Spécificité</strong> = VN/(VN+FP) : identifier les non-malades. SpPin.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Valeurs prédictives</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>VPP</strong> = VP/(VP+FP) : dépend de la prévalence ↑.</li><li><strong>VPN</strong> = VN/(VN+FN) : dépend de la prévalence ↓.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Courbe ROC</h4><p class="mb-3">Se vs 1-Sp. AUC : 0.5 = inutile, 1 = parfait.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé : Dépistage → forte Se. Confirmation → forte Sp.</p></div>` },

  // ===== BIOPHYSIQUE =====
  { id: 'biophysique-optique', subject: 'biophysique', title: 'Optique géométrique et physiologique', summary: 'Réfraction, lentilles, vergence et optique de l\'œil.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Optique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Snell-Descartes</h4><p class="mb-3">n₁ sin(i₁) = n₂ sin(i₂). Réflexion totale si i > angle critique.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lentilles</h4><p class="mb-3">V = 1/f (dioptries). Convergente : V>0. Divergente : V<0. Conjugaison : 1/OA' - 1/OA = 1/f.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">L'œil</h4><p class="mb-3">~60 dioptries. Cornée (2/3) + cristallin. <strong>Myopie</strong> : lentille divergente. <strong>Hypermétropie</strong> : convergente.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé : Presbytie = perte d'accommodation du cristallin avec l'âge.</p></div>` },
  { id: 'biophysique-ondes', subject: 'biophysique', title: 'Ondes et ultrasons', summary: 'Propriétés des ondes et échographie.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Ondes et ultrasons</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Propriétés</h4><p class="mb-3">v = λ × f. Son ~340 m/s. Ultrasons : f > 20 kHz. Échographie : 2-15 MHz.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Échographie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Émission → réflexion aux interfaces → échos.</li><li><strong>Impédance Z</strong> = ρ × v. Grand contraste = écho fort.</li><li><strong>Doppler</strong> : mesure la vitesse du sang.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé : Le gel élimine l'air (interface air-tissu = 100% réflexion).</p></div>` },
  { id: 'biophysique-radioactivite', subject: 'biophysique', title: 'Radioactivité et radioprotection', summary: 'Rayonnements, décroissance et principes de radioprotection.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Radioactivité</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Rayonnements</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>α</strong> : noyau He. Très ionisant, faible pénétration.</li><li><strong>β⁻</strong> : électron. Pénétration moyenne.</li><li><strong>γ</strong> : photon haute énergie. Très pénétrant.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Décroissance</h4><p class="mb-3">N(t) = N₀ × e^(-λt). T½ = ln2/λ. Activité A (Bq) = λN.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Dosimétrie</h4><p class="mb-3">Gray (dose absorbée) → Sievert (dose équivalente/efficace).</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé : 3 principes = justification, optimisation (ALARA), limitation.</p></div>` },
  { id: 'biophysique-imagerie', subject: 'biophysique', title: 'Imagerie médicale', summary: 'Radiologie, scanner, IRM, scintigraphie et TEP.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Imagerie médicale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Radiologie / Scanner</h4><p class="mb-3">Rayons X. Scanner = coupes axiales. Hounsfield : air=-1000, eau=0, os=+1000.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">IRM</h4><p class="mb-3">Champ magnétique + RF. <strong>T1</strong> : graisse brillante. <strong>T2</strong> : eau brillante. Pas d'ionisation.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Médecine nucléaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Scintigraphie</strong> : traceur (Tc-99m) + gamma-caméra.</li><li><strong>TEP</strong> : FDG (F-18). Photons 511 keV. Oncologie.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé : CI IRM = pacemaker, implants ferromagnétiques. Gadolinium CI si IR sévère.</p></div>` },
  { id: 'biophysique-solutions', subject: 'biophysique', title: 'Biophysique des solutions', summary: 'Osmose, pression osmotique et diffusion.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Solutions</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Osmose</h4><p class="mb-3">Hypotonique → hypertonique. π = CRT (Van't Hoff).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Tonicité</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Isotonique</strong> (~300 mOsm/L) : NaCl 0.9%.</li><li><strong>Hypertonique</strong> : cellule se rétracte.</li><li><strong>Hypotonique</strong> : cellule gonfle → lyse.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Diffusion (Fick)</h4><p class="mb-3">J = -D × (dC/dx). Proportionnel au gradient de concentration.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé : Osm plasmatique ≈ 2×[Na⁺] + [glucose] + [urée] ≈ 300 mOsm/L.</p></div>` },
  { id: 'biophysique-rmn', subject: 'biophysique', title: 'Bases de la RMN', summary: 'Résonance magnétique nucléaire et principes de l\'IRM.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">RMN</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">Noyaux de spin ½ (¹H) dans champ B0 → aimantation M0. Fréquence de Larmor : ω₀ = γB₀.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Relaxation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>T1</strong> (spin-réseau) : retour de Mz. Graisse ~250ms, eau ~2000ms.</li><li><strong>T2</strong> (spin-spin) : décroissance de Mxy. T2 ≤ T1.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">IRM</h4><p class="mb-3">Gradients de champ → codage spatial. Contraste selon T1, T2 et densité de protons.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé : 1.5T ou 3T en clinique. Plus B0 est intense, meilleur est le signal/bruit.</p></div>` },

  // ===== SSH / ÉTHIQUE =====
  { id: 'ssh-ethique', subject: 'ssh', title: 'Éthique médicale', summary: 'Les 4 principes de Beauchamp & Childress.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Éthique médicale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">4 principes</h4><ul class="list-disc pl-5 space-y-2 mb-4 text-gray-700"><li><strong>Autonomie</strong> : respecter les décisions du patient.</li><li><strong>Bienfaisance</strong> : agir pour son bien-être.</li><li><strong>Non-malfaisance</strong> : primum non nocere.</li><li><strong>Justice</strong> : équité d'accès aux soins.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Consentement éclairé</h4><p class="mb-3">Information loyale, claire et appropriée. Consentement libre.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Dilemmes</h4><p class="mb-3">Autonomie vs bienfaisance (refus de traitement), justice vs bienfaisance (ressources limitées).</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé : Secret médical (art. L1110-4 CSP). Exceptions : MDO, maltraitance mineur, danger tiers.</p></div>` },
  { id: 'ssh-droit', subject: 'ssh', title: 'Droit de la santé', summary: 'Lois Kouchner, Leonetti et Claeys-Leonetti.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Droit de la santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi Kouchner (2002)</h4><p class="mb-3">Droits des patients : information, consentement, accès au dossier, refus de soins, dignité.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi Leonetti (2005)</h4><p class="mb-3">Fin de vie : interdiction obstination déraisonnable, directives anticipées, personne de confiance.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi Claeys-Leonetti (2016)</h4><p class="mb-3"><strong>Sédation profonde et continue</strong>. Directives anticipées contraignantes.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Responsabilité</h4><p class="mb-3">Obligation de <strong>moyens</strong> (pas de résultat). Civile, pénale, disciplinaire.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé : L'euthanasie active reste interdite en France.</p></div>` },
  { id: 'ssh-psychologie', subject: 'ssh', title: 'Psychologie médicale', summary: 'Relation médecin-patient et mécanismes de défense.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Psychologie médicale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Relation médecin-patient</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Paternaliste</strong> : le médecin décide.</li><li><strong>Informatif</strong> : le patient décide.</li><li><strong>Délibératif</strong> : décision partagée (recommandé).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Mécanismes de défense</h4><p class="mb-3">Déni, régression, projection agressive, rationalisation, déplacement.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Deuil (Kübler-Ross)</h4><p class="mb-3">Déni → Colère → Marchandage → Dépression → Acceptation.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé : Transfert et contre-transfert influencent la relation thérapeutique.</p></div>` },
  { id: 'ssh-sociologie', subject: 'ssh', title: 'Sociologie de la santé', summary: 'Inégalités sociales et système de soins français.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Sociologie de la santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Déterminants sociaux</h4><p class="mb-3">Niveau socio-économique, environnement, comportements, accès aux soins.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Inégalités</h4><p class="mb-3">Un cadre vit ~6 ans de plus qu'un ouvrier. Gradient social présent dès l'enfance.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Système français</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Sécu (1945) : cotisations + CSG.</li><li>Parcours de soins : médecin traitant → spécialiste.</li><li>CSS pour les précaires. Déserts médicaux.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé : Littératie en santé = capacité à comprendre l'information de santé.</p></div>` },
  { id: 'ssh-histoire', subject: 'ssh', title: 'Histoire de la médecine', summary: 'D\'Hippocrate à Watson & Crick, les grandes étapes.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Histoire de la médecine</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Antiquité</h4><p class="mb-3"><strong>Hippocrate</strong> : 4 humeurs, serment. <strong>Galien</strong> : anatomie, physiologie.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Renaissance</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Vésale</strong> (1543) : anatomie moderne.</li><li><strong>Harvey</strong> (1628) : circulation sanguine.</li><li><strong>Jenner</strong> (1796) : premier vaccin.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">XIXe-XXe siècles</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Pasteur</strong> : germes, vaccins. <strong>Koch</strong> : bacille TB.</li><li><strong>Fleming</strong> (1928) : pénicilline.</li><li><strong>Watson & Crick</strong> (1953) : double hélice ADN.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé : Code de Nuremberg (1947) et Déclaration d'Helsinki (1964) = éthique de la recherche.</p></div>` },
  { id: 'ssh-philosophie', subject: 'ssh', title: 'Philosophie du soin', summary: 'Courants éthiques et notion de care.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Philosophie du soin</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Courants éthiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Kant</strong> (déontologisme) : agir par devoir, principes universalisables.</li><li><strong>Bentham/Mill</strong> (utilitarisme) : maximiser le bien-être global.</li><li><strong>Aristote</strong> (vertus) : développer compassion, prudence, justice.</li><li><strong>Gilligan/Tronto</strong> (care) : attention à la vulnérabilité.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Cure vs Care</h4><p class="mb-3"><strong>Cure</strong> = guérir (biomédical). <strong>Care</strong> = prendre soin (humaniste). Intégration des deux.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé : Ricœur — "la visée de la vie bonne, avec et pour autrui, dans des institutions justes".</p></div>` },

  // ===== ANATOMIE — FICHES APPROFONDIES =====
  { id: 'anatomie-coeur', subject: 'anatomie', title: 'Anatomie du cœur', summary: 'Configuration interne, vascularisation coronaire et système de conduction.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Le cœur : anatomie détaillée</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Situation et morphologie</h4><p class="mb-3">Organe musculaire creux, ~300g, situé dans le <strong>médiastin antérieur</strong>. Apex orienté en bas, à gauche et en avant. Enveloppé par le <strong>péricarde</strong> (feuillet fibreux + séreux).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Configuration interne</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>4 cavités</strong> : 2 oreillettes (atria) + 2 ventricules, séparées par le septum interauriculaire et interventriculaire.</li><li><strong>Valves auriculo-ventriculaires</strong> : mitrale (bicuspide, gauche) et tricuspide (droite).</li><li><strong>Valves sigmoïdes</strong> : aortique (3 valvules semi-lunaires) et pulmonaire.</li><li>Paroi ventriculaire gauche 3x plus épaisse que la droite (~15mm vs ~5mm).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Vascularisation coronaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Coronaire gauche</strong> : tronc commun → IVA (interventriculaire antérieure) + artère circonflexe. Irrigue paroi antérieure et latérale du VG.</li><li><strong>Coronaire droite</strong> : sillon AV droit → IVP (interventriculaire postérieure). Irrigue VD et paroi inférieure du VG.</li><li>Le retour veineux se fait par le <strong>sinus coronaire</strong> → oreillette droite.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Système de conduction</h4><p class="mb-3"><strong>Nœud sinusal</strong> (Keith et Flack, oreillette droite) → nœud auriculo-ventriculaire (Aschoff-Tawara) → faisceau de His → branches droite/gauche → réseau de Purkinje. Fréquence intrinsèque : nœud sinusal ~70-80 bpm, nœud AV ~40-60, His ~20-40.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : L'IVA est l'artère la plus fréquemment atteinte dans l'infarctus du myocarde. La valve mitrale est la plus souvent touchée par les valvulopathies rhumatismales.</p></div>` },
  { id: 'anatomie-membre-sup', subject: 'anatomie', title: 'Membre supérieur détaillé', summary: 'Os, articulations, muscles et innervation du membre supérieur.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Membre supérieur</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Squelette</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Ceinture scapulaire</strong> : clavicule + scapula. Articulation sterno-claviculaire (seul lien osseux avec le tronc).</li><li><strong>Bras</strong> : humérus. Col chirurgical = zone de fracture fréquente.</li><li><strong>Avant-bras</strong> : radius (latéral) + ulna (médial). Membrane interosseuse = pronation/supination.</li><li><strong>Main</strong> : 8 os du carpe (scaphoïde = fracture fréquente), 5 métacarpiens, 14 phalanges.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Articulation de l'épaule</h4><p class="mb-3">Articulation <strong>gléno-humérale</strong> : la plus mobile du corps (énarthrose). Stabilisée par la coiffe des rotateurs (supra-épineux, infra-épineux, petit rond, subscapulaire) et le bourrelet glénoïdien. Grande amplitude mais instable → luxations fréquentes (antéro-interne ++).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Plexus brachial</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Racines <strong>C5-T1</strong> → troncs → faisceaux → nerfs terminaux.</li><li><strong>N. musculo-cutané</strong> (C5-C7) : flexion du coude (biceps).</li><li><strong>N. médian</strong> (C5-T1) : pronation, flexion des doigts. Syndrome du canal carpien.</li><li><strong>N. ulnaire</strong> (C8-T1) : muscles intrinsèques de la main. Griffe ulnaire si lésion.</li><li><strong>N. radial</strong> (C5-T1) : extension du poignet et des doigts. Main tombante si lésion.</li><li><strong>N. axillaire</strong> (C5-C6) : deltoïde. Lésé dans les luxations d'épaule.</li></ul><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le nerf radial passe dans la gouttière de torsion de l'humérus → vulnérable dans les fractures de la diaphyse humérale. Le scaphoïde est l'os du carpe le plus souvent fracturé.</p></div>` },
  { id: 'anatomie-membre-inf', subject: 'anatomie', title: 'Membre inférieur détaillé', summary: 'Os, articulations, muscles et innervation du membre inférieur.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Membre inférieur</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Squelette</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Os coxal</strong> : ilium + ischium + pubis. Cotyle (acétabulum) → articulation coxo-fémorale.</li><li><strong>Fémur</strong> : os le plus long. Col fémoral (fractures du col chez le sujet âgé). Angle cervico-diaphysaire ~125°.</li><li><strong>Patella</strong> : os sésamoïde le plus volumineux.</li><li><strong>Jambe</strong> : tibia (médial, porteur) + fibula (latéral). Membrane interosseuse.</li><li><strong>Pied</strong> : tarse (7 os dont talus et calcanéus), 5 métatarsiens, 14 phalanges.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Articulation du genou</h4><p class="mb-3">Plus grande articulation du corps. <strong>Ménisques</strong> médial et latéral (amortisseurs). <strong>Ligaments croisés</strong> : LCA (antérieur, le plus lésé) et LCP. Ligaments collatéraux médial et latéral. Tiroir antérieur = signe de rupture du LCA.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Innervation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Plexus lombaire</strong> (L1-L4) : n. fémoral (quadriceps, extension genou), n. obturateur (adducteurs).</li><li><strong>Plexus sacré</strong> (L4-S3) : n. sciatique (le plus gros nerf du corps) → n. tibial + n. fibulaire commun.</li><li><strong>N. fibulaire commun</strong> : contourne le col de la fibula (vulnérable). Lésion → pied tombant (steppage).</li></ul><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le triangle de Scarpa contient l'artère fémorale (point de ponction). Le nerf sciatique sort par la grande échancrure sciatique sous le muscle piriforme.</p></div>` },
  { id: 'anatomie-sna', subject: 'anatomie', title: 'Système nerveux autonome', summary: 'Sympathique, parasympathique et régulation végétative.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Système nerveux autonome (SNA)</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Organisation générale</h4><p class="mb-3">Le SNA contrôle les fonctions involontaires : cœur, vaisseaux, digestion, sécrétions, pupille. Deux voies neuronales en série : <strong>neurone préganglionnaire</strong> (SNC) → ganglion → <strong>neurone postganglionnaire</strong> (organe cible).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Sympathique (thoraco-lombaire)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Origine : <strong>T1-L2</strong>. Chaîne ganglionnaire paravertébrale.</li><li>Neurotransmetteur préganglionnaire : <strong>acétylcholine</strong> (nicotinique).</li><li>Neurotransmetteur postganglionnaire : <strong>noradrénaline</strong> (récepteurs α et β).</li><li>Effets : tachycardie, mydriase, bronchodilatation, vasoconstriction, inhibition digestive. Réponse fight or flight.</li><li>Exception : <strong>médullosurrénale</strong> = ganglion modifié → adrénaline dans le sang.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Parasympathique (crânio-sacré)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Origine : nerfs crâniens <strong>III, VII, IX, X</strong> + <strong>S2-S4</strong>.</li><li>Le <strong>nerf vague (X)</strong> assure 75% de l'innervation parasympathique.</li><li>Neurotransmetteur pré et postganglionnaire : <strong>acétylcholine</strong> (muscarinique en post).</li><li>Effets : bradycardie, myosis, bronchoconstriction, stimulation digestive. Réponse rest and digest.</li></ul><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : L'atropine bloque les récepteurs muscariniques (parasympatholytique) → tachycardie, mydriase. Les β-bloquants inhibent le sympathique → bradycardie.</p></div>` },
  { id: 'anatomie-respiratoire', subject: 'anatomie', title: 'Appareil respiratoire détaillé', summary: 'Anatomie des voies aériennes, poumons, plèvre et mécanique ventilatoire.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Appareil respiratoire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies aériennes supérieures</h4><p class="mb-3">Fosses nasales (réchauffement, humidification, filtration) → pharynx (carrefour aérodigestif) → <strong>larynx</strong> (cartilages thyroïde, cricoïde, aryténoïdes; cordes vocales; épiglotte pour la déglutition).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies aériennes inférieures</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Trachée</strong> : 16-20 anneaux cartilagineux en C. Bifurque en T4-T5 (carène/carina).</li><li><strong>Bronche souche droite</strong> : plus verticale, plus courte, plus large → inhalation de corps étrangers ++.</li><li>Division : bronches lobaires → segmentaires → sous-segmentaires → bronchioles → bronchioles terminales → bronchioles respiratoires → canaux alvéolaires → <strong>alvéoles</strong>.</li><li>~300 millions d'alvéoles. Surface d'échange ~70-80 m². Barrière alvéolo-capillaire ~0.5 μm.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Poumons et plèvre</h4><p class="mb-3">Poumon droit : <strong>3 lobes</strong> (sup, moy, inf) séparés par 2 scissures. Poumon gauche : <strong>2 lobes</strong> + lingula. <strong>Plèvre</strong> : feuillet viscéral (poumon) + pariétal (paroi), espace pleural avec pression négative (-5 cmH2O).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Vascularisation</h4><p class="mb-3"><strong>Circulation fonctionnelle</strong> : artères pulmonaires (sang désoxygéné) → capillaires alvéolaires → veines pulmonaires (sang oxygéné) → OG. <strong>Circulation nourricière</strong> : artères bronchiques (issues de l'aorte).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le pneumothorax rompt la pression négative pleurale → rétraction pulmonaire. Le surfactant (pneumocytes II) diminue la tension superficielle et empêche le collapsus alvéolaire.</p></div>` },
  { id: 'anatomie-urogenital', subject: 'anatomie', title: 'Appareil urogénital', summary: 'Reins, voies urinaires et anatomie génitale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Appareil urogénital</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Les reins</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Organes <strong>rétropéritonéaux</strong>, en regard de T12-L3. Rein droit légèrement plus bas (foie).</li><li>Structure : capsule → cortex (glomérules, TCP, TCD) → médullaire (pyramides de Malpighi, anses de Henlé, tubes collecteurs) → calices → bassinet.</li><li><strong>Néphron</strong> = unité fonctionnelle (~1 million/rein). Glomérule (filtration) → TCP (réabsorption 65%) → anse de Henlé (concentration) → TCD → tube collecteur.</li><li>Filtration glomérulaire : ~180 L/jour → 1.5 L d'urine. DFG normal : 120 mL/min.</li><li>Vascularisation : artère rénale (branche de l'aorte) → artères segmentaires → interlobaires → arquées → interlobulaires → artérioles afférentes → glomérule → artérioles efférentes.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies urinaires</h4><p class="mb-3">Calices → bassinet → <strong>uretère</strong> (25-30 cm, 3 rétrécissements : jonction pyélo-urétérale, croisement iliaque, jonction vésico-urétérale = sites de blocage des calculs) → <strong>vessie</strong> (trigone vésical) → <strong>urètre</strong>.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Fonctions endocrines du rein</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Rénine</strong> → système rénine-angiotensine-aldostérone (SRAA) → régulation de la PA.</li><li><strong>Érythropoïétine (EPO)</strong> → stimulation de l'érythropoïèse.</li><li><strong>1,25-dihydroxyvitamine D</strong> (calcitriol) → métabolisme phosphocalcique.</li></ul><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : L'artère rénale est terminale (pas d'anastomose) → l'occlusion provoque un infarctus rénal. La clairance de la créatinine estime le DFG.</p></div>` },

  // ===== CHIMIE — FICHES APPROFONDIES =====
  { id: 'chimie-classification', subject: 'chimie', title: 'Classification périodique', summary: 'Tableau périodique, propriétés atomiques et tendances.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Classification périodique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Structure du tableau</h4><p class="mb-3"><strong>7 périodes</strong> (lignes = couches électroniques remplies) et <strong>18 groupes</strong> (colonnes = même nombre d'électrons de valence). Blocs s, p, d, f selon la sous-couche en cours de remplissage.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Configuration électronique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Remplissage selon la règle de <strong>Klechkowski</strong> : 1s 2s 2p 3s 3p 4s 3d 4p...</li><li>Règle de <strong>Hund</strong> : remplir chaque orbitale d'une sous-couche avec 1 e⁻ avant d'apparier.</li><li><strong>Principe d'exclusion de Pauli</strong> : max 2 e⁻ par orbitale, de spins opposés.</li><li>Exceptions notables : Cr [Ar] 3d⁵4s¹ et Cu [Ar] 3d¹⁰4s¹ (stabilité des sous-couches demi-remplies ou remplies).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Propriétés périodiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Rayon atomique</strong> : augmente vers le bas et vers la gauche (ajout de couches, moins d'attraction).</li><li><strong>Énergie d'ionisation</strong> : augmente vers le haut et la droite (plus difficile d'arracher un e⁻).</li><li><strong>Électronégativité</strong> (Pauling) : augmente vers le haut et la droite. F (3.98) > O > N > Cl.</li><li><strong>Affinité électronique</strong> : max pour les halogènes (ajout d'1 e⁻ = configuration de gaz noble).</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Les gaz nobles (groupe 18) ont une couche de valence complète → quasi inertes. L'électronégativité gouverne la polarité des liaisons (ΔEN > 1.7 → liaison ionique).</p></div>` },
  { id: 'chimie-acido-basique', subject: 'chimie', title: 'Équilibres acido-basiques', summary: 'pH, tampons, Henderson-Hasselbalch et applications biologiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Équilibres acido-basiques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définitions</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Brønsted</strong> : acide = donneur de H⁺, base = accepteur de H⁺.</li><li><strong>Lewis</strong> : acide = accepteur de doublet, base = donneur de doublet.</li><li>pH = -log[H⁺]. Ke = [H⁺][OH⁻] = 10⁻¹⁴ à 25°C.</li><li>pKa = -log(Ka). Plus pKa est faible, plus l'acide est fort.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Équation de Henderson-Hasselbalch</h4><p class="mb-3"><strong>pH = pKa + log([A⁻]/[AH])</strong>. Quand [A⁻] = [AH] → pH = pKa (pouvoir tampon maximal). Zone tampon efficace : pKa ± 1.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Tampons biologiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Tampon bicarbonate</strong> (sang) : CO₂ + H₂O ⇌ H₂CO₃ ⇌ HCO₃⁻ + H⁺. pKa = 6.1. pH sanguin = 7.40 ± 0.02. Rapport [HCO₃⁻]/[CO₂] = 20/1.</li><li><strong>Tampon phosphate</strong> : H₂PO₄⁻/HPO₄²⁻ (pKa = 6.8). Important au niveau intracellulaire et rénal.</li><li><strong>Tampon protéinate</strong> : histidine (pKa ~6.0) des protéines plasmatiques et de l'hémoglobine.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Troubles acido-basiques</h4><p class="mb-3">Acidose métabolique (↓HCO₃⁻), acidose respiratoire (↑pCO₂), alcalose métabolique (↑HCO₃⁻), alcalose respiratoire (↓pCO₂). Compensation rénale ou respiratoire.</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le tampon bicarbonate est ouvert (CO₂ éliminé par les poumons, HCO₃⁻ régulé par les reins) → capacité tampon supérieure à ce que prédirait son pKa seul.</p></div>` },
  { id: 'chimie-cinetique', subject: 'chimie', title: 'Cinétique chimique', summary: 'Vitesse de réaction, ordres, Arrhenius et catalyse.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Cinétique chimique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Vitesse de réaction</h4><p class="mb-3">v = -d[réactif]/dt = +d[produit]/dt. Loi de vitesse : <strong>v = k[A]ᵃ[B]ᵇ</strong> où a+b = ordre global, k = constante de vitesse.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Ordres de réaction</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Ordre 0</strong> : [A] = [A]₀ - kt. v constante. t½ = [A]₀/2k. Graphe [A] vs t = droite décroissante.</li><li><strong>Ordre 1</strong> : [A] = [A]₀ × e⁻ᵏᵗ. t½ = ln2/k (indépendant de [A]₀). Graphe ln[A] vs t = droite.</li><li><strong>Ordre 2</strong> : 1/[A] = 1/[A]₀ + kt. t½ = 1/(k[A]₀). Graphe 1/[A] vs t = droite.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi d'Arrhenius</h4><p class="mb-3"><strong>k = A × e⁻ᴱᵃ/ᴿᵀ</strong>. A = facteur de fréquence, Ea = énergie d'activation. Augmenter T de 10°C double environ la vitesse. Graphe ln(k) vs 1/T = droite de pente -Ea/R.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Catalyse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Le catalyseur <strong>abaisse Ea</strong> sans modifier la thermodynamique (ΔG inchangé).</li><li><strong>Catalyse homogène</strong> : même phase que les réactifs.</li><li><strong>Catalyse hétérogène</strong> : phase différente (surface solide).</li><li><strong>Catalyse enzymatique</strong> : spécificité, conditions douces (37°C, pH ~7).</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : La radioactivité suit une cinétique d'ordre 1 (t½ constant). Les enzymes sont des catalyseurs biologiques qui accélèrent les réactions d'un facteur 10⁶ à 10¹² sans être consommées.</p></div>` },
  { id: 'chimie-acides-nucleiques', subject: 'chimie', title: 'Acides nucléiques', summary: 'Structure de l\'ADN et ARN, bases azotées et appariements.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Acides nucléiques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Nucléotides</h4><p class="mb-3">Unité de base = <strong>base azotée + pentose + phosphate</strong>. Nucléoside = base + sucre (sans phosphate). Liaison N-glycosidique entre la base et le C1' du sucre.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Bases azotées</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Purines</strong> (2 cycles) : Adénine (A) et Guanine (G). Mnémotechnique : les PURines sont les plus GRAndes (AGR).</li><li><strong>Pyrimidines</strong> (1 cycle) : Cytosine (C), Thymine (T, ADN), Uracile (U, ARN).</li><li>Appariement de Watson-Crick : <strong>A=T</strong> (2 liaisons H), <strong>G≡C</strong> (3 liaisons H). Règle de Chargaff : %A=%T, %G=%C.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">ADN</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Double hélice, antiparallèle (5'→3' / 3'→5'). Sucre = <strong>désoxyribose</strong>.</li><li>Forme B (physiologique) : pas de 3.4 nm, 10 pb/tour, diamètre 2 nm.</li><li>Sillon majeur (accessible aux protéines régulatrices) et sillon mineur.</li><li>Température de fusion (Tm) : plus riche en GC → Tm élevée (3 liaisons H vs 2).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">ARN</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Simple brin, sucre = <strong>ribose</strong> (OH en 2'), U remplace T.</li><li><strong>ARNm</strong> : coiffe 5', queue poly-A 3'. Codons de 3 nucléotides.</li><li><strong>ARNt</strong> : structure en trèfle/L. Anticodon + site d'accrochage de l'acide aminé (3'-CCA).</li><li><strong>ARNr</strong> : composant structural des ribosomes (60% du ribosome).</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le 2'-OH du ribose rend l'ARN instable (hydrolysable en milieu basique). L'ADN est plus stable → support de l'information génétique. Le code génétique est dégénéré (61 codons sens pour 20 AA) mais non ambigu.</p></div>` },
  { id: 'chimie-lipides', subject: 'chimie', title: 'Lipides et membranes', summary: 'Acides gras, phospholipides, cholestérol et lipoprotéines.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Lipides</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Acides gras (AG)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Chaîne hydrocarbonée + COOH. Notation : C:n Δx (C = carbones, n = insaturations, x = position).</li><li><strong>AG saturés</strong> : palmitique (C16:0), stéarique (C18:0). Linéaires → empaquetage serré → solides.</li><li><strong>AG insaturés</strong> : oléique (C18:1 Δ9 cis), linoléique (C18:2 Δ9,12 = oméga-6), α-linolénique (C18:3 = oméga-3). Configuration cis → coude → fluidité membranaire.</li><li><strong>AG essentiels</strong> : linoléique (ω-6) et α-linolénique (ω-3). Non synthétisables par l'Homme.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Phospholipides</h4><p class="mb-3">Glycérol + 2 AG + phosphate + tête polaire. <strong>Amphiphiles</strong> → bicouche lipidique. Phosphatidylcholine (lécithine) = le plus abondant. Fluidité dépend de : insaturation des AG, longueur des chaînes, et teneur en cholestérol.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Cholestérol</h4><p class="mb-3">Noyau stérane (4 cycles). <strong>Module la fluidité</strong> membranaire : diminue à haute T, augmente à basse T. Précurseur des hormones stéroïdiennes (cortisol, aldostérone, testostérone, estradiol), vitamine D et acides biliaires.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lipoprotéines</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Chylomicrons</strong> : transport des lipides alimentaires (intestin → tissus).</li><li><strong>VLDL</strong> → <strong>LDL</strong> (mauvais cholestérol, transport vers les tissus). Récepteur LDL hépatique.</li><li><strong>HDL</strong> (bon cholestérol) : transport inverse (tissus → foie pour excrétion biliaire).</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : La β-oxydation des AG produit acétyl-CoA + FADH₂ + NADH. Un AG à 16C (palmitate) produit 106 ATP, bien plus que le glucose (36-38 ATP).</p></div>` },
  { id: 'chimie-vitamines', subject: 'chimie', title: 'Vitamines et coenzymes', summary: 'Vitamines hydrosolubles, liposolubles et leurs rôles métaboliques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Vitamines et coenzymes</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Vitamines hydrosolubles</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>B1 (thiamine)</strong> → TPP : décarboxylation oxydative (pyruvate déshydrogénase). Carence = béribéri.</li><li><strong>B2 (riboflavine)</strong> → FAD/FMN : transporteurs d'électrons. Chaîne respiratoire.</li><li><strong>B3 (niacine/PP)</strong> → NAD⁺/NADP⁺ : oxydoréduction. Carence = pellagre (3D : dermatite, diarrhée, démence).</li><li><strong>B5 (pantothénique)</strong> → CoA : métabolisme des AG et cycle de Krebs.</li><li><strong>B6 (pyridoxine)</strong> → PLP : transamination des acides aminés. Carence = neuropathie.</li><li><strong>B9 (folates)</strong> : synthèse des bases puriques et de dTMP. Carence = anémie mégaloblastique, défaut de fermeture du tube neural.</li><li><strong>B12 (cobalamine)</strong> : cofacteur de la méthionine synthase. Carence = anémie de Biermer (défaut de facteur intrinsèque).</li><li><strong>C (ascorbique)</strong> : antioxydant, cofacteur de la prolyl-hydroxylase (synthèse du collagène). Carence = scorbut.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Vitamines liposolubles (A, D, E, K)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>A (rétinol)</strong> : vision (rhodopsine), différenciation épithéliale. Carence = cécité nocturne.</li><li><strong>D (cholécalciférol)</strong> : absorption intestinale du Ca²⁺. Activation : foie (25-OH) → rein (1,25-OH). Carence = rachitisme/ostéomalacie.</li><li><strong>E (tocophérol)</strong> : antioxydant lipidique, protection membranaire.</li><li><strong>K (phylloquinone)</strong> : carboxylation des facteurs de coagulation (II, VII, IX, X). Cible des AVK.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : NAD⁺ intervient dans le catabolisme (glycolyse, Krebs), NADPH dans l'anabolisme (synthèse des AG, voie des pentoses phosphates). B9 et B12 sont synergiques dans la synthèse d'ADN.</p></div>` },

  // ===== BIOLOGIE CELLULAIRE — FICHES APPROFONDIES =====
  { id: 'biocell-cytosquelette', subject: 'biocell', title: 'Cytosquelette', summary: 'Microfilaments, microtubules, filaments intermédiaires et fonctions.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Cytosquelette</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Microfilaments d'actine (7 nm)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Polymère d'<strong>actine G</strong> → actine F. Polarisés : extrémité (+) croissance rapide, (-) lente.</li><li>Fonctions : contraction musculaire (avec myosine), anneau contractile (cytocinèse), microvillosités, lamellipodes (migration cellulaire).</li><li>Drogues : <strong>phalloïdine</strong> (stabilise), <strong>cytochalasine</strong> (empêche polymérisation).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Microtubules (25 nm)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Hétérodimères <strong>α/β-tubuline</strong>. Nucléés au <strong>centrosome</strong> (MTOC). Instabilité dynamique.</li><li>Fonctions : fuseau mitotique, transport intracellulaire (kinésine vers +, dynéine vers -), cils et flagelles (9+2).</li><li>Drogues : <strong>colchicine/nocodazole</strong> (dépolymérisation), <strong>taxol</strong> (stabilisation → bloque mitose, anticancéreux).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Filaments intermédiaires (10 nm)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Résistance mécanique. Non polarisés, très stables.</li><li><strong>Kératines</strong> (épithéliums), <strong>vimentine</strong> (mésenchyme), <strong>neurofilaments</strong> (neurones), <strong>lamines</strong> (lamina nucléaire).</li><li>Marqueurs diagnostiques en anatomopathologie (identifier l'origine d'une tumeur).</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Le taxol (paclitaxel) bloque les cellules en métaphase en stabilisant les microtubules → utilisé en chimiothérapie. La colchicine est utilisée pour les caryotypes (blocage en métaphase).</p></div>` },
  { id: 'biocell-apoptose', subject: 'biocell', title: 'Apoptose et mort cellulaire', summary: 'Voies intrinsèque et extrinsèque, caspases et nécrose.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Mort cellulaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Apoptose (mort programmée)</h4><p class="mb-3">Processus actif, ordonné, sans inflammation. Caractéristiques : condensation chromatine, fragmentation ADN internucléosomale (échelle 180 pb), bourgeonnement membranaire, corps apoptotiques phagocytés.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Voie intrinsèque (mitochondriale)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Stimuli : dommages ADN, stress oxydatif, privation de facteurs de croissance.</li><li>Protéines pro-apoptotiques <strong>Bax/Bak</strong> → pore dans la membrane mitochondriale externe → libération de <strong>cytochrome c</strong>.</li><li>Cytochrome c + Apaf-1 → <strong>apoptosome</strong> → activation de la <strong>caspase 9</strong> (initiatrice) → caspases effectrices (3, 6, 7).</li><li><strong>Bcl-2</strong> (anti-apoptotique) inhibe Bax/Bak. Surexprimé dans certains cancers.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voie extrinsèque (récepteurs de mort)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Ligand (FasL, TNF, TRAIL) → récepteur de mort (Fas, TNFR) → recrutement FADD → activation <strong>caspase 8</strong> (initiatrice).</li><li>Caspase 8 → caspases effectrices 3/7 → clivage des substrats (PARP, lamines, ICAD).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Nécrose</h4><p class="mb-3">Mort passive, non programmée. Gonflement cellulaire, rupture membranaire, libération du contenu → <strong>inflammation</strong>. Causes : ischémie, trauma, toxines.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : p53 est un inducteur majeur d'apoptose (gardien du génome). Sa mutation est retrouvée dans >50% des cancers humains. La phosphatidylsérine exposée sur la face externe est un signal eat me pour les phagocytes.</p></div>` },
  { id: 'biocell-replication', subject: 'biocell', title: 'Réplication de l\'ADN', summary: 'Mécanisme semi-conservatif, enzymes et fidélité de la réplication.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Réplication de l'ADN</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Caractéristiques</h4><p class="mb-3"><strong>Semi-conservative</strong> (Meselson-Stahl, 1958) : chaque brin sert de matrice. <strong>Bidirectionnelle</strong> : 2 fourches de réplication à partir de chaque origine. <strong>Semi-discontinue</strong> : brin avancé (continu) et brin retardé (fragments d'Okazaki).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Enzymes clés</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Hélicase</strong> : déroule la double hélice (consomme ATP).</li><li><strong>Topoisomérases</strong> : relâchent les supertours. Topo I (coupure 1 brin), Topo II (2 brins, = gyrase chez procaryotes).</li><li><strong>Primase</strong> : synthétise les amorces ARN (~10 nt).</li><li><strong>ADN polymérase III</strong> (procaryotes) / <strong>Pol δ et ε</strong> (eucaryotes) : élongation 5'→3'. Activité de relecture 3'→5' (proofreading).</li><li><strong>ADN polymérase I</strong> : remplace les amorces ARN par de l'ADN.</li><li><strong>ADN ligase</strong> : scelle les brèches (liaison phosphodiester).</li><li><strong>SSB/RPA</strong> : protéines de liaison à l'ADN simple brin (empêchent la reformation de la double hélice).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Télomères et télomérase</h4><p class="mb-3">Problème de la réplication des extrémités : raccourcissement à chaque division (perte de 50-200 pb). <strong>Télomérase</strong> (transcriptase inverse) ajoute des répétitions TTAGGG. Active dans les cellules souches et cancéreuses. Absente dans les cellules somatiques → sénescence réplicative.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Toutes les ADN polymérases synthétisent dans le sens 5'→3' et nécessitent une amorce. Le taux d'erreur après relecture est de ~10⁻⁷ par nucléotide (10⁻⁹ après réparation).</p></div>` },
  { id: 'biocell-transcription', subject: 'biocell', title: 'Transcription et régulation', summary: 'ARN polymérases, promoteurs, facteurs de transcription et épigénétique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Transcription</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Mécanisme chez les eucaryotes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>ARN pol I</strong> : ARNr (28S, 18S, 5.8S) dans le nucléole.</li><li><strong>ARN pol II</strong> : ARNm et snARN. Sensible à l'<strong>α-amanitine</strong> (poison de l'amanite phalloïde).</li><li><strong>ARN pol III</strong> : ARNt, ARNr 5S, snARN.</li><li>Promoteur : boîte TATA (~-25), boîte CAAT (~-80). Fixation de <strong>TBP</strong> (TATA-binding protein) puis facteurs généraux TFIIA, B, D, E, F, H.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Maturation du pré-ARNm</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Coiffe 5'</strong> : 7-méthylguanosine. Protection et reconnaissance par le ribosome.</li><li><strong>Queue poly-A 3'</strong> : ~200 adénines. Stabilité et export nucléaire.</li><li><strong>Épissage</strong> : excision des introns par le <strong>spliceosome</strong> (snRNP U1, U2, U4, U5, U6). Sites conservés : GU (donneur 5') et AG (accepteur 3'). Épissage alternatif → diversité protéique.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Régulation de la transcription</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Enhancers</strong> (activateurs) et <strong>silencers</strong> (répresseurs) : séquences régulatrices à distance.</li><li><strong>Facteurs de transcription</strong> : domaines de liaison à l'ADN (doigt de zinc, leucine zipper, hélice-tour-hélice).</li><li><strong>Épigénétique</strong> : méthylation de l'ADN (CpG → silence), acétylation des histones (chromatine ouverte → transcription active), méthylation des histones (activation ou répression selon le résidu).</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : L'épissage alternatif permet à un seul gène de coder plusieurs protéines. Le gène DSCAM de Drosophila peut produire >38 000 variants par épissage alternatif.</p></div>` },
  { id: 'biocell-traduction', subject: 'biocell', title: 'Traduction et modifications', summary: 'Ribosome, code génétique, initiation/élongation/terminaison.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Traduction</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le code génétique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>64 codons</strong> : 61 sens (codant un AA) + 3 stop (UAA, UAG, UGA).</li><li>Codon initiateur : <strong>AUG</strong> (méthionine). Universel (sauf mitochondries), dégénéré (plusieurs codons pour 1 AA), non ambigu (1 codon = 1 AA), non chevauchant.</li><li>Wobble (flottement) : la 3e base du codon tolère des mésappariements → un ARNt peut lire plusieurs codons synonymes.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Ribosome eucaryote (80S)</h4><p class="mb-3">Petite sous-unité <strong>40S</strong> (ARNr 18S) : décodage. Grande sous-unité <strong>60S</strong> (ARNr 28S, 5.8S, 5S) : catalyse (peptidyltransférase = ribozyme). Sites A (aminoacyl), P (peptidyl), E (exit).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Étapes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Initiation</strong> : coiffe → scanning 5'→3' → reconnaissance AUG (contexte Kozak). eIF2-GTP amène Met-ARNti au site P. Jonction 40S+60S.</li><li><strong>Élongation</strong> : aminoacyl-ARNt au site A (eEF1α-GTP) → liaison peptidique → translocation (eEF2-GTP). ~6 AA/seconde.</li><li><strong>Terminaison</strong> : codon stop → facteur de libération eRF1 → hydrolyse du polypeptide → dissociation du ribosome.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Modifications post-traductionnelles</h4><p class="mb-3">Clivage du peptide signal, <strong>glycosylation</strong> (N-linked dans le RE, O-linked dans le Golgi), phosphorylation (Ser/Thr/Tyr par kinases), ubiquitination (signal de dégradation par le protéasome).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Les antibiotiques ciblent le ribosome procaryote (70S) : chloramphénicol (peptidyltransférase), tétracyclines (site A), aminosides (erreurs de lecture), macrolides (translocation).</p></div>` },
  { id: 'biocell-jonctions', subject: 'biocell', title: 'Jonctions et matrice extracellulaire', summary: 'Jonctions serrées, adhérentes, desmosomes, gap et MEC.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Jonctions cellulaires et MEC</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Jonctions cellule-cellule</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Jonctions serrées (tight)</strong> : claudines, occludines. Barrière imperméable entre les cellules épithéliales. Polarité apico-basale.</li><li><strong>Jonctions adhérentes</strong> : cadhérines (E-cadhérine dans les épithéliums) + caténines → liaison aux microfilaments d'actine. Ca²⁺-dépendantes.</li><li><strong>Desmosomes</strong> : desmogléine, desmocolline → liaison aux filaments intermédiaires (kératines). Résistance mécanique (peau, cœur).</li><li><strong>Jonctions gap (communicantes)</strong> : connexines (6 = connexon, 2 connexons = canal). Passage d'ions et petites molécules (<1 kDa). Couplage électrique (cœur) et métabolique.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Jonctions cellule-MEC</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Intégrines</strong> : hétérodimères αβ transmembranaires. Liaison à la fibronectine, laminine, collagène. Signalisation bidirectionnelle (inside-out et outside-in).</li><li><strong>Hémidesmosomes</strong> : intégrines α6β4 → filaments intermédiaires → lame basale.</li><li><strong>Contacts focaux</strong> : intégrines → microfilaments d'actine (via taline, vinculine). Migration cellulaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Matrice extracellulaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Collagène</strong> : triple hélice (Gly-X-Y), 28 types. Type I = le plus abondant (os, peau). Hydroxyproline (vitamine C nécessaire).</li><li><strong>Élastine</strong> : élasticité (poumons, artères, peau).</li><li><strong>Protéoglycanes</strong> : protéine + GAG (héparane sulfate, chondroïtine sulfate). Rétention d'eau, résistance à la compression (cartilage).</li><li><strong>Lame basale</strong> : collagène IV + laminine + nidogène + perlécan. Support des épithéliums et endothéliums.</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : La perte de E-cadhérine est un marqueur de transition épithélio-mésenchymateuse (invasion tumorale). Le pemphigus est une maladie auto-immune contre les desmogléines.</p></div>` },

  // ===== BIOSTATISTIQUES — FICHES APPROFONDIES =====
  { id: 'biostats-lois', subject: 'biostats', title: 'Lois de probabilité', summary: 'Binomiale, Poisson, Normale et leurs applications en santé.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Lois de probabilité</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi binomiale B(n, p)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>n épreuves indépendantes, probabilité de succès p. P(X=k) = C(n,k) × pᵏ × (1-p)ⁿ⁻ᵏ.</li><li>E(X) = np, Var(X) = np(1-p). Ex : nombre de malades dans un échantillon.</li><li>Quand n grand et p petit : approximation par <strong>Poisson</strong>.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi de Poisson P(λ)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Événements rares : P(X=k) = e⁻λ × λᵏ / k!. E(X) = Var(X) = λ.</li><li>Applications : nombre d'admissions aux urgences/jour, nombre de mutations par génome.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi normale N(μ, σ²)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Courbe en cloche symétrique. 68% dans [μ±σ], 95% dans [μ±1.96σ], 99.7% dans [μ±3σ].</li><li><strong>Centrage-réduction</strong> : Z = (X-μ)/σ ~ N(0,1). Permet la lecture de la table de la loi normale.</li><li><strong>Théorème central limite</strong> : la moyenne d'un grand échantillon (n≥30) suit approximativement une loi normale, quelle que soit la distribution d'origine.</li></ul><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : IC 95% de la moyenne = X̄ ± 1.96 × σ/√n. Plus n augmente, plus l'intervalle se resserre (précision augmente).</p></div>` },
  { id: 'biostats-regression', subject: 'biostats', title: 'Régression et corrélation', summary: 'Régression linéaire, coefficient r de Pearson et interprétation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Régression et corrélation</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Corrélation linéaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Coefficient de Pearson r</strong> : mesure la force et le sens de l'association linéaire entre 2 variables quantitatives.</li><li>r ∈ [-1, +1]. |r| > 0.7 = forte corrélation, 0.3-0.7 = modérée, < 0.3 = faible.</li><li><strong>r²</strong> (coefficient de détermination) : % de variance de Y expliquée par X. Ex : r = 0.8 → r² = 0.64 → 64% de la variance expliquée.</li><li>Corrélation ≠ causalité. Facteurs de confusion possibles.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Régression linéaire simple</h4><p class="mb-3">Modèle : <strong>Y = a + bX + ε</strong>. b (pente) = Cov(X,Y)/Var(X). a (ordonnée à l'origine) = Ȳ - bX̄. Méthode des moindres carrés : minimise la somme des résidus au carré.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Régression logistique</h4><p class="mb-3">Variable dépendante binaire (0/1). Modèle : ln(p/(1-p)) = a + bX. L'<strong>odds ratio</strong> (OR) = e^b mesure l'association. OR > 1 = facteur de risque, OR < 1 = facteur protecteur, OR = 1 = pas d'association.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Le coefficient de Spearman est l'alternative non paramétrique à Pearson (données ordinales ou non linéaires). En régression multiple, on peut ajuster sur les facteurs de confusion.</p></div>` },
  { id: 'biostats-essais', subject: 'biostats', title: 'Essais cliniques', summary: 'Phases, randomisation, double aveugle et biais.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Essais cliniques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Les 4 phases</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Phase I</strong> : tolérance/pharmacocinétique. Volontaires sains (n = 20-80). Dose maximale tolérée.</li><li><strong>Phase II</strong> : efficacité préliminaire + dose optimale. Patients malades (n = 100-300).</li><li><strong>Phase III</strong> : efficacité comparative. <strong>Essai randomisé contrôlé</strong> (gold standard). n = 1000-3000. Nécessaire pour l'AMM.</li><li><strong>Phase IV</strong> : pharmacovigilance post-AMM. Effets indésirables rares, population réelle.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Méthodologie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Randomisation</strong> : attribution aléatoire du traitement. Élimine les biais de sélection.</li><li><strong>Double aveugle</strong> : ni patient ni médecin ne connaissent le traitement → élimine biais de mesure et effet placebo.</li><li><strong>Intention de traiter (ITT)</strong> : analyse tous les patients selon le groupe assigné, même si non-compliance → conserve la randomisation.</li><li><strong>Per protocole</strong> : analyse seulement les patients ayant suivi le protocole → surévalue l'efficacité.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Principaux biais</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Sélection</strong> : groupes non comparables → randomisation.</li><li><strong>Mesure (information)</strong> : erreur de classification → aveugle.</li><li><strong>Confusion</strong> : 3e variable liée à l'exposition et à l'issue → ajustement/stratification.</li><li><strong>Attrition</strong> : perdus de vue différentiels → analyse ITT.</li></ul><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : La puissance (1-β) est la probabilité de détecter une différence quand elle existe. Elle augmente avec n. α = risque de 1ère espèce (faux positif, classiquement 5%).</p></div>` },
  { id: 'biostats-survie', subject: 'biostats', title: 'Analyse de survie', summary: 'Kaplan-Meier, censure, log-rank et modèle de Cox.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Analyse de survie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principes</h4><p class="mb-3">Analyse le <strong>délai de survenue</strong> d'un événement (décès, rechute, guérison). Prend en compte les données <strong>censurées</strong> (patients perdus de vue ou sans événement à la fin de l'étude).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Méthode de Kaplan-Meier</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Estimation non paramétrique de la fonction de survie S(t) = P(T > t).</li><li>Courbe en <strong>marches d'escalier</strong> décroissante. Chaque marche = un événement.</li><li>S(t) = ∏ [(nᵢ - dᵢ) / nᵢ] pour chaque temps tᵢ où un événement survient.</li><li>La <strong>médiane de survie</strong> = temps où S(t) = 0.5 (50% des patients ont eu l'événement).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Comparaison de courbes</h4><p class="mb-3"><strong>Test du log-rank</strong> : compare 2 courbes de survie (H0 : pas de différence). Non paramétrique. Suit un Chi-2 à 1 ddl.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Modèle de Cox</h4><p class="mb-3">Régression semi-paramétrique. h(t) = h₀(t) × exp(β₁X₁ + β₂X₂ + ...). Le <strong>Hazard Ratio (HR)</strong> = exp(β) mesure le risque relatif instantané. HR > 1 = surrisque, HR < 1 = protection. Hypothèse de <strong>proportionnalité des risques</strong>.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : La censure droite est la plus fréquente (patient encore vivant à la fin). Le modèle de Cox permet d'ajuster sur les covariables (âge, sexe, stade).</p></div>` },
  { id: 'biostats-etudes-obs', subject: 'biostats', title: 'Études observationnelles', summary: 'Cohorte, cas-témoins, transversale et mesures d\'association.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Études observationnelles</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Étude de cohorte (prospective)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Sélection selon l'<strong>exposition</strong> → suivi dans le temps → mesure de l'incidence de la maladie.</li><li>Mesure : <strong>Risque Relatif (RR)</strong> = incidence exposés / incidence non-exposés.</li><li>Avantages : temporalité, plusieurs maladies étudiables, calcul direct de l'incidence.</li><li>Inconvénients : durée, coût, perdus de vue, inadaptée aux maladies rares.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Étude cas-témoins (rétrospective)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Sélection selon la <strong>maladie</strong> (cas vs témoins) → mesure rétrospective de l'exposition.</li><li>Mesure : <strong>Odds Ratio (OR)</strong> = (a×d)/(b×c). Approxime le RR quand la maladie est rare.</li><li>Avantages : rapide, peu coûteux, adapté aux maladies rares.</li><li>Inconvénients : biais de mémoire, pas de calcul d'incidence, un seul facteur de risque étudié de manière optimale.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Étude transversale</h4><p class="mb-3">Mesure exposition et maladie <strong>au même moment</strong>. Calcul de <strong>prévalence</strong>. Rapide mais pas de temporalité → pas de causalité.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Hiérarchie des preuves (du plus au moins fiable) : méta-analyse > essai randomisé > cohorte > cas-témoins > transversale > série de cas > cas clinique.</p></div>` },
  { id: 'biostats-roc', subject: 'biostats', title: 'Courbe ROC et valeurs prédictives', summary: 'Se, Sp, VPP, VPN, rapport de vraisemblance et courbe ROC.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Performance diagnostique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Tableau de contingence</h4><p class="mb-3">Vrais positifs (VP), faux positifs (FP), vrais négatifs (VN), faux négatifs (FN).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Indices intrinsèques (indépendants de la prévalence)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Sensibilité (Se)</strong> = VP/(VP+FN). Capacité à détecter les malades. Un test très sensible, s'il est négatif, exclut la maladie (SnNout).</li><li><strong>Spécificité (Sp)</strong> = VN/(VN+FP). Capacité à exclure les non-malades. Un test très spécifique, s'il est positif, confirme la maladie (SpPin).</li><li><strong>RV+</strong> = Se/(1-Sp). <strong>RV-</strong> = (1-Se)/Sp. Bon test si RV+ > 10 et RV- < 0.1.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Indices extrinsèques (dépendent de la prévalence)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>VPP</strong> = VP/(VP+FP). Probabilité d'être malade si test +. Augmente avec la prévalence.</li><li><strong>VPN</strong> = VN/(VN+FN). Probabilité d'être sain si test -. Diminue quand la prévalence augmente.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Courbe ROC</h4><p class="mb-3">Graphe de <strong>Se (axe Y) vs 1-Sp (axe X)</strong> pour tous les seuils de positivité. L'<strong>AUC</strong> (aire sous la courbe) mesure la discrimination globale : 0.5 = hasard, 0.7-0.8 = acceptable, 0.8-0.9 = bon, > 0.9 = excellent. Le seuil optimal maximise l'indice de Youden (Se + Sp - 1).</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : En dépistage (prévalence faible), même un test très spécifique donne beaucoup de faux positifs → VPP basse. C'est pourquoi on fait un test de confirmation.</p></div>` },

  // ===== BIOPHYSIQUE — FICHES APPROFONDIES =====
  { id: 'biophysique-potentiel', subject: 'biophysique', title: 'Électricité et potentiel de membrane', summary: 'Potentiel de repos, d\'action, Nernst et conduction nerveuse.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Bioélectricité</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Potentiel de repos</h4><p class="mb-3">Différence de potentiel transmembranaire au repos : <strong>-70 mV</strong> (intérieur négatif). Maintenu par la pompe Na⁺/K⁺-ATPase (3 Na⁺ sortent, 2 K⁺ entrent) et la perméabilité sélective au K⁺.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Équation de Nernst</h4><p class="mb-3"><strong>E = (RT/zF) × ln([ion]ext/[ion]int)</strong>. À 37°C : E = 61.5/z × log([ext]/[int]) mV. E(K⁺) ≈ -90 mV, E(Na⁺) ≈ +60 mV. Equation de Goldman : prend en compte toutes les perméabilités.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Potentiel d'action</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Loi du tout ou rien</strong> : si stimulus ≥ seuil (-55 mV) → PA complet.</li><li><strong>Dépolarisation</strong> : ouverture canaux Na⁺ voltage-dépendants → entrée massive de Na⁺ → +30 mV.</li><li><strong>Repolarisation</strong> : inactivation Na⁺ + ouverture canaux K⁺ → sortie de K⁺.</li><li><strong>Hyperpolarisation transitoire</strong> : fermeture retardée des canaux K⁺.</li><li><strong>Période réfractaire absolue</strong> : aucun nouveau PA possible (canaux Na⁺ inactivés). Puis relative.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Conduction nerveuse</h4><p class="mb-3">Fibres myélinisées : conduction <strong>saltatoire</strong> (nœuds de Ranvier) → rapide (120 m/s). Fibres amyéliniques : conduction continue → lente (0.5-2 m/s). Vitesse proportionnelle au diamètre.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Les anesthésiques locaux (lidocaïne) bloquent les canaux Na⁺ voltage-dépendants → empêchent la dépolarisation. La sclérose en plaques détruit la myéline → ralentissement de la conduction.</p></div>` },
  { id: 'biophysique-thermo-bio', subject: 'biophysique', title: 'Thermodynamique biologique', summary: 'Enthalpie, entropie, énergie libre de Gibbs et couplage énergétique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Thermodynamique biologique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>1er principe</strong> : conservation de l'énergie. ΔU = Q + W. L'énergie totale de l'univers est constante.</li><li><strong>2e principe</strong> : l'entropie de l'univers augmente toujours. ΔS(univers) ≥ 0.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Énergie libre de Gibbs</h4><p class="mb-3"><strong>ΔG = ΔH - TΔS</strong>. Si ΔG < 0 : réaction spontanée (exergonique). Si ΔG > 0 : non spontanée (endergonique). Si ΔG = 0 : équilibre. Relation avec la constante d'équilibre : ΔG° = -RT ln(Keq).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">ATP et couplage énergétique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Hydrolyse de l'ATP : ATP + H₂O → ADP + Pi. <strong>ΔG°' = -30.5 kJ/mol</strong>.</li><li>In vivo : ΔG ≈ -50 kJ/mol (concentrations réelles).</li><li><strong>Couplage</strong> : une réaction exergonique (ATP → ADP) fournit l'énergie pour une réaction endergonique. Ex : phosphorylation du glucose par l'hexokinase.</li><li>Autres molécules à haut potentiel de transfert : phosphoénolpyruvate (-61.9), 1,3-bisphosphoglycérate (-49.4), créatine-phosphate (-43.1).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Oxydoréduction biologique</h4><p class="mb-3">E° (potentiel standard de réduction). Plus E° est négatif, plus le réducteur est fort. NAD⁺/NADH : E° = -0.32V. O₂/H₂O : E° = +0.82V. ΔG° = -nFΔE° (transfert d'e⁻ de NADH vers O₂ = exergonique → ATP).</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : La chaîne respiratoire couple l'oxydation du NADH (exergonique) au pompage de protons → gradient H⁺ → ATP synthase (chimiosmose de Mitchell). ~2.5 ATP par NADH, ~1.5 par FADH₂.</p></div>` },
  { id: 'biophysique-spectro', subject: 'biophysique', title: 'Spectrophotométrie', summary: 'Loi de Beer-Lambert, absorbance et applications analytiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Spectrophotométrie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi de Beer-Lambert</h4><p class="mb-3"><strong>A = ε × l × c</strong>. A = absorbance (sans unité, = DO densité optique). ε = coefficient d'extinction molaire (L.mol⁻¹.cm⁻¹). l = trajet optique (cm). c = concentration (mol/L).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Transmittance et absorbance</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>T = I/I₀ (fraction de lumière transmise). <strong>A = -log(T) = log(I₀/I)</strong>.</li><li>A = 0 → T = 100% (transparent). A = 1 → T = 10%. A = 2 → T = 1%.</li><li>Validité de Beer-Lambert : solutions diluées (A < 2), lumière monochromatique, pas d'interaction entre molécules.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Applications</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Dosage enzymatique</strong> : NADH absorbe à 340 nm (ε = 6220). NAD⁺ n'absorbe pas → suivi de l'activité enzymatique.</li><li><strong>Dosage des protéines</strong> : UV à 280 nm (Trp, Tyr). Bradford (595 nm). BCA (562 nm).</li><li><strong>Dosage ADN</strong> : UV à 260 nm. Ratio A260/A280 ≈ 1.8 (ADN pur). < 1.8 = contamination protéique.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : L'effet hyperchrome : l'ADN dénaturé (simple brin) absorbe 30-40% de plus à 260 nm que l'ADN natif (double brin). Utilisé pour mesurer la Tm.</p></div>` },
  { id: 'biophysique-rayonsx', subject: 'biophysique', title: 'Production des rayons X', summary: 'Tube à rayons X, spectre de freinage, raies caractéristiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Rayons X</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Production : tube de Coolidge</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Cathode (filament chauffé) émet des e⁻ par effet thermoïonique.</li><li>Haute tension (30-150 kV) accélère les e⁻ vers l'<strong>anode</strong> (tungstène W, Z=74).</li><li>Rendement très faible : <strong>~1% en X, 99% en chaleur</strong> → refroidissement nécessaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Spectre d'émission</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Rayonnement de freinage (Bremsstrahlung)</strong> : spectre continu. E max = eV (tension appliquée). λ min = hc/eV.</li><li><strong>Raies caractéristiques</strong> : spectre discret. Transition K, L, M de l'atome cible. Kα, Kβ (propres au matériau de l'anode).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Interactions X-matière</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Effet photoélectrique</strong> : photon X absorbé totalement → éjection d'un e⁻. Prépondérant à basse énergie. Proportionnel à Z³/E³ → excellent contraste os/tissus mous.</li><li><strong>Effet Compton</strong> : diffusion avec perte partielle d'énergie. Prépondérant à haute énergie. Indépendant de Z → dégrade le contraste (diffusé = bruit).</li><li><strong>Création de paire</strong> : E > 1.022 MeV. e⁻ + e⁺. Négligeable en imagerie diagnostique.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Augmenter le kV augmente la pénétration (moins de contraste). Augmenter le mA augmente le nombre de photons (meilleur rapport signal/bruit mais plus d'irradiation).</p></div>` },
  { id: 'biophysique-ph-tampons', subject: 'biophysique', title: 'pH et tampons biologiques', summary: 'Équilibre acido-basique du sang, tampons et régulation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">pH et tampons biologiques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">pH sanguin</h4><p class="mb-3">pH artériel normal : <strong>7.38-7.42</strong>. Compatible avec la vie : 6.8-7.8. Régulation par 3 systèmes : tampons chimiques (immédiat), poumons (minutes), reins (heures-jours).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Diagramme de Davenport</h4><p class="mb-3">Représente [HCO₃⁻] en fonction du pH. Les isobares de pCO₂ sont des droites obliques. Permet de visualiser les troubles acido-basiques et leur compensation.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Gaz du sang</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>pH = 7.40 ± 0.02. <strong>pCO₂</strong> = 40 ± 5 mmHg. <strong>pO₂</strong> = 80-100 mmHg. <strong>HCO₃⁻</strong> = 24 ± 2 mmol/L.</li><li>Démarche diagnostique : 1) Acidose ou alcalose ? 2) Respiratoire (pCO₂) ou métabolique (HCO₃⁻) ? 3) Compensation adéquate ?</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Exemples cliniques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Acidose métabolique</strong> : pH↓, HCO₃⁻↓. Causes : acidocétose diabétique, insuffisance rénale, diarrhée. Compensation : hyperventilation (↓pCO₂).</li><li><strong>Alcalose respiratoire</strong> : pH↑, pCO₂↓. Cause : hyperventilation (anxiété, altitude). Compensation rénale : excrétion de HCO₃⁻.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Le trou anionique = Na⁺ - (Cl⁻ + HCO₃⁻) ≈ 12 ± 4. Augmenté dans les acidoses avec production d'acide (lactique, cétoacides). Normal dans les pertes de HCO₃⁻ (diarrhée).</p></div>` },
  { id: 'biophysique-med-nucleaire', subject: 'biophysique', title: 'Médecine nucléaire détaillée', summary: 'Scintigraphie, TEP-scan, radiopharmaceutiques et dosimétrie.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Médecine nucléaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">Administration d'un <strong>radiopharmaceutique</strong> (traceur radioactif) → détection externe des rayonnements émis → image fonctionnelle/métabolique (vs anatomique en radiologie).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Scintigraphie (TEMP/SPECT)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Traceur : <strong>Tc-99m</strong> (T½ = 6h, γ = 140 keV). Le plus utilisé (80% des examens).</li><li>Détection : <strong>gamma-caméra</strong> (cristal NaI + collimateur + PM).</li><li>Applications : thyroïde (I-123), os (Tc-99m-MDP), cœur (Tc-99m-MIBI), poumons (Tc-99m-MAA).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">TEP (Tomographie par Émission de Positons)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Traceur : <strong>¹⁸F-FDG</strong> (T½ = 110 min). Glucose marqué → capté par cellules à métabolisme intense.</li><li>Émission β⁺ → annihilation avec e⁻ → <strong>2 photons de 511 keV à 180°</strong> → détection en coïncidence.</li><li>Résolution supérieure à la TEMP. Couplé au scanner (TEP-TDM) pour localisation anatomique.</li><li>Applications principales : <strong>oncologie</strong> (staging, restaging, évaluation de la réponse), neurologie (épilepsie, démences), cardiologie (viabilité myocardique).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Radioprotection</h4><p class="mb-3">Le patient est la source → isolement temporaire. Distance, temps d'exposition, écrans de plomb. Femme enceinte et enfants : précautions renforcées. Dose efficace : ~5-10 mSv par examen.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Le FDG n'est pas spécifique du cancer : l'inflammation et l'infection captent aussi. Le cerveau et le cœur sont physiologiquement avides de FDG → faux positifs possibles.</p></div>` },

  // ===== SSH — FICHES APPROFONDIES =====
  { id: 'ssh-sante-publique', subject: 'ssh', title: 'Santé publique et prévention', summary: 'Niveaux de prévention, dépistage, épidémies et politique de santé.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Santé publique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Niveaux de prévention (OMS)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Primaire</strong> : empêcher l'apparition de la maladie. Vaccination, éducation, hygiène.</li><li><strong>Secondaire</strong> : dépistage précoce. Mammographie, frottis cervical, test néonatal.</li><li><strong>Tertiaire</strong> : limiter les complications et rechutes. Rééducation, éducation thérapeutique.</li><li><strong>Quaternaire</strong> : éviter la surmédicalisation et l'iatrogénie.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Critères de dépistage (Wilson & Jungner)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Maladie fréquente et grave. Histoire naturelle connue. Phase préclinique détectable.</li><li>Test acceptable, fiable, reproductible. Traitement efficace disponible.</li><li>Rapport coût/bénéfice favorable. Programme continu.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Indicateurs de santé</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Incidence</strong> : nouveaux cas / population à risque / temps. Mesure la vitesse d'apparition.</li><li><strong>Prévalence</strong> : cas existants / population totale. Photo à un instant t.</li><li><strong>Mortalité</strong> : décès / population. Taux brut vs standardisé (ajusté sur l'âge).</li><li><strong>Espérance de vie</strong> : France ~85 ans (F), ~79 ans (H). EVSI : espérance de vie sans incapacité.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Prévalence ≈ Incidence × Durée de la maladie. Un traitement efficace qui prolonge la vie sans guérir augmente la prévalence tout en pouvant diminuer l'incidence.</p></div>` },
  { id: 'ssh-bioethique', subject: 'ssh', title: 'Lois de bioéthique', summary: 'PMA, don d\'organes, recherche sur l\'embryon et génétique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Lois de bioéthique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Historique</h4><p class="mb-3">Lois de bioéthique françaises : <strong>1994</strong> (fondatrices), révisées en <strong>2004</strong>, <strong>2011</strong> et <strong>2021</strong>. Principes : dignité, non-patrimonialité du corps humain, anonymat et gratuité du don.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">PMA (Procréation Médicalement Assistée)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Depuis 2021 : ouverte aux <strong>couples de femmes et femmes seules</strong>.</li><li>Techniques : insémination artificielle, FIV, FIV-ICSI.</li><li>Don de gamètes : gratuit, anonyme (mais levée possible de l'anonymat pour les enfants nés après 2021).</li><li><strong>GPA</strong> (gestation pour autrui) : interdite en France.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Don d'organes et de tissus</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Principe du <strong>consentement présumé</strong> : tout le monde est donneur sauf inscription au registre national des refus.</li><li>Mort encéphalique : 2 EEG plats à 4h d'intervalle ou angiographie cérébrale.</li><li>Don du vivant : possible pour les proches (rein, lobe hépatique). Comité donneur vivant.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Recherche sur l'embryon</h4><p class="mb-3">Recherche sur l'embryon et les cellules souches embryonnaires : autorisée sous conditions strictes (protocole approuvé par l'ABM). Embryons surnuméraires. Interdit de créer des embryons pour la recherche.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Le DPI (diagnostic préimplantatoire) est autorisé pour les maladies génétiques graves. Le DPN (prénatal) peut conduire à une IMG si maladie incurable au moment du diagnostic.</p></div>` },
  { id: 'ssh-handicap', subject: 'ssh', title: 'Handicap et dépendance', summary: 'Classification CIF, loi 2005, MDPH et accompagnement.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Handicap</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définitions</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>CIF (OMS, 2001)</strong> : Classification Internationale du Fonctionnement. Modèle biopsychosocial : déficience (corps) → limitation d'activité → restriction de participation.</li><li><strong>Loi du 11 février 2005</strong> : "Constitue un handicap toute limitation d'activité ou restriction de participation à la vie en société subie dans son environnement par une personne en raison d'une altération substantielle, durable ou définitive d'une ou plusieurs fonctions."</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Types de handicap</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Moteur</strong> : paralysie, amputation, troubles musculosquelettiques.</li><li><strong>Sensoriel</strong> : visuel, auditif.</li><li><strong>Mental/intellectuel</strong> : trisomie 21, retard mental.</li><li><strong>Psychique</strong> : schizophrénie, troubles bipolaires.</li><li><strong>Cognitif</strong> : troubles dys, TDA/H.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Droits et accompagnement</h4><p class="mb-3"><strong>MDPH</strong> : guichet unique. Évalue les besoins via l'équipe pluridisciplinaire. Délivre la RQTH, l'AAH, la PCH, oriente vers les établissements (ESAT, MAS, FAM). Droit à la <strong>compensation</strong> du handicap. Accessibilité universelle (loi 2005).</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : 12 millions de Français touchés par un handicap (80% invisibles). La loi 2005 a posé le principe d'accessibilité universelle et de compensation individualisée.</p></div>` },
  { id: 'ssh-communication', subject: 'ssh', title: 'Relation de soin et communication', summary: 'Annonce diagnostique, empathie, communication non violente.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Communication en santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Dispositif d'annonce</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Protocole <strong>SPIKES</strong> (Buckman) : Setting (cadre), Perception (que sait le patient ?), Invitation (veut-il savoir ?), Knowledge (information), Empathy (émotions), Summary (résumé et plan).</li><li>Temps dédié, lieu calme, pas de téléphone. Évaluer les connaissances du patient avant d'informer.</li><li>Plan cancer : temps médical, temps d'accompagnement soignant, accès au soutien psychologique.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Empathie clinique</h4><p class="mb-3">Comprendre le vécu du patient sans s'y identifier (≠ sympathie). <strong>Écoute active</strong> : reformulation, questions ouvertes, silence, validation émotionnelle. Éviter : banalisation, fausses réassurances, jugement.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Éducation thérapeutique du patient (ETP)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Processus continu : aider le patient à <strong>acquérir des compétences</strong> pour gérer sa maladie chronique.</li><li>Diagnostic éducatif → programme personnalisé → séances (individuelles/collectives) → évaluation.</li><li>Compétences d'autosoins et compétences d'adaptation (coping).</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La décision médicale partagée (shared decision making) est le modèle recommandé : information claire + délibération + choix conjoint patient-médecin.</p></div>` },
  { id: 'ssh-recherche', subject: 'ssh', title: 'Éthique de la recherche', summary: 'Comités d\'éthique, consentement, CPP et déclarations internationales.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Éthique de la recherche</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Textes fondateurs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Code de Nuremberg (1947)</strong> : consentement volontaire obligatoire. Né des procès des médecins nazis.</li><li><strong>Déclaration d'Helsinki (1964, révisée)</strong> : intérêt du sujet > intérêt de la science. Comité d'éthique. Populations vulnérables.</li><li><strong>Rapport Belmont (1979)</strong> : respect des personnes, bienfaisance, justice.</li><li><strong>Loi Huriet-Sérusclat (1988)</strong> : première loi française sur la recherche biomédicale. CPP obligatoire.</li><li><strong>Loi Jardé (2012, appliquée 2016)</strong> : 3 catégories de recherches impliquant la personne humaine.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Catégories de recherche (loi Jardé)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Cat. 1</strong> : recherches interventionnelles (médicament, dispositif). Autorisation ANSM + avis CPP.</li><li><strong>Cat. 2</strong> : recherches à risques et contraintes minimes (questionnaires invasifs, prélèvements mineurs). Avis CPP.</li><li><strong>Cat. 3</strong> : recherches non interventionnelles (observationnelles). Avis CPP.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Consentement</h4><p class="mb-3">Information préalable loyale, claire et appropriée. <strong>Consentement libre, éclairé et écrit</strong> (cat. 1 et 2). Droit de retrait à tout moment sans préjudice. Populations vulnérables : protections renforcées (mineurs, majeurs protégés, urgence).</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Le CPP (Comité de Protection des Personnes) rend un avis éthique et scientifique. L'ANSM autorise les essais de cat. 1. La CNIL contrôle les données personnelles.</p></div>` },
  { id: 'ssh-systeme-sante', subject: 'ssh', title: 'Système de santé français', summary: 'Organisation, financement, ARS et parcours de soins.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Système de santé français</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Organisation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Modèle <strong>bismarckien</strong> (assurance sociale) avec éléments beveridgiens (CMU/CSS, prévention).</li><li><strong>Sécurité sociale</strong> (1945) : branche maladie (CPAM), AT-MP, vieillesse, famille, autonomie (2020).</li><li><strong>ARS</strong> (Agences Régionales de Santé, 2010) : pilotent la politique de santé régionale (hôpitaux, ambulatoire, médico-social, prévention).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Financement</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>~260 milliards/an. Sources : cotisations sociales, <strong>CSG</strong>, taxes (tabac, alcool), ONDAM.</li><li>Assurance maladie obligatoire (AMO) : rembourse ~78%. Complémentaires (mutuelles) : ~13%. Reste à charge : ~9%.</li><li>Hôpital : <strong>T2A</strong> (tarification à l'activité) depuis 2004. GHS (groupe homogène de séjours).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Parcours de soins</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Médecin traitant</strong> : déclaration obligatoire depuis 2004. Gate-keeper → accès coordonné au spécialiste.</li><li>Hors parcours : majoration du reste à charge (30% remboursement vs 70%).</li><li>ALD (Affection Longue Durée) : 30 maladies. Prise en charge à 100% sur la base du tarif sécu.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Enjeux actuels</h4><p class="mb-3">Déserts médicaux, vieillissement, maladies chroniques, soutenabilité financière, virage ambulatoire, e-santé, démocratie sanitaire.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La France a le 2e budget santé/PIB des pays de l'OCDE (~12%). La HAS évalue les médicaments (SMR/ASMR) et produit les recommandations de bonne pratique.</p></div>` },

  // ===== ANATOMIE — EXTENSION PROGRAMME COMPLET =====
  { id: 'anatomie-rachis', subject: 'anatomie', title: 'Anatomie du rachis', summary: 'Vertèbres, courbures, disques intervertébraux et moelle épinière.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Le rachis (colonne vertébrale)</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Structure générale</h4><p class="mb-3"><strong>33-34 vertèbres</strong> : 7 cervicales (C1-C7), 12 thoraciques (T1-T12), 5 lombaires (L1-L5), 5 sacrées (fusionnées = sacrum), 4-5 coccygiennes (coccyx). Courbures sagittales : <strong>lordose</strong> cervicale et lombaire (concavité postérieure), <strong>cyphose</strong> thoracique et sacrée (convexité postérieure).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Vertèbre type</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Corps vertébral</strong> (antérieur) : cylindrique, supporte le poids. Augmente de taille de C1 à L5.</li><li><strong>Arc postérieur</strong> : pédicules, lames, processus épineux (postérieur), processus transverses (latéraux), processus articulaires (sup/inf).</li><li><strong>Foramen vertébral</strong> : contient la moelle épinière. Foramen intervertébral : passage des nerfs spinaux.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Vertèbres particulières</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Atlas (C1)</strong> : pas de corps, pas de processus épineux. Articulation avec les condyles occipitaux (oui/non).</li><li><strong>Axis (C2)</strong> : processus odontoïde (dent). Articulation atlanto-axoïdienne (rotation non/non).</li><li><strong>C7</strong> (vertebra prominens) : processus épineux long et palpable.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Disque intervertébral</h4><p class="mb-3"><strong>Nucleus pulposus</strong> (centre gélatineux, riche en eau) + <strong>annulus fibrosus</strong> (anneaux fibreux concentriques). Amortisseur. <strong>Hernie discale</strong> = migration du nucleus à travers l'annulus → compression radiculaire. Plus fréquente en L4-L5 et L5-S1.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Moelle épinière</h4><p class="mb-3">De C1 à L1-L2 (cône médullaire). En dessous : <strong>queue de cheval</strong> (racines lombaires et sacrées). 31 paires de nerfs spinaux. Substance grise (centre, cornes antérieures motrices et postérieures sensitives) + substance blanche (faisceaux ascendants/descendants).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : La ponction lombaire se fait en L3-L4 ou L4-L5 (sous le cône médullaire pour éviter la moelle). Le syndrome de la queue de cheval est une urgence chirurgicale.</p></div>` },
  { id: 'anatomie-paroi-thorax', subject: 'anatomie', title: 'Paroi thoracique et diaphragme', summary: 'Côtes, muscles intercostaux, diaphragme et mécanique ventilatoire.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Paroi thoracique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Cage thoracique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>12 paires de côtes</strong> : 7 vraies (sternales), 3 fausses (attachées au cartilage de la 7e), 2 flottantes (11e-12e).</li><li><strong>Sternum</strong> : manubrium + corps + appendice xiphoïde. Angle de Louis (jonction manubrium-corps) = repère de T4-T5 et 2e côte.</li><li>Paquet vasculo-nerveux intercostal (VAN) : chemine dans le sillon costal au bord <strong>inférieur</strong> de chaque côte → ponction pleurale au bord supérieur de la côte inférieure.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Muscles respiratoires</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Intercostaux externes</strong> : élèvent les côtes → inspiration.</li><li><strong>Intercostaux internes</strong> : abaissent les côtes → expiration forcée.</li><li>Muscles accessoires : scalènes, SCM (inspiration forcée), abdominaux (expiration forcée).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Le diaphragme</h4><p class="mb-3">Muscle principal de la respiration. Coupole musculo-tendineuse séparant thorax et abdomen. Innervé par le <strong>nerf phrénique (C3-C5)</strong>. Contraction → abaissement → augmentation du volume thoracique → inspiration. Orifices : <strong>hiatus aortique</strong> (T12), <strong>hiatus œsophagien</strong> (T10), <strong>foramen de la VCI</strong> (T8). Mnémotechnique : 8-10-12.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : "C3-4-5 keeps the diaphragm alive". Une lésion médullaire haute (au-dessus de C3) paralyse le diaphragme → arrêt respiratoire. La hernie hiatale = passage de l'estomac par le hiatus œsophagien.</p></div>` },
  { id: 'anatomie-abdomen', subject: 'anatomie', title: 'Anatomie de l\'abdomen', summary: 'Péritoine, tube digestif, estomac, intestins et vascularisation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Abdomen</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le péritoine</h4><p class="mb-3">Membrane séreuse à 2 feuillets : <strong>pariétal</strong> (paroi) et <strong>viscéral</strong> (organes). Cavité péritonéale virtuelle. Organes intrapéritonéaux (estomac, intestin grêle, côlon transverse, sigmoïde) vs rétropéritonéaux (reins, pancréas, duodénum D2-D4, aorte, VCI). Mésos : mésentère (intestin grêle), mésocôlon transverse.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Estomac</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Régions : cardia, fundus, corps, antre, pylore. Grande et petite courbure.</li><li>Vascularisation : tronc cœliaque → artère gastrique gauche, artère splénique, artère hépatique commune.</li><li>Muqueuse : cellules pariétales (HCl, FI), cellules principales (pepsinogène), cellules G (gastrine).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Intestin grêle</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Duodénum</strong> (25 cm, 4 portions en C) : reçoit le cholédoque et le canal de Wirsung en D2 (ampoule de Vater).</li><li><strong>Jéjunum</strong> + <strong>iléon</strong> (~6 m) : absorption principale. Vascularisation par l'artère mésentérique supérieure (AMS).</li><li>Villosités intestinales → augmentation surface d'absorption (~200 m2).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Côlon</h4><p class="mb-3">Cæcum (+ appendice) → côlon ascendant → angle colique droit → côlon transverse → angle colique gauche → côlon descendant → sigmoïde → rectum. Vascularisation : AMS (jusqu'à l'angle gauche) + AMI (au-delà). <strong>Haustrations</strong> et bandelettes coliques (tænia coli).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le point de McBurney (1/3 externe de la ligne ombilico-iliaque droite) est le repère de l'appendice. L'artère mésentérique supérieure naît de l'aorte en L1.</p></div>` },
  { id: 'anatomie-foie-pancreas', subject: 'anatomie', title: 'Foie, pancréas et rate', summary: 'Anatomie hépato-biliaire, pancréatique et splénique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Foie, voies biliaires, pancréas et rate</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le foie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Plus grosse glande (~1500 g). Hypochondre droit. <strong>Double vascularisation</strong> : artère hépatique propre (25% O2) + veine porte (75%, sang digestif).</li><li>Segmentation de <strong>Couinaud</strong> : 8 segments (I-VIII) basés sur les veines hépatiques et la veine porte.</li><li>Lobule hépatique : hexagonal, veine centrolobulaire au centre, espaces portes en périphérie (triade : branche porte, artère hépatique, canal biliaire).</li><li>Fonctions : métabolisme glucidique/lipidique/protéique, détoxification, synthèse bile, production albumine et facteurs de coagulation.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies biliaires</h4><p class="mb-3">Canalicules biliaires → canaux hépatiques droit/gauche → <strong>canal hépatique commun</strong> + canal cystique (vésicule biliaire) → <strong>cholédoque</strong> → ampoule de Vater (avec le Wirsung) → D2 duodénum. Sphincter d'Oddi contrôle l'écoulement.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Le pancréas</h4><p class="mb-3">Organe rétropéritonéal. Tête (encadrée par le duodénum), isthme, corps, queue (vers la rate). <strong>Exocrine</strong> : acini → suc pancréatique (lipase, amylase, trypsine). <strong>Endocrine</strong> : îlots de Langerhans (cellules alpha = glucagon, cellules beta = insuline, cellules delta = somatostatine).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">La rate</h4><p class="mb-3">Hypochondre gauche, sous le diaphragme. Organe lymphoïde secondaire. Fonctions : filtration du sang (destruction des GR vieillis), réservoir plaquettaire, immunité (pulpe blanche = lymphocytes, pulpe rouge = filtration). <strong>Asplénie</strong> → risque infectieux (pneumocoque ++).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le cancer du pancréas touche surtout la tête (70%) → ictère obstructif par compression du cholédoque. La veine porte se forme par confluence de la veine mésentérique supérieure et de la veine splénique.</p></div>` },
  { id: 'anatomie-pelvis', subject: 'anatomie', title: 'Anatomie du pelvis', summary: 'Plancher pelvien, organes pelviens et périnée.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Le pelvis</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Ceinture pelvienne</h4><p class="mb-3">2 os coxaux + sacrum + coccyx. Articulations sacro-iliaques (peu mobiles) et symphyse pubienne. Le <strong>détroit supérieur</strong> sépare le grand bassin (au-dessus) du petit bassin (pelvis vrai, en dessous). Dimorphisme sexuel : bassin féminin plus large et plus évasé (adaptation à l'accouchement).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Plancher pelvien (périnée)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Diaphragme pelvien</strong> : muscle élévateur de l'anus (levator ani) = composante principale. Soutient les organes pelviens.</li><li>Périnée antérieur (urogénital) et postérieur (anal).</li><li>Faiblesse du plancher → <strong>prolapsus</strong> (descente d'organes) : cystocèle, rectocèle, hystéroptose.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Organes pelviens féminins</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Utérus</strong> : corps + col. Antéversé-antéfléchi. Ligament large, ligament rond, ligaments utérosacrés.</li><li><strong>Ovaires</strong> : follicules, ovulation, corps jaune. Ligament propre de l'ovaire.</li><li><strong>Trompes utérines</strong> : pavillon (fimbriae) → ampoule (lieu de fécondation) → isthme → portion interstitielle.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Organes pelviens masculins</h4><p class="mb-3"><strong>Prostate</strong> : sous la vessie, entoure l'urètre prostatique. Zones périphérique (cancer), transitionnelle (HBP), centrale. <strong>Vésicules séminales</strong> + canal déférent → canal éjaculateur. Testicules dans le scrotum (température inférieure de 2-3°C).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : La GEU (grossesse extra-utérine) siège le plus souvent dans l'ampoule tubaire. Le toucher rectal permet de palper la prostate (face postérieure) et d'évaluer le cul-de-sac de Douglas.</p></div>` },
  { id: 'anatomie-oeil', subject: 'anatomie', title: 'Organe de la vision', summary: 'Globe oculaire, muscles oculomoteurs et voies visuelles.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">L'œil et la vision</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Globe oculaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>3 tuniques</strong> : fibreuse (sclérotique + cornée), vasculaire/uvée (choroïde, corps ciliaire, iris), nerveuse (rétine).</li><li><strong>Cornée</strong> : transparente, avasculaire, puissance réfractive ~43 dioptries (2/3 du pouvoir réfractif total).</li><li><strong>Cristallin</strong> : lentille biconvexe, transparent, accommodation (modification de courbure par le muscle ciliaire). Cataracte = opacification.</li><li>Milieux transparents : humeur aqueuse (chambre antérieure), cristallin, corps vitré (chambre postérieure).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Rétine</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Cônes</strong> (~6 millions) : vision diurne, couleurs, acuité. Concentrés dans la <strong>fovéa</strong> (macula).</li><li><strong>Bâtonnets</strong> (~120 millions) : vision nocturne, périphérique. Rhodopsine = pigment visuel.</li><li><strong>Papille optique</strong> (disque optique) : point de départ du nerf optique. Tache aveugle (pas de photorécepteurs).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies visuelles</h4><p class="mb-3">Nerf optique (II) → <strong>chiasma optique</strong> (décussation des fibres nasales) → bandelettes optiques → corps genouillé latéral (thalamus) → radiations optiques → <strong>cortex visuel primaire</strong> (aire V1, lobe occipital). Hémianopsie bitemporale = lésion du chiasma (adénome hypophysaire).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Muscles oculomoteurs</h4><p class="mb-3">6 muscles extrinsèques : 4 droits (sup, inf, médial, latéral) + 2 obliques (sup, inf). Innervation : III (oculomoteur commun, 4 muscles + releveur paupière), IV (trochléaire, oblique sup), VI (abducens, droit latéral).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le glaucome est une hypertension intraoculaire (humeur aqueuse) → atteinte du nerf optique. La DMLA touche la macula → perte de la vision centrale. Le réflexe photomoteur passe par le II (afférent) et le III (efférent).</p></div>` },
  { id: 'anatomie-oreille', subject: 'anatomie', title: 'Organe de l\'audition', summary: 'Oreille externe, moyenne, interne et voies auditives.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">L'oreille</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Oreille externe</h4><p class="mb-3">Pavillon auriculaire (cartilage élastique) + conduit auditif externe (~25 mm). Rôle : capter et canaliser les ondes sonores vers le tympan.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Oreille moyenne</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Caisse du tympan</strong> : cavité aérienne dans le rocher du temporal.</li><li><strong>Chaîne des osselets</strong> : marteau (malleus) → enclume (incus) → étrier (stapes). Plus petits os du corps. Amplifient les vibrations (~20x).</li><li><strong>Trompe d'Eustache</strong> (trompe auditive) : relie l'oreille moyenne au rhinopharynx. Équilibre pressionnel.</li><li>Muscles : tenseur du tympan (V) et stapédien (VII) → réflexe stapédien de protection contre les sons forts.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Oreille interne</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Cochlée</strong> (limaçon) : organe de l'audition. 2.5 tours de spire. Organe de Corti (cellules ciliées internes = transduction mécano-électrique). Tonotopie : base = aigus, apex = graves.</li><li><strong>Vestibule</strong> : utricule + saccule (otolithes → accélérations linéaires et gravité).</li><li><strong>Canaux semi-circulaires</strong> (3, dans les 3 plans) : crêtes ampullaires → accélérations angulaires (rotation).</li><li>Liquides : périlymphe (rampes vestibulaire et tympanique) et endolymphe (canal cochléaire).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies auditives</h4><p class="mb-3">Nerf cochléaire (VIII) → noyaux cochléaires → olive supérieure → colliculus inférieur → corps genouillé médial (thalamus) → cortex auditif primaire (gyrus temporal supérieur, aire de Heschl).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Surdité de transmission (oreille externe/moyenne) vs surdité de perception (oreille interne/nerf). Le test de Weber et le test de Rinne permettent de les différencier. La maladie de Ménière associe vertiges, acouphènes et surdité (hydrops endolymphatique).</p></div>` },
  { id: 'anatomie-lymphatique', subject: 'anatomie', title: 'Système lymphatique', summary: 'Organes lymphoïdes, ganglions et circulation lymphatique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Système lymphatique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Circulation lymphatique</h4><p class="mb-3">Capillaires lymphatiques (borgnes) → vaisseaux lymphatiques afférents → <strong>nœuds lymphatiques</strong> (ganglions) → vaisseaux efférents → troncs lymphatiques → <strong>canal thoracique</strong> (gauche, draine 3/4 du corps) ou <strong>grande veine lymphatique</strong> (droite). Se jette dans la confluence jugulo-sous-clavière. ~2-4 L de lymphe/jour.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Organes lymphoïdes primaires</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Moelle osseuse rouge</strong> : hématopoïèse. Maturation des lymphocytes B.</li><li><strong>Thymus</strong> : maturation et sélection des lymphocytes T (sélection positive dans le cortex, négative dans la médullaire). Involue après la puberté.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Organes lymphoïdes secondaires</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Rate</strong> : filtre le sang. Pulpe blanche (lymphocytes) + pulpe rouge (destruction GR).</li><li><strong>Nœuds lymphatiques</strong> : filtrent la lymphe. Cortex (follicules B), paracortex (zone T), médullaire. Adénopathie = ganglion pathologique (&gt;1 cm).</li><li><strong>MALT</strong> (tissu lymphoïde associé aux muqueuses) : amygdales, plaques de Peyer (iléon), appendice.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Territoires ganglionnaires</h4><p class="mb-3">Cervicaux (tête/cou), axillaires (membre supérieur, sein), inguinaux (membre inférieur, périnée), médiastinaux, mésentériques. Le <strong>ganglion sentinelle</strong> = premier ganglion drainant une tumeur (biopsie en oncologie).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le canal thoracique naît de la citerne de Pecquet (L1-L2) et se termine dans le confluent jugulo-sous-clavier gauche. L'obstruction lymphatique provoque un lymphœdème.</p></div>` },
  { id: 'anatomie-mediastin', subject: 'anatomie', title: 'Anatomie du médiastin', summary: 'Contenu médiastinal, rapports et compartiments.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Le médiastin</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définition et limites</h4><p class="mb-3">Espace central du thorax entre les deux poumons. Limites : sternum (avant), rachis thoracique (arrière), plèvres médiastinales (latéral), orifice supérieur du thorax (haut), diaphragme (bas).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Compartiments</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Médiastin supérieur</strong> (au-dessus de T4) : arc aortique et ses branches (TABC, carotide commune gauche, subclavière gauche), VCS, trachée, œsophage, canal thoracique, thymus.</li><li><strong>Médiastin antérieur</strong> : thymus (ou reliquat graisseux), ganglions lymphatiques. Pathologie : thymome, lymphome, tumeurs germinales.</li><li><strong>Médiastin moyen</strong> : cœur + péricarde, gros vaisseaux (aorte ascendante, artère pulmonaire), bifurcation trachéale, nerfs phréniques.</li><li><strong>Médiastin postérieur</strong> : œsophage thoracique, aorte descendante, veines azygos, canal thoracique, nerfs vagues, chaîne sympathique. Pathologie : tumeurs neurogènes.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Rapports importants</h4><p class="mb-3">Le <strong>nerf récurrent laryngé gauche</strong> passe sous la crosse aortique (lésion → dysphonie). Le nerf récurrent droit passe sous l'artère subclavière droite. L'<strong>œsophage</strong> est en rapport étroit avec l'oreillette gauche (écho transœsophagienne).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : La règle des 4T pour les masses du médiastin antérieur : Thymome, Thyroïde (goitre plongeant), Terrible lymphome, Tumeur germinale. Le syndrome cave supérieur = compression de la VCS → œdème en pèlerine.</p></div>` },
  { id: 'anatomie-paroi-abdominale', subject: 'anatomie', title: 'Paroi abdominale et muscles du tronc', summary: 'Muscles abdominaux, canal inguinal et hernies.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Paroi abdominale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Muscles de la paroi antéro-latérale</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Grand droit</strong> (rectus abdominis) : vertical, de part et d'autre de la ligne blanche. Intersections tendineuses. Flexion du tronc.</li><li><strong>Oblique externe</strong> : fibres obliques en bas et en avant. Rotation controlatérale.</li><li><strong>Oblique interne</strong> : fibres obliques en haut et en avant. Rotation homolatérale.</li><li><strong>Transverse</strong> : fibres horizontales. Muscle le plus profond. Contention abdominale, expiration forcée.</li><li><strong>Gaine des droits</strong> : formée par les aponévroses des obliques et du transverse. Ligne blanche = raphé médian.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Canal inguinal</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Trajet oblique (~4 cm) dans la paroi abdominale inférieure. Orifice inguinal profond → orifice inguinal superficiel.</li><li>Contenu homme : <strong>cordon spermatique</strong> (canal déférent, artère testiculaire, plexus veineux pampiniforme).</li><li>Contenu femme : ligament rond de l'utérus.</li><li><strong>Hernie inguinale indirecte</strong> (latérale) : passe par l'orifice profond, dans le canal. <strong>Hernie directe</strong> (médiale) : passe par le triangle de Hesselbach (en dedans des vaisseaux épigastriques inférieurs).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Muscles du dos</h4><p class="mb-3">Plans superficiel (trapèze, grand dorsal), intermédiaire (dentelé postérieur), profond (<strong>érecteurs du rachis</strong> : iliocostal, longissimus, épineux ; muscles transversaires épineux : multifide, rotateurs). Le multifide est le stabilisateur segmentaire principal du rachis.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : La hernie inguinale est la hernie la plus fréquente (75% des hernies de la paroi). L'étranglement herniaire est une urgence chirurgicale (risque de nécrose intestinale).</p></div>` },
  { id: 'anatomie-vasc-cerebrale', subject: 'anatomie', title: 'Vascularisation cérébrale', summary: 'Polygone de Willis, territoires vasculaires et AVC.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Vascularisation cérébrale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Système carotidien (antérieur)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Artère carotide interne</strong> → artère cérébrale antérieure (ACA) + artère cérébrale moyenne (ACM/sylvienne).</li><li><strong>ACA</strong> : face médiale du lobe frontal et pariétal. Occlusion → déficit moteur/sensitif du membre inférieur controlatéral.</li><li><strong>ACM</strong> : face latérale. Artère la plus fréquemment touchée dans les AVC. Occlusion → hémiplégie brachio-faciale + aphasie (si hémisphère dominant).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Système vertébro-basilaire (postérieur)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Artères vertébrales</strong> (naissent des subclavières) → passent par les foramens transversaires C6-C1 → fusionnent en <strong>tronc basilaire</strong> → artères cérébrales postérieures (ACP).</li><li>Branches : PICA (cervelet postéro-inférieur), AICA, SCA. Artère spinale antérieure.</li><li><strong>ACP</strong> : lobe occipital (cortex visuel). Occlusion → hémianopsie latérale homonyme controlatérale.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Polygone de Willis</h4><p class="mb-3">Anastomose artérielle à la base du cerveau. ACA — <strong>communicante antérieure</strong> — ACA / ACI — <strong>communicante postérieure</strong> — ACP. Système de suppléance en cas d'occlusion. Nombreuses variantes anatomiques (cercle complet dans seulement ~25-50% des cas). Les anévrismes siègent préférentiellement sur la communicante antérieure (30-35%).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Drainage veineux</h4><p class="mb-3">Veines cérébrales → <strong>sinus veineux duraux</strong> (sinus sagittal supérieur, sinus transverse, sinus sigmoïde) → veines jugulaires internes. Confluence des sinus (pressoir d'Hérophile).</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : AVC ischémique (80%) vs hémorragique (20%). Le cerveau consomme 20% du débit cardiaque pour 2% du poids corporel. Ischémie > 4-5 min → lésions irréversibles. Thrombolyse si AVC ischémique < 4h30.</p></div>` },
  { id: 'anatomie-snc-fonctionnel', subject: 'anatomie', title: 'Anatomie fonctionnelle du SNC', summary: 'Aires corticales, voies motrices et sensitives.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">SNC : anatomie fonctionnelle</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Cortex cérébral — Aires fonctionnelles</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Lobe frontal</strong> : aire motrice primaire (M1, gyrus précentral — somatotopie/homonculus), aire prémotrice, aire de Broca (44-45, production du langage), cortex préfrontal (fonctions exécutives, personnalité).</li><li><strong>Lobe pariétal</strong> : aire somesthésique primaire (S1, gyrus postcentral), cortex pariétal postérieur (intégration spatiale, schéma corporel).</li><li><strong>Lobe temporal</strong> : aire auditive primaire (Heschl), aire de Wernicke (22, compréhension du langage), hippocampe (mémoire).</li><li><strong>Lobe occipital</strong> : aire visuelle primaire (V1), aires visuelles associatives (reconnaissance des formes, couleurs, mouvements).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voie motrice (pyramidale)</h4><p class="mb-3">Cortex moteur (M1) → <strong>faisceau corticospinal</strong> → décussation au niveau des <strong>pyramides bulbaires</strong> (80-90% croisent) → corne antérieure de la moelle → motoneurone alpha → muscle. Lésion du neurone moteur central (NMC) : spasticité, hyperréflexie, Babinski. Lésion du neurone moteur périphérique (NMP) : hypotonie, amyotrophie, aréflexie.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Voies sensitives</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Voie lemniscale</strong> (colonnes dorsales) : tact fin, proprioception, vibration. Décusse dans le bulbe. Neurone 1 → colonnes dorsales → noyaux gracile/cunéiforme → décussation → lemnisque médial → thalamus (VPL) → S1.</li><li><strong>Voie spinothalamique</strong> : douleur, température, tact grossier. Décusse dans la moelle (au niveau métamérique). Monte dans le cordon antéro-latéral → thalamus → S1.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Noyaux gris centraux (ganglions de la base)</h4><p class="mb-3">Striatum (noyau caudé + putamen), pallidum, noyau sous-thalamique, substance noire. Rôle dans la <strong>planification et l'initiation du mouvement</strong>. Maladie de Parkinson = dégénérescence de la substance noire → déficit dopaminergique → akinésie, rigidité, tremblement de repos.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Le syndrome de Brown-Séquard (hémi-section médullaire) : paralysie ipsilatérale (voie pyramidale croisée au bulbe) + perte de la proprioception ipsilatérale (colonnes dorsales croisent au bulbe) + perte thermo-algique controlatérale (voie spinothalamique croise dans la moelle).</p></div>` },
  { id: 'anatomie-embryologie', subject: 'anatomie', title: 'Embryologie générale', summary: 'Gastrulation, neurulation, organogenèse et annexes embryonnaires.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Embryologie générale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Première semaine</h4><p class="mb-3">Fécondation (trompe, ampoule) → zygote → segmentation (divisions mitotiques sans croissance) → <strong>morula</strong> (J3-J4) → <strong>blastocyste</strong> (J5-J6) : masse cellulaire interne (embryoblaste → embryon) + trophoblaste (→ placenta). Implantation dans l'endomètre J6-J7 (nidation).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Deuxième semaine (disque didermique)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Embryoblaste → 2 feuillets : <strong>épiblaste</strong> (dorsal) et <strong>hypoblaste</strong> (ventral).</li><li>Cavité amniotique (au-dessus de l'épiblaste), vésicule vitelline (sous l'hypoblaste).</li><li>Trophoblaste → syncytiotrophoblaste (envahit l'endomètre) + cytotrophoblaste.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Troisième semaine (gastrulation)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Ligne primitive</strong> → migration cellulaire → formation des 3 feuillets : <strong>ectoderme</strong>, <strong>mésoderme</strong>, <strong>endoderme</strong>.</li><li><strong>Ectoderme</strong> → SNC, peau, cristallin, émail dentaire.</li><li><strong>Mésoderme</strong> → muscles, os, cœur, reins, gonades, sang.</li><li><strong>Endoderme</strong> → épithélium digestif, respiratoire, foie, pancréas, thyroïde.</li><li><strong>Neurulation</strong> : plaque neurale → gouttière → tube neural (J21-J28). Défaut de fermeture → spina bifida (postérieur) ou anencéphalie (antérieur). Prévention : <strong>acide folique</strong>.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Organogenèse (semaines 4-8)</h4><p class="mb-3">Période la plus sensible aux <strong>tératogènes</strong>. Plicature de l'embryon (crânio-caudale et latérale). Formation du cœur (battement J22), des bourgeons des membres, de la face. Crêtes neurales → cellules migratrices → mélanoblastes, ganglions, médullosurrénale, os de la face.</p><div class="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-indigo-800">Point clé concours : Les malformations congénitales touchent ~3% des naissances. La période embryonnaire (S3-S8) est la plus vulnérable. L'alcool est le premier tératogène évitable (syndrome d'alcoolisation fœtale). L'acide folique en périconceptionnel réduit de 70% les anomalies du tube neural.</p></div>` },

  // ===== CHIMIE/BIOCHIMIE — EXTENSION PROGRAMME COMPLET =====
  { id: 'chimie-stereochimie', subject: 'chimie', title: 'Stéréochimie', summary: 'Chiralité, configurations R/S et E/Z, diastéréoisomères.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Stéréochimie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Isomérie</h4><p class="mb-3"><strong>Isomères de constitution</strong> (même formule brute, connectivité différente) vs <strong>stéréoisomères</strong> (même connectivité, arrangement spatial différent). Stéréoisomères = énantiomères + diastéréoisomères.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Chiralité</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Molécule chirale = non superposable à son image dans un miroir. Condition suffisante : <strong>carbone asymétrique</strong> (C*) lié à 4 substituants différents.</li><li><strong>Énantiomères</strong> : images miroir non superposables. Mêmes propriétés physico-chimiques sauf pouvoir rotatoire (+ dextrogyre / - lévogyre) et interactions avec d'autres molécules chirales.</li><li><strong>Mélange racémique</strong> : 50/50 énantiomères, pouvoir rotatoire nul.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Nomenclature R/S (Cahn-Ingold-Prelog)</h4><p class="mb-3">Classer les 4 substituants par priorité (Z décroissant). Placer le plus petit en arrière. Sens horaire = <strong>R</strong> (rectus), antihoraire = <strong>S</strong> (sinister).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Configuration E/Z (doubles liaisons)</h4><p class="mb-3">Pour C=C avec substituants différents de chaque côté. Priorités CIP sur chaque C. Même côté = <strong>Z</strong> (zusammen), côtés opposés = <strong>E</strong> (entgegen).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Diastéréoisomères</h4><p class="mb-3">Stéréoisomères non énantiomères. Propriétés physico-chimiques différentes (T°fusion, solubilité). n C* → 2^n stéréoisomères max. Forme <strong>méso</strong> : C* mais plan de symétrie interne → achirale.</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : En pharmacologie, les énantiomères peuvent avoir des activités très différentes (ex : thalidomide R = sédatif, S = tératogène). Les acides aminés naturels sont L (S sauf cystéine), les sucres naturels sont D.</p></div>` },
  { id: 'chimie-glucides', subject: 'chimie', title: 'Glucides détaillés', summary: 'Oses, osides, glycoprotéines et glycosaminoglycanes.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Les glucides</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Oses (monosaccharides)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Formule : Cn(H2O)n. Classification : aldoses (CHO) / cétoses (C=O). Trioses → hexoses.</li><li><strong>Glucose</strong> (aldohexose, D-glucose) : carburant principal. Glycémie ~1 g/L (5.5 mmol/L).</li><li><strong>Fructose</strong> (cétohexose) : fruits, miel. Métabolisme hépatique.</li><li><strong>Galactose</strong> : composant du lactose. Galactosémie = déficit enzymatique.</li><li>Cyclisation : formes furanose (5 atomes) et pyranose (6 atomes). Anomères alpha/beta selon position du OH anomérique.</li><li>Pouvoir réducteur : fonction aldéhyde ou cétone libre → réduit les réactifs (Fehling, Benedict).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Osides (oligosaccharides et polysaccharides)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Liaison O-glycosidique</strong> : entre C anomérique et OH d'un autre ose. Alpha ou beta.</li><li><strong>Saccharose</strong> (glucose + fructose, alpha-1,2) : non réducteur.</li><li><strong>Lactose</strong> (galactose + glucose, beta-1,4) : réducteur. Intolérance = déficit en lactase.</li><li><strong>Amidon</strong> : amylose (alpha-1,4 linéaire) + amylopectine (alpha-1,4 et alpha-1,6 ramifié). Réserve végétale.</li><li><strong>Glycogène</strong> : alpha-1,4 et alpha-1,6 (très ramifié). Réserve animale (foie, muscle).</li><li><strong>Cellulose</strong> : beta-1,4. Non digestible par l'homme (pas de cellulase). Fibres alimentaires.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Glycosaminoglycanes (GAG)</h4><p class="mb-3">Polymères d'unités disaccharidiques (hexosamine + acide uronique). <strong>Héparine</strong> (anticoagulant), <strong>acide hyaluronique</strong> (lubrification articulaire), chondroïtine sulfate (cartilage), kératane sulfate (cornée).</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : L'HbA1c (hémoglobine glyquée) reflète la glycémie moyenne sur 2-3 mois (glycation non enzymatique). Les glycoprotéines portent des chaînes oligosaccharidiques ajoutées dans le RE et le Golgi (N-glycosylation sur Asn, O-glycosylation sur Ser/Thr).</p></div>` },
  { id: 'chimie-proteines-structure', subject: 'chimie', title: 'Protéines : structure', summary: 'Niveaux de structure, hémoglobine, myoglobine et dénaturation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Structure des protéines</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Les 20 acides aminés</h4><p class="mb-3">Structure commune : NH2-CH(R)-COOH. Carbone alpha chiral (sauf glycine). Classification selon R : apolaires (Ala, Val, Leu, Ile, Pro, Phe, Trp, Met), polaires non chargés (Ser, Thr, Cys, Tyr, Asn, Gln), chargés + (Lys, Arg, His), chargés - (Asp, Glu). pHi = pH où charge nette = 0.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Niveaux de structure</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Primaire</strong> : séquence linéaire d'AA reliés par des liaisons peptidiques (C-N, planaire, caractère partiel de double liaison).</li><li><strong>Secondaire</strong> : <strong>hélice alpha</strong> (3.6 AA/tour, liaisons H intra-chaîne i→i+4) et <strong>feuillet beta</strong> (liaisons H inter-chaînes, parallèle ou antiparallèle). Coudes beta.</li><li><strong>Tertiaire</strong> : repliement 3D global. Stabilisé par interactions hydrophobes, liaisons ioniques, ponts disulfure (Cys-Cys), liaisons H, van der Waals.</li><li><strong>Quaternaire</strong> : association de sous-unités (ex : hémoglobine = tétramère alpha2-beta2).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Hémoglobine et myoglobine</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Myoglobine</strong> : monomère, 1 hème, courbe de fixation O2 hyperbolique. Stockage musculaire.</li><li><strong>Hémoglobine</strong> : tétramère (alpha2-beta2), 4 hèmes, courbe <strong>sigmoïde</strong> (coopérativité). Effet Bohr : ↓pH ou ↑CO2 → ↓affinité O2 (libération aux tissus). 2,3-BPG : diminue l'affinité.</li><li>HbF (fœtale, alpha2-gamma2) : affinité O2 supérieure à HbA (ne lie pas le 2,3-BPG).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Dénaturation</h4><p class="mb-3">Perte de la structure 3D (chaleur, pH extrême, urée, SDS) → perte de fonction. Réversible ou irréversible. Les <strong>chaperonnes</strong> (HSP) aident au repliement correct.</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : La drépanocytose = mutation E6V sur la chaîne beta (Glu→Val) → HbS → polymérisation → GR falciformes. Les prions sont des protéines mal repliées (PrPSc) qui catalysent le mauvais repliement d'autres PrPc.</p></div>` },
  { id: 'chimie-oxydoreduction', subject: 'chimie', title: 'Oxydoréduction', summary: 'Couples redox, potentiel standard, piles et applications biologiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Oxydoréduction</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définitions</h4><p class="mb-3"><strong>Oxydation</strong> = perte d'électrons (augmentation du nombre d'oxydation). <strong>Réduction</strong> = gain d'électrons. Couple redox Ox/Red : Ox + ne⁻ ⇌ Red. Toute réaction redox = transfert d'électrons d'un réducteur vers un oxydant.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Potentiel standard E°</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Mesuré vs <strong>ENH</strong> (électrode normale à hydrogène, E° = 0 V par convention).</li><li>Plus E° est élevé, plus l'oxydant est fort. Plus E° est bas, plus le réducteur est fort.</li><li><strong>Équation de Nernst</strong> : E = E° + (RT/nF) × ln([Ox]/[Red]). À 25°C : E = E° + (0.059/n) × log([Ox]/[Red]).</li><li>Réaction spontanée si ΔE° &gt; 0 (E°cathode - E°anode &gt; 0) → ΔG° = -nFΔE° &lt; 0.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Piles électrochimiques</h4><p class="mb-3"><strong>Anode</strong> = oxydation (pôle -). <strong>Cathode</strong> = réduction (pôle +). Pont salin assure la neutralité électrique. fem = E°cathode - E°anode.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Applications biologiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Chaîne respiratoire</strong> : transfert d'e⁻ du NADH (E° = -0.32 V) à O2 (E° = +0.82 V). ΔE° = +1.14 V → très exergonique.</li><li>Couples biologiques : NAD⁺/NADH, FAD/FADH2, cytochrome c oxydé/réduit, O2/H2O.</li><li><strong>Nombre d'oxydation du carbone</strong> : CO2 (+4) → glucose (0) → acides gras (~-2). Réduction = stockage d'énergie.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le NADH est un réducteur fort (E° bas). Chaque paire d'e⁻ du NADH qui traverse la chaîne respiratoire permet la synthèse de ~2.5 ATP. Le FADH2 entre plus tard → ~1.5 ATP.</p></div>` },
  { id: 'chimie-solutions', subject: 'chimie', title: 'Chimie des solutions', summary: 'Solubilité, Ks, complexation et précipitation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Chimie des solutions</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Solubilité et Ks</h4><p class="mb-3">Pour un sel peu soluble AB : AB(s) ⇌ A⁺(aq) + B⁻(aq). <strong>Ks</strong> (produit de solubilité) = [A⁺][B⁻]. Plus Ks est petit, moins le sel est soluble. Précipitation si Q &gt; Ks (quotient réactionnel &gt; Ks). Solubilité s = (Ks)^(1/n) selon la stœchiométrie.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Facteurs influençant la solubilité</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Effet d'ion commun</strong> : l'ajout d'un ion commun diminue la solubilité (déplacement d'équilibre).</li><li><strong>pH</strong> : pour les sels d'acides faibles (CaCO3), l'acidification augmente la solubilité (H⁺ consomme l'anion).</li><li><strong>Complexation</strong> : la formation d'un complexe augmente la solubilité (consomme le cation libre).</li><li>Température : solubilité augmente généralement avec T (sauf exceptions : CaSO4, Ca(OH)2).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Complexation</h4><p class="mb-3">Métal + ligand(s) → complexe. M + nL ⇌ MLn. Constante de formation globale <strong>beta_n</strong> = [MLn]/([M][L]^n). Les complexes stables ont des beta élevés. <strong>Agents chélateurs</strong> : ligands multidentates (EDTA, 6 sites de liaison) → complexes très stables (effet chélate).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Applications biomédicales</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Calculs rénaux : oxalate de calcium (CaC2O4, très peu soluble). Prévention : hydratation, citrate (complexe le Ca²⁺).</li><li><strong>EDTA</strong> : chélation du Ca²⁺ (anticoagulant in vitro), traitement intoxication plomb.</li><li>Gadolinium chélaté (IRM) : le chélate empêche la toxicité du Gd³⁺ libre.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : L'hydroxyapatite Ca10(PO4)6(OH)2 est le minéral de l'os et de l'émail dentaire. Sa solubilité augmente en milieu acide → caries dentaires. Le fluor substitue OH → fluoroapatite (plus résistante).</p></div>` },
  { id: 'chimie-metabolisme-aa', subject: 'chimie', title: 'Métabolisme des acides aminés', summary: 'Transamination, désamination, cycle de l\'urée et catabolisme.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Métabolisme des acides aminés</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Vue d'ensemble</h4><p class="mb-3">Les AA en excès ne sont pas stockés → catabolisme. Devenir du squelette carboné : néoglucogenèse ou cétogenèse. Devenir de l'azote : <strong>cycle de l'urée</strong> (élimination).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Transamination</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Transfert du groupe NH2 d'un AA vers un alpha-cétoacide. Catalysé par les <strong>aminotransférases</strong> (transaminases). Coenzyme : <strong>pyridoxal phosphate (PLP, vitamine B6)</strong>.</li><li><strong>ASAT (GOT)</strong> : aspartate + alpha-cétoglutarate ⇌ oxaloacétate + glutamate. Cardiaque, hépatique.</li><li><strong>ALAT (GPT)</strong> : alanine + alpha-cétoglutarate ⇌ pyruvate + glutamate. Spécifique du foie.</li><li>Le <strong>glutamate</strong> est le collecteur universel des groupes aminés.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Désamination oxydative</h4><p class="mb-3">Glutamate → alpha-cétoglutarate + NH4⁺. Catalysée par la <strong>glutamate déshydrogénase</strong> (mitochondrie hépatique). NAD⁺ ou NADP⁺. Libère l'ammoniac pour le cycle de l'urée.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Cycle de l'urée</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Localisation : <strong>foie</strong> (mitochondrie + cytosol). 5 enzymes.</li><li>Bilan : 2 NH4⁺ + CO2 + 3 ATP → <strong>urée</strong> (H2N-CO-NH2) + H2O + 2 ADP + AMP.</li><li>Étapes clés : CPS1 (mitochondrie, étape limitante) → citrulline → argininosuccinate → arginine → urée + ornithine.</li><li>L'urée est excrétée par les reins. Hyperammoniémie si déficit enzymatique → encéphalopathie.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">AA essentiels</h4><p class="mb-3">8 AA indispensables : Val, Leu, Ile, Thr, Met, Phe, Trp, Lys. Mnémo : "Le Very Lyrique Tristan Fait Mille Trucs Impossibles".</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : ALAT > ASAT oriente vers une hépatite. ASAT > ALAT oriente vers une atteinte musculaire ou cardiaque. La phénylcétonurie = déficit en phénylalanine hydroxylase → accumulation Phe → retard mental si non traité (dépistage néonatal).</p></div>` },
  { id: 'chimie-neoglucogenese', subject: 'chimie', title: 'Néoglucogenèse et glycogène', summary: 'Voie des pentoses phosphates, glycogénolyse et régulation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Métabolisme glucidique avancé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Néoglucogenèse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Synthèse de glucose à partir de précurseurs non glucidiques : <strong>pyruvate, lactate, glycérol, AA glucoformateurs</strong>.</li><li>Localisation : foie (90%) et rein (10%). Surtout en période de jeûne.</li><li>Contourne les 3 étapes irréversibles de la glycolyse : pyruvate → OAA (pyruvate carboxylase) → PEP (PEPCK), F1,6BP → F6P (F1,6-bisphosphatase), G6P → glucose (glucose-6-phosphatase).</li><li>Coût : 6 ATP + 2 GTP pour 1 glucose (vs 2 ATP produits par glycolyse).</li><li>Activée par le <strong>glucagon</strong>, inhibée par l'<strong>insuline</strong>.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Métabolisme du glycogène</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Glycogénogenèse</strong> : glucose → G6P → G1P → UDP-glucose → ajout par glycogène synthase (alpha-1,4) + enzyme branchante (alpha-1,6). Stimulée par l'insuline.</li><li><strong>Glycogénolyse</strong> : glycogène phosphorylase (coupe alpha-1,4) + enzyme débranchante (alpha-1,6) → G1P → G6P. Stimulée par glucagon (foie) et adrénaline (muscle).</li><li>Foie : libère du glucose dans le sang (glucose-6-phosphatase). Muscle : G6P entre dans la glycolyse (pas de G6Pase).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Voie des pentoses phosphates</h4><p class="mb-3">Phase oxydative : G6P → 6-phosphogluconate → ribulose-5P. Produit <strong>2 NADPH</strong> (biosynthèses, défense antioxydante via glutathion). Phase non oxydative : interconversions de sucres (ribose-5P pour synthèse des nucléotides). Enzyme clé : <strong>G6PD</strong> (déficit = favisme → anémie hémolytique par stress oxydant).</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le cycle de Cori (lactate musculaire → glucose hépatique) et le cycle glucose-alanine consomment de l'énergie hépatique. Les glycogénoses sont des maladies de surcharge en glycogène (ex : maladie de Von Gierke = déficit en G6Pase).</p></div>` },
  { id: 'chimie-hormones', subject: 'chimie', title: 'Hormones et messagers chimiques', summary: 'Catécholamines, stéroïdes, eicosanoïdes et signalisation hormonale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Hormones et messagers</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Classification chimique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Peptidiques</strong> : insuline, glucagon, GH, ACTH, ADH, ocytocine. Hydrophiles → récepteurs membranaires → seconds messagers (AMPc, IP3, DAG).</li><li><strong>Dérivés d'acides aminés</strong> : catécholamines (dopamine, noradrénaline, adrénaline — issues de la tyrosine), hormones thyroïdiennes (T3, T4 — tyrosine + iode), sérotonine et mélatonine (tryptophane).</li><li><strong>Stéroïdes</strong> : cortisol, aldostérone, testostérone, estradiol, progestérone, vitamine D. Lipophiles → traversent la membrane → récepteurs nucléaires → régulation de la transcription.</li><li><strong>Eicosanoïdes</strong> : dérivés de l'acide arachidonique (C20:4). Prostaglandines, thromboxanes (COX), leucotriènes (LOX). Action locale (paracrine/autocrine).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Synthèse des stéroïdes</h4><p class="mb-3">Cholestérol → <strong>prégnénolone</strong> (enzyme limitante : CYP11A1/P450scc, clivage de la chaîne latérale) → progestérone → cortisol (surrénale), aldostérone (surrénale), testostérone (testicule), estradiol (ovaire, via aromatase). Toutes les stéroïdes partagent le noyau cyclopentanoperhydrophénanthrène.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Axes hormonaux</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Axe hypothalamo-hypophysaire</strong> : hypothalamus (hormones releasing/inhibiting) → adénohypophyse (TSH, ACTH, LH, FSH, GH, PRL) → glandes cibles. Rétrocontrôle négatif.</li><li>Axe corticotrope : CRH → ACTH → cortisol. Rythme circadien (pic matinal).</li><li>Axe thyréotrope : TRH → TSH → T3/T4. T3 est la forme active (désiodation de T4).</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : L'aspirine inhibe COX (irréversiblement sur les plaquettes → antiagrégant). Les AINS inhibent COX1/COX2. Les corticoïdes inhibent la phospholipase A2 → anti-inflammatoire puissant. L'hyperaldostéronisme primaire (Conn) = HTA + hypokaliémie.</p></div>` },
  { id: 'chimie-spectroscopie', subject: 'chimie', title: 'Spectroscopie (UV, IR, masse)', summary: 'Techniques d\'analyse moléculaire et interprétation de spectres.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Spectroscopie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Spectroscopie UV-visible</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Absorption de photons UV-vis → transitions électroniques (n→pi*, pi→pi*).</li><li><strong>Loi de Beer-Lambert</strong> : A = epsilon × l × C. A = absorbance, epsilon = coefficient d'absorption molaire (L.mol⁻¹.cm⁻¹), l = trajet optique, C = concentration.</li><li>Lambda max : longueur d'onde du maximum d'absorption. Chromophores : C=C, C=O, cycles aromatiques.</li><li>Applications : dosage (protéines à 280 nm — Trp, Tyr ; ADN à 260 nm), cinétique enzymatique (NADH à 340 nm).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Spectroscopie infrarouge (IR)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Absorption IR → vibrations moléculaires (élongation, déformation).</li><li>Bandes caractéristiques : O-H (~3300 cm⁻¹ large), N-H (~3400 cm⁻¹), C=O (~1700 cm⁻¹), C-H (~2900 cm⁻¹).</li><li>Empreinte digitale : zone 600-1500 cm⁻¹, spécifique de chaque molécule.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Spectrométrie de masse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Principe : ionisation → séparation selon le rapport <strong>m/z</strong> (masse/charge) → détection.</li><li>Ionisation : ESI (électrospray, molécules biologiques), MALDI (protéomique).</li><li>Pic moléculaire [M+H]⁺ → masse molaire. Fragmentation → structure.</li><li>Applications : protéomique, pharmacologie, dépistage néonatal, toxicologie.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le rapport A260/A280 évalue la pureté de l'ADN (~1.8 pour ADN pur, ~2.0 pour ARN pur). La spectrométrie de masse tandem (MS/MS) est utilisée pour le dépistage néonatal de la phénylcétonurie et d'autres maladies métaboliques.</p></div>` },
  { id: 'chimie-proteomique', subject: 'chimie', title: 'Techniques d\'analyse des protéines', summary: 'Électrophorèse, western blot, chromatographie et protéomique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Analyse des protéines</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Électrophorèse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>SDS-PAGE</strong> : SDS dénature et charge négativement toutes les protéines proportionnellement à leur masse → séparation par <strong>masse moléculaire</strong> uniquement. Gel de polyacrylamide.</li><li><strong>Isoélectrofocalisation (IEF)</strong> : séparation selon le <strong>pHi</strong>. Gradient de pH dans le gel.</li><li><strong>2D-PAGE</strong> : IEF (1re dimension) + SDS-PAGE (2e dimension) → carte protéique.</li><li><strong>Électrophorèse des protéines sériques</strong> (clinique) : albumine, alpha-1, alpha-2, beta, gamma-globulines. Pic monoclonal en gamma → myélome.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Western blot (immunoblot)</h4><p class="mb-3">SDS-PAGE → transfert sur membrane (PVDF/nitrocellulose) → blocage → anticorps primaire (spécifique de la protéine cible) → anticorps secondaire conjugué (peroxydase ou fluorescence) → révélation. Détection spécifique et semi-quantitative.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Chromatographie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Exclusion de taille</strong> (filtration sur gel) : les grosses molécules sortent en premier (exclues des pores).</li><li><strong>Échange d'ions</strong> : cationique (résine -) retient les protéines +, anionique (résine +) retient les protéines -. Élution par gradient de sel ou pH.</li><li><strong>Affinité</strong> : ligand immobilisé capture spécifiquement la protéine cible. Très sélective (ex : protéine A pour les anticorps, Ni-NTA pour les protéines His-tag).</li><li><strong>HPLC</strong> : haute résolution, phase inverse (C18) pour peptides/protéines.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le test ELISA (Enzyme-Linked Immunosorbent Assay) utilise aussi des anticorps pour détecter/quantifier des protéines (diagnostic VIH, COVID, dosages hormonaux). ELISA sandwich = Ac capture + antigène + Ac détection.</p></div>` },
  { id: 'chimie-cholesterol', subject: 'chimie', title: 'Métabolisme du cholestérol', summary: 'Synthèse, lipoprotéines, statines et athérosclérose.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Cholestérol et lipoprotéines</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Synthèse du cholestérol</h4><p class="mb-3">À partir d'acétyl-CoA. Étape limitante : <strong>HMG-CoA réductase</strong> (3-hydroxy-3-méthylglutaryl-CoA → mévalonate). Cible des <strong>statines</strong> (inhibiteurs compétitifs). Localisation : foie principalement, toutes les cellules. ~700-900 mg/j synthétisés vs ~300 mg/j apportés par l'alimentation.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lipoprotéines</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Chylomicrons</strong> : transportent les lipides alimentaires (TG ++) de l'intestin vers les tissus. Apolipoprotéine B48.</li><li><strong>VLDL</strong> : transportent les TG hépatiques vers les tissus. ApoB100. → IDL → LDL.</li><li><strong>LDL</strong> ("mauvais cholestérol") : transportent le cholestérol vers les tissus. Captés par le récepteur LDL (LDLR). Oxydés → captés par macrophages → cellules spumeuses → athérosclérose.</li><li><strong>HDL</strong> ("bon cholestérol") : <strong>transport inverse</strong> du cholestérol (tissus → foie). ApoA1. Effet protecteur cardiovasculaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Régulation</h4><p class="mb-3"><strong>SREBP</strong> (Sterol Regulatory Element Binding Protein) : quand le cholestérol intracellulaire est bas → activation de SREBP → transcription de HMG-CoA réductase et LDLR. Rétrocontrôle négatif : excès de cholestérol → dégradation de HMG-CoA réductase.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Dérivés du cholestérol</h4><p class="mb-3">Hormones stéroïdes, acides biliaires (solubilisation des lipides alimentaires), vitamine D (7-déhydrocholestérol → cholécalciférol sous UV).</p><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : L'hypercholestérolémie familiale (mutation du LDLR) est la maladie génétique la plus fréquente (1/500 hétérozygote). LDL-cholestérol cible < 0.7 g/L en prévention secondaire. Statines = traitement de 1re intention.</p></div>` },
  { id: 'chimie-radicaux-libres', subject: 'chimie', title: 'Radicaux libres et stress oxydant', summary: 'ROS, antioxydants, dommages oxydatifs et pathologie.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Stress oxydant</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Espèces réactives de l'oxygène (ROS)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Anion superoxyde</strong> (O2•⁻) : formé par fuite d'e⁻ de la chaîne respiratoire (complexes I et III). Aussi par NADPH oxydase (phagocytes → bactéricidie).</li><li><strong>Peroxyde d'hydrogène</strong> (H2O2) : formé par SOD. Moins réactif mais diffusible. Substrat de la réaction de Fenton.</li><li><strong>Radical hydroxyle</strong> (HO•) : le plus réactif et destructeur. Réaction de Fenton : Fe²⁺ + H2O2 → Fe³⁺ + HO• + OH⁻.</li><li>Autres : monoxyde d'azote (NO•), peroxynitrite (ONOO⁻), acide hypochloreux (HOCl, par MPO des neutrophiles).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Dommages oxydatifs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Lipides</strong> : peroxydation lipidique (chaîne en cascade sur les AGPI membranaires). Marqueur : MDA, 4-HNE.</li><li><strong>Protéines</strong> : carbonylation, oxydation des thiols (Cys), fragmentation. Perte de fonction.</li><li><strong>ADN</strong> : 8-oxo-guanine (marqueur principal), cassures simple/double brin. Mutagenèse → cancer.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Défenses antioxydantes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Enzymatiques</strong> : SOD (O2•⁻ → H2O2), catalase (H2O2 → H2O + O2), glutathion peroxydase (GPx, avec GSH et Se).</li><li><strong>Non enzymatiques</strong> : glutathion (GSH), vitamine C (hydrosoluble), vitamine E (liposoluble, membranes), caroténoïdes, polyphénols.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : Le stress oxydant est impliqué dans le vieillissement, les maladies neurodégénératives (Alzheimer, Parkinson), le cancer, le diabète et l'athérosclérose. Les suppléments antioxydants n'ont pas prouvé de bénéfice clinique en prévention (études randomisées négatives).</p></div>` },
  { id: 'chimie-medicaments', subject: 'chimie', title: 'Chimie des médicaments', summary: 'Pharmacochimie, relations structure-activité et pharmacocinétique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Pharmacochimie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Relations structure-activité (RSA)</h4><p class="mb-3">La structure chimique d'un médicament détermine son activité pharmacologique. <strong>Pharmacophore</strong> : ensemble minimal de caractéristiques structurales nécessaires à l'interaction avec la cible (récepteur, enzyme). Modifications chimiques → modulation de l'activité, la sélectivité et la pharmacocinétique.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Interactions médicament-cible</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Liaisons faibles</strong> (réversibles) : ioniques, hydrogène, van der Waals, hydrophobes. Majorité des médicaments.</li><li><strong>Liaison covalente</strong> (irréversible) : aspirine (acétylation COX), oméprazole (IPP, pont disulfure avec H⁺/K⁺-ATPase), pénicilline (acylation PBP).</li><li>Agoniste : mime le ligand naturel → activation du récepteur. Antagoniste : se lie sans activer → bloque l'effet de l'agoniste.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Pharmacocinétique (ADME)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Absorption</strong> : orale (biodisponibilité, effet de premier passage hépatique), IV (100%), SC, IM.</li><li><strong>Distribution</strong> : liaison aux protéines plasmatiques (albumine), volume de distribution (Vd). Barrière hémato-encéphalique.</li><li><strong>Métabolisme</strong> : foie (cytochromes P450 — phase I oxydation, phase II conjugaison). CYP3A4 métabolise ~50% des médicaments. Inducteurs (rifampicine) et inhibiteurs (kétoconazole).</li><li><strong>Élimination</strong> : rénale (filtration glomérulaire, sécrétion tubulaire), biliaire. Demi-vie t½ = 0.693 × Vd / Clairance. État d'équilibre atteint après ~5 t½.</li></ul><div class="bg-emerald-50 border border-emerald-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-emerald-800">Point clé concours : La règle de Lipinski (rule of 5) prédit l'absorption orale : MW < 500, logP < 5, donneurs H < 5, accepteurs H < 10. Les prodrogues sont inactives et activées in vivo (ex : clopidogrel activé par CYP2C19).</p></div>` },

  // ===== BIOLOGIE CELLULAIRE — EXTENSION PROGRAMME COMPLET =====
  { id: 'biocell-noyau', subject: 'biocell', title: 'Noyau et chromatine', summary: 'Enveloppe nucléaire, euchromatine, hétérochromatine et nucléole.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Le noyau cellulaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Enveloppe nucléaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Double membrane : externe (continue avec le RE rugueux, ribosomes) et interne (lamina nucléaire).</li><li><strong>Pores nucléaires</strong> : ~3000-4000/noyau. Complexe du pore (NPC, ~125 MDa). Passage passif &lt;40 kDa. Transport actif : importines/exportines + <strong>Ran-GTP</strong>.</li><li><strong>Lamina nucléaire</strong> : réseau de lamines (A, B, C) sous la membrane interne. Soutien structural, ancrage chromatine. Mutations lamines → laminopathies (progéria de Hutchinson-Gilford).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Chromatine</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Nucléosome</strong> : unité de base. ADN (146 pb) enroulé autour d'un octamère d'histones (2x H2A, H2B, H3, H4). Histone H1 = histone de liaison.</li><li><strong>Euchromatine</strong> : décondensée, transcriptionnellement active. Riche en gènes exprimés.</li><li><strong>Hétérochromatine</strong> : condensée, inactive. Constitutive (centromères, télomères) ou facultative (corps de Barr = Xi inactivé).</li><li>Modifications post-traductionnelles des histones : acétylation (H3K9ac → activation), méthylation (H3K9me3 → répression, H3K4me3 → activation).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Nucléole</h4><p class="mb-3">Site de transcription des ARNr (par l'ARN pol I) et d'assemblage des sous-unités ribosomiques. Non délimité par membrane. Disparaît en mitose, se reforme en télophase. <strong>Organisateurs nucléolaires</strong> (NOR) : régions des chromosomes acrocentriques (13, 14, 15, 21, 22) portant les gènes d'ARNr.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Le signal de localisation nucléaire (NLS) permet l'import nucléaire via les importines. Le signal d'export nucléaire (NES) permet la sortie. La phosphorylation des lamines par CDK1 provoque la désassemblage de l'enveloppe nucléaire en mitose.</p></div>` },
  { id: 'biocell-trafic', subject: 'biocell', title: 'Trafic vésiculaire', summary: 'Endocytose, exocytose, voie sécrétoire et tri des protéines.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Trafic vésiculaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Voie sécrétoire (exocytose)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>RE rugueux (synthèse, repliement, N-glycosylation) → vésicules <strong>COPII</strong> (RE→Golgi) → Golgi cis → médian → trans (maturation des glycanes, tri) → vésicules vers membrane, lysosomes ou sécrétion.</li><li><strong>Sécrétion constitutive</strong> : continue, par défaut (protéines membranaires, MEC).</li><li><strong>Sécrétion régulée</strong> : stockage en granules, libération sur signal (Ca²⁺, AMPc). Ex : insuline, neurotransmetteurs.</li><li>Vésicules <strong>COPI</strong> : transport rétrograde (Golgi→RE, récupération des protéines résidentes du RE avec signal KDEL).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Endocytose</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Endocytose clathrine-dépendante</strong> : récepteurs concentrés dans les puits couverts de clathrine → vésicule → endosome précoce (tri : recyclage ou dégradation) → endosome tardif → fusion avec lysosome.</li><li><strong>Phagocytose</strong> : ingestion de grosses particules (bactéries, cellules mortes). Macrophages, neutrophiles. Phagosome → phagolysosome.</li><li><strong>Pinocytose</strong> : ingestion de fluide. Macropinocytose, cavéoles.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Machinerie de fusion</h4><p class="mb-3">Protéines <strong>SNARE</strong> : v-SNARE (vésicule) + t-SNARE (cible) → complexe trans-SNARE → fusion membranaire. <strong>Rab-GTPases</strong> : adressage des vésicules au bon compartiment. NSF + alpha-SNAP : désassemblage du complexe SNARE post-fusion.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : La toxine botulique et la toxine tétanique clivent les SNARE → bloquent la libération de neurotransmetteurs. Le mannose-6-phosphate (M6P) est le signal d'adressage des enzymes lysosomales (maladie des cellules I si défaut).</p></div>` },
  { id: 'biocell-differenciation', subject: 'biocell', title: 'Différenciation et cellules souches', summary: 'Pluripotence, iPSC, niches et différenciation cellulaire.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Cellules souches et différenciation</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Hiérarchie des cellules souches</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Totipotentes</strong> : zygote → morula. Donnent tous les tissus + annexes embryonnaires (placenta).</li><li><strong>Pluripotentes</strong> : cellules de la masse interne du blastocyste (cellules ES). Donnent les 3 feuillets mais pas les annexes.</li><li><strong>Multipotentes</strong> : cellules souches adultes. Un lignage : CSH (hématopoïétiques), CSM (mésenchymateuses), cellules satellites (muscle).</li><li><strong>Unipotentes</strong> : progéniteurs engagés. Un seul type cellulaire (kératinocytes basaux, spermatogonies).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Propriétés des cellules souches</h4><p class="mb-3"><strong>Auto-renouvellement</strong> (division symétrique → 2 cellules souches, ou asymétrique → 1 souche + 1 progéniteur) + <strong>différenciation</strong>. La <strong>niche</strong> est le microenvironnement qui maintient la quiescence et régule le destin cellulaire (signaux Wnt, Notch, BMP, Hedgehog).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">iPSC (cellules souches pluripotentes induites)</h4><p class="mb-3">Yamanaka (2006, Nobel 2012) : reprogrammation de cellules somatiques en cellules pluripotentes par 4 facteurs de transcription : <strong>Oct4, Sox2, Klf4, c-Myc</strong>. Applications : modélisation de maladies, criblage de médicaments, médecine régénérative personnalisée. Risque : tumorigénicité (c-Myc = oncogène).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Différenciation</h4><p class="mb-3">Activation séquentielle de <strong>facteurs de transcription</strong> spécifiques (MyoD pour muscle, GATA-1 pour érythrocytes). Remodelage épigénétique progressif (méthylation ADN, modifications histones). La différenciation est normalement irréversible (sauf reprogrammation).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Les CSH résident dans la moelle osseuse (niche endostéale/vasculaire). La greffe de CSH traite les leucémies. Les cellules souches cancéreuses (CSC) seraient responsables des rechutes (résistantes à la chimiothérapie).</p></div>` },
  { id: 'biocell-epithelial', subject: 'biocell', title: 'Tissu épithélial', summary: 'Classification, polarité, spécialisations apicales et lame basale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Tissu épithélial</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Caractéristiques générales</h4><p class="mb-3">Cellules jointives, polarisées, reposant sur une <strong>lame basale</strong>. Avasculaire (nutrition par diffusion depuis le tissu conjonctif sous-jacent). Forte capacité de renouvellement. Origines : ectoderme (épiderme), endoderme (épithélium digestif), mésoderme (mésothélium, endothélium).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Classification</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Simple</strong> (1 couche) : pavimenteux (endothélium, alvéoles), cubique (tubes rénaux), cylindrique (intestin).</li><li><strong>Stratifié</strong> (plusieurs couches) : pavimenteux kératinisé (épiderme), non kératinisé (œsophage, vagin), transitionnel/urothélium (vessie).</li><li><strong>Pseudo-stratifié</strong> : toutes les cellules touchent la lame basale mais n'atteignent pas toutes la surface. Épithélium respiratoire (cilié, cellules caliciformes à mucus).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Polarité et spécialisations</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Pôle apical</strong> : microvillosités (bordure en brosse intestinale → absorption, 600x surface), cils vibratiles (voies respiratoires → clairance mucociliaire), stéréocils (épididyme).</li><li><strong>Pôle latéral</strong> : jonctions intercellulaires (jonctions serrées, adhérentes, desmosomes, gap).</li><li><strong>Pôle basal</strong> : hémidesmosomes (ancrage à la lame basale via intégrines).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Lame basale</h4><p class="mb-3">Laminine + collagène IV + nidogène + perlécan. Filtre sélectif, support structural, rôle dans la signalisation. La rupture de la lame basale par les cellules cancéreuses = critère d'invasion (carcinome invasif vs in situ).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Le syndrome de Kartagener = défaut de dynéine ciliaire → immobilité ciliaire → bronchectasies, sinusites, situs inversus, infertilité masculine. La métaplasie malpighienne bronchique (tabac) = remplacement de l'épithélium cilié par un épithélium pavimenteux stratifié.</p></div>` },
  { id: 'biocell-conjonctif', subject: 'biocell', title: 'Tissu conjonctif', summary: 'Collagène, élastine, MEC, fibroblastes et tissus spécialisés.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Tissu conjonctif</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Caractéristiques</h4><p class="mb-3">Cellules dispersées dans une <strong>matrice extracellulaire (MEC)</strong> abondante. Vascularisé et innervé. Origine mésodermique (mésenchyme). Fonctions : soutien, nutrition, défense, réparation.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Cellules</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Fibroblastes</strong> : cellules résidentes principales. Synthèse de collagène, élastine, GAG, fibronectine. Rôle majeur dans la cicatrisation.</li><li><strong>Macrophages</strong> : phagocytose, présentation antigénique, sécrétion de cytokines. Dérivés des monocytes sanguins.</li><li><strong>Mastocytes</strong> : granules d'histamine et héparine. Réaction allergique (IgE → dégranulation).</li><li><strong>Adipocytes</strong> : stockage de triglycérides (blanc) ou thermogenèse (brun).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Fibres de la MEC</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Collagène</strong> : protéine la plus abondante du corps (~30%). Triple hélice (Gly-X-Y, souvent Pro et Hyp). Type I (os, tendon, peau), II (cartilage), III (réticuline), IV (lame basale). Synthèse : procollagène → clivage → fibrilles. Hydroxylation de Pro/Lys nécessite la <strong>vitamine C</strong> (scorbut si carence).</li><li><strong>Élastine</strong> : extensibilité et élasticité. Réseau de fibres élastiques (poumon, artères, peau). Desmosine = pont covalent spécifique. Marfan = mutation fibrilline-1 (protéine associée).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Substance fondamentale</h4><p class="mb-3">GAG (acide hyaluronique, chondroïtine sulfate) + protéoglycanes (GAG liés à une protéine core) + glycoprotéines d'adhérence (fibronectine, laminine). Gel hydraté résistant à la compression.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Le syndrome d'Ehlers-Danlos = anomalie du collagène → hyperlaxité articulaire, fragilité cutanée. L'ostéogenèse imparfaite = mutation du collagène I → fragilité osseuse ("maladie des os de verre").</p></div>` },
  { id: 'biocell-immunite-innee', subject: 'biocell', title: 'Immunité innée', summary: 'Barrières, phagocytes, inflammation, complément et cellules NK.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Immunité innée</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Barrières naturelles</h4><p class="mb-3"><strong>Mécaniques</strong> : peau (épithélium kératinisé), muqueuses, cils, péristaltisme. <strong>Chimiques</strong> : pH acide (estomac, vagin), lysozyme (larmes, salive), défensines, acides gras. <strong>Biologiques</strong> : microbiote commensal (compétition avec pathogènes).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Reconnaissance innée</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>PAMPs</strong> (Pathogen-Associated Molecular Patterns) : LPS bactérien, peptidoglycane, ARN double brin viral, flagelline.</li><li><strong>DAMPs</strong> (Damage-Associated) : ATP extracellulaire, HMGB1, acide urique (cellules endommagées).</li><li><strong>PRR</strong> (Pattern Recognition Receptors) : TLR (Toll-Like Receptors, 10 chez l'homme), NLR (cytoplasmiques), RLR (détectent ARN viral). TLR4 reconnaît le LPS.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Cellules de l'immunité innée</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Neutrophiles</strong> : les plus abondants (60-70% des leucocytes). Phagocytose, dégranulation, NETs (filets d'ADN). Premiers arrivés. Pus = neutrophiles morts.</li><li><strong>Macrophages</strong> : phagocytose, présentation antigénique (CPA), sécrétion de cytokines (TNF-alpha, IL-1, IL-6). M1 (pro-inflammatoire) vs M2 (réparation).</li><li><strong>Cellules dendritiques</strong> : CPA professionnelles → pont entre immunité innée et adaptative. Migration vers les ganglions lymphatiques.</li><li><strong>Cellules NK</strong> : tuent les cellules infectées ou tumorales (pas de CMH I → "missing self" → lyse). Perforines + granzymes. Pas de réarrangement des récepteurs.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Système du complément</h4><p class="mb-3">~30 protéines plasmatiques. 3 voies d'activation : classique (Ag-Ac → C1q), alterne (surface bactérienne → C3b), lectine (MBL → MASP). Convergent vers <strong>C3 convertase → C3a/C3b → C5 convertase → C5a/C5b → MAC (C5b-C9)</strong>. Effets : opsonisation (C3b), chimiotactisme (C3a, C5a), lyse cellulaire (MAC).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : L'inflammation aiguë : rougeur (vasodilatation), chaleur, gonflement (exsudation), douleur (bradykinine, PGE2). Les 4 signes de Celse. La fièvre est déclenchée par IL-1, IL-6, TNF-alpha → PGE2 hypothalamique.</p></div>` },
  { id: 'biocell-immunite-adaptive', subject: 'biocell', title: 'Immunité adaptative', summary: 'Lymphocytes T et B, anticorps, CMH et mémoire immunitaire.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Immunité adaptative</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Lymphocytes T</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Maturation dans le <strong>thymus</strong>. TCR (T Cell Receptor) reconnaît un peptide présenté par le CMH.</li><li><strong>LT CD4⁺</strong> (helpers) : reconnaissent CMH II (CPA). Sous-types : Th1 (immunité cellulaire, IFN-gamma), Th2 (immunité humorale, IL-4/5/13), Th17 (inflammation, IL-17), Treg (tolérance, IL-10, TGF-beta).</li><li><strong>LT CD8⁺</strong> (cytotoxiques) : reconnaissent CMH I (toutes cellules nucléées). Tuent par perforines/granzymes et Fas/FasL. Essentiels contre virus et tumeurs.</li><li>Sélection thymique : positive (cortex, survie si TCR reconnaît CMH du soi) + négative (médullaire, élimination si forte affinité pour auto-antigènes).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Lymphocytes B et anticorps</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Maturation dans la <strong>moelle osseuse</strong>. BCR = immunoglobuline de surface. Activés par l'antigène + aide T (CD4 Th2) → différenciation en <strong>plasmocytes</strong> (sécrétion d'anticorps) et cellules B mémoire.</li><li><strong>Ig structure</strong> : 2 chaînes lourdes + 2 légères. Région variable (paratope, liaison Ag) + région constante (fonctions effectrices). 5 classes : IgM (pentamère, primaire), IgG (la plus abondante, traverse le placenta), IgA (muqueuses, dimère), IgE (allergie, parasites), IgD (BCR naïf).</li><li>Diversité : recombinaison V(D)J (RAG1/RAG2), hypermutation somatique (centres germinatifs), commutation de classe (switch isotypique).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">CMH (Complexe Majeur d'Histocompatibilité)</h4><p class="mb-3"><strong>CMH I</strong> (HLA-A, B, C) : sur toutes les cellules nucléées. Présente des peptides endogènes aux LT CD8⁺. <strong>CMH II</strong> (HLA-DP, DQ, DR) : sur les CPA (macrophages, cellules dendritiques, LB). Présente des peptides exogènes aux LT CD4⁺. Le CMH est le système le plus polymorphe du génome → compatibilité HLA cruciale pour les greffes.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : La réponse primaire (IgM puis IgG, lente, ~10j) vs réponse secondaire (IgG rapide et intense, mémoire). La vaccination exploite la mémoire immunitaire. Le VIH détruit les LT CD4⁺ → immunodéficience → infections opportunistes.</p></div>` },
  { id: 'biocell-cancer', subject: 'biocell', title: 'Biologie du cancer', summary: 'Oncogènes, suppresseurs de tumeurs, métastases et thérapies ciblées.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Biologie du cancer</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Hallmarks du cancer (Hanahan & Weinberg)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Autosuffisance en signaux de croissance, insensibilité aux signaux anti-croissance.</li><li>Évasion de l'apoptose, potentiel réplicatif illimité (télomérase).</li><li>Angiogenèse soutenue (VEGF), invasion et métastases.</li><li>Reprogrammation du métabolisme (effet Warburg : glycolyse aérobie), évasion immunitaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Oncogènes</h4><p class="mb-3">Proto-oncogènes activés par mutation <strong>gain de fonction</strong> (dominant, 1 allèle suffit). Exemples : <strong>RAS</strong> (30% des cancers, GTPase bloquée en forme active), <strong>HER2/ErbB2</strong> (cancer du sein, récepteur tyrosine kinase amplifié), <strong>MYC</strong> (facteur de transcription, prolifération), <strong>BCR-ABL</strong> (LMC, translocation t(9;22) = chromosome Philadelphie).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Gènes suppresseurs de tumeurs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Inactivation par mutation <strong>perte de fonction</strong> (récessif, les 2 allèles). Knudson : "two-hit hypothesis".</li><li><strong>p53</strong> ("gardien du génome") : muté dans &gt;50% des cancers. Arrêt du cycle (p21), réparation ADN, apoptose. Li-Fraumeni si mutation germinale.</li><li><strong>Rb</strong> (rétinoblastome) : contrôle le passage G1→S en séquestrant E2F. Mutation germinale → rétinoblastome familial.</li><li><strong>BRCA1/BRCA2</strong> : réparation de l'ADN (recombinaison homologue). Mutation → cancer sein/ovaire héréditaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Métastases</h4><p class="mb-3">Cascade métastatique : perte d'adhérence (↓E-cadhérine, transition épithélio-mésenchymateuse EMT) → invasion locale (MMPs) → intravasation → survie dans la circulation → extravasation → colonisation d'un site distant. Sites préférentiels (théorie du "seed and soil" de Paget).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : L'imatinib (Glivec) cible BCR-ABL → révolution dans la LMC. Le trastuzumab (Herceptin) cible HER2. Les inhibiteurs de checkpoints immunitaires (anti-PD-1/PD-L1, anti-CTLA-4) restaurent l'immunité anti-tumorale (immunothérapie).</p></div>` },
  { id: 'biocell-reparation-adn', subject: 'biocell', title: 'Réparation de l\'ADN', summary: 'BER, NER, mismatch repair, recombinaison et conséquences des défauts.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Réparation de l'ADN</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Types de lésions</h4><p class="mb-3">~10 000-100 000 lésions/cellule/jour. Dépurination, désamination (C→U), oxydation (8-oxoG), dimères de thymine (UV), cassures simple brin (SSB) et double brin (DSB), adduits chimiques (benzopyrène du tabac), mésappariements (erreurs de réplication).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Mécanismes de réparation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>BER</strong> (Base Excision Repair) : lésions ponctuelles (oxydation, désamination). ADN glycosylase (reconnaît et excise la base altérée) → AP endonucléase → ADN polymérase beta → ligase.</li><li><strong>NER</strong> (Nucleotide Excision Repair) : lésions encombrantes (dimères de pyrimidine UV, adduits). Reconnaissance → incision 3' et 5' → excision (~25-30 nt) → resynthèse (ADN pol delta/epsilon) → ligase. Défaut → <strong>xeroderma pigmentosum</strong> (XP) : hypersensibilité UV → cancers cutanés précoces.</li><li><strong>MMR</strong> (Mismatch Repair) : erreurs de réplication (mésappariements). MSH2/MSH6 (reconnaissance) → MLH1/PMS2 (incision) → excision → resynthèse. Défaut → syndrome de Lynch (HNPCC) : cancer colorectal héréditaire. Instabilité des microsatellites (MSI).</li><li><strong>Recombinaison homologue (HR)</strong> : cassures double brin, haute fidélité (phase S/G2, chromatide sœur comme matrice). BRCA1/BRCA2, RAD51. Défaut → cancers sein/ovaire.</li><li><strong>NHEJ</strong> (Non-Homologous End Joining) : cassures double brin, rapide mais imprécis (toutes les phases). Ku70/Ku80, DNA-PKcs, ligase IV. Peut causer des microdélétions.</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : La "létalité synthétique" : les cellules BRCA-mutées dépendent de PARP pour la réparation → les inhibiteurs de PARP (olaparib) tuent sélectivement ces cellules tumorales. ATM et ATR sont les kinases sentinelles des dommages à l'ADN → activation de p53 et arrêt du cycle.</p></div>` },
  { id: 'biocell-epigenetique', subject: 'biocell', title: 'Épigénétique', summary: 'Méthylation de l\'ADN, modifications des histones et ARN non codants.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Épigénétique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définition</h4><p class="mb-3">Modifications <strong>héritables de l'expression génique sans changement de la séquence d'ADN</strong>. Transmissibles lors de la division cellulaire (et parfois transgénérationnellement). Explique comment ~200 types cellulaires différents ont le même génome mais des transcriptomes différents.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Méthylation de l'ADN</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Ajout d'un groupe méthyle sur le <strong>C5 des cytosines dans les dinucléotides CpG</strong>. Par les <strong>DNMT</strong> (DNA methyltransferases).</li><li>DNMT1 : maintien (copie le patron de méthylation après réplication). DNMT3a/3b : méthylation de novo.</li><li>Hyperméthylation des promoteurs → <strong>répression</strong> transcriptionnelle (recrutement de MBD → complexes répresseurs → compaction chromatine).</li><li>Îlots CpG : régions riches en CpG (promoteurs de ~70% des gènes). Normalement non méthylés. Hyperméthylation aberrante de suppresseurs de tumeurs dans les cancers.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Modifications des histones</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Sur les queues N-terminales. Code histone = combinaison de modifications → état transcriptionnel.</li><li><strong>Acétylation</strong> (HAT/HDAC) : neutralise charges + des lysines → relaxation chromatine → <strong>activation</strong>. H3K9ac, H3K27ac.</li><li><strong>Méthylation</strong> (HMT/KDM) : peut activer (H3K4me3) ou réprimer (H3K9me3, H3K27me3) selon le résidu et le degré.</li><li>Phosphorylation (H3S10p → condensation mitotique), ubiquitination.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">ARN non codants régulateurs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>miARN</strong> (~22 nt) : s'apparient au 3'UTR de l'ARNm cible → dégradation ou inhibition de la traduction. Régulent ~60% des gènes.</li><li><strong>lncARN</strong> (&gt;200 nt) : régulation transcriptionnelle. Ex : <strong>XIST</strong> = inactivation du chromosome X (corps de Barr).</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : L'empreinte parentale (imprinting) = expression monoallélique selon l'origine parentale (ex : IGF2 paternel, H19 maternel). Défaut → syndrome de Beckwith-Wiedemann ou Prader-Willi/Angelman. Les inhibiteurs de HDAC et de DNMT sont utilisés en oncologie (épigénétique du cancer).</p></div>` },
  { id: 'biocell-mitochondrie-bio', subject: 'biocell', title: 'Mitochondrie et bioénergétique', summary: 'Chaîne respiratoire, ATP synthase, découplage et maladies mitochondriales.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Mitochondrie et bioénergétique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Structure</h4><p class="mb-3">Double membrane : externe (porines, perméable) et interne (très imperméable, crêtes mitochondriales → surface augmentée). Espace intermembranaire. Matrice : ADNmt circulaire (16.5 kb, 37 gènes, héritage <strong>maternel</strong>), ribosomes mitochondriaux, enzymes du cycle de Krebs et de la beta-oxydation.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Chaîne respiratoire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Complexe I</strong> (NADH déshydrogénase) : NADH → ubiquinone. Pompe 4 H⁺.</li><li><strong>Complexe II</strong> (succinate déshydrogénase) : FADH2 → ubiquinone. Ne pompe PAS de H⁺. Seul complexe entièrement codé par l'ADN nucléaire.</li><li><strong>Complexe III</strong> (cytochrome bc1) : ubiquinol → cytochrome c. Pompe 4 H⁺.</li><li><strong>Complexe IV</strong> (cytochrome c oxydase) : cytochrome c → O2 → H2O. Pompe 2 H⁺. Inhibé par le CN⁻ et le CO.</li><li><strong>Complexe V</strong> (ATP synthase) : le gradient de H⁺ (force proton-motrice) entraîne la rotation du rotor → ADP + Pi → <strong>ATP</strong>. ~2.5 ATP/NADH, ~1.5 ATP/FADH2.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Bilan énergétique</h4><p class="mb-3">1 glucose → glycolyse (2 ATP + 2 NADH) → 2 pyruvate → 2 acétyl-CoA (2 NADH) → cycle de Krebs (2 GTP + 6 NADH + 2 FADH2) → phosphorylation oxydative → total <strong>~30-32 ATP</strong>.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Découplage et maladies</h4><p class="mb-3"><strong>UCP1</strong> (thermogénine, tissu adipeux brun) : dissipe le gradient en chaleur (thermogenèse du nouveau-né). <strong>Maladies mitochondriales</strong> : mutations ADNmt → MELAS (myopathie + encéphalopathie + acidose lactique + stroke-like episodes), MERRF, neuropathie optique de Leber. Hérédité maternelle.</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : L'intoxication au cyanure bloque le complexe IV → arrêt de la chaîne respiratoire → mort cellulaire rapide. Antidote : hydroxocobalamine. L'ouverture du pore de transition de perméabilité mitochondriale (mPTP) libère le cytochrome c → apoptose.</p></div>` },
  { id: 'biocell-communication', subject: 'biocell', title: 'Communication intercellulaire', summary: 'Synapses, neurotransmetteurs, jonctions gap et signalisation paracrine.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Communication intercellulaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Types de communication</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Endocrine</strong> : hormones sécrétées dans le sang → cibles distantes. Lent mais durable.</li><li><strong>Paracrine</strong> : médiateurs locaux (facteurs de croissance, cytokines, eicosanoïdes). Action sur cellules voisines.</li><li><strong>Autocrine</strong> : la cellule agit sur elle-même. Fréquent dans l'immunité et le cancer.</li><li><strong>Synaptique</strong> : neurotransmetteurs libérés dans la fente synaptique. Rapide et précis.</li><li><strong>Juxtacrine</strong> : contact direct cellule-cellule (Notch-Delta, jonctions gap).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">La synapse chimique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Potentiel d'action → dépolarisation du bouton synaptique → entrée de <strong>Ca²⁺</strong> (canaux voltage-dépendants) → fusion des vésicules synaptiques (SNARE) → libération du neurotransmetteur dans la fente.</li><li>NT se lie aux récepteurs post-synaptiques : <strong>ionotropiques</strong> (canaux ligand-dépendants, rapide : AMPA, NMDA, GABA-A, nicotinique) ou <strong>métabotropiques</strong> (RCPG, lent : muscarinique, sérotoninergique, dopaminergique).</li><li>Inactivation : recapture (transporteurs), dégradation enzymatique (AChE pour l'acétylcholine, MAO/COMT pour les catécholamines), diffusion.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Principaux neurotransmetteurs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Acétylcholine</strong> : jonction neuromusculaire (nicotinique), SNA parasympathique.</li><li><strong>Glutamate</strong> : principal NT excitateur du SNC. Récepteurs AMPA, NMDA (Ca²⁺, plasticité synaptique).</li><li><strong>GABA</strong> : principal NT inhibiteur du SNC. Cible des benzodiazépines (potentialisent GABA-A).</li><li><strong>Dopamine</strong> : récompense, motricité. Déficit → Parkinson. Excès → schizophrénie.</li><li><strong>Sérotonine (5-HT)</strong> : humeur, sommeil, appétit. Cible des ISRS (antidépresseurs).</li><li><strong>Noradrénaline</strong> : vigilance, stress. Recapture inhibée par les antidépresseurs tricycliques.</li></ul><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : Le curare bloque les récepteurs nicotiniques de la jonction neuromusculaire → paralysie. Les organophosphorés inhibent l'AChE → accumulation d'ACh → crise cholinergique. La potentialisation à long terme (LTP) au niveau hippocampique (récepteurs NMDA) est le substrat cellulaire de la mémoire.</p></div>` },
  { id: 'biocell-techniques', subject: 'biocell', title: 'Techniques de biologie cellulaire', summary: 'Microscopie, cytométrie, culture cellulaire et PCR.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Techniques de biologie cellulaire</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Microscopie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Optique</strong> : résolution ~200 nm (limite de diffraction). Coloration HE (hématoxyline = noyaux bleu, éosine = cytoplasme rose). Fond clair, contraste de phase (cellules vivantes), fluorescence.</li><li><strong>Confocale</strong> : laser + pinhole → sections optiques fines, reconstruction 3D. Fluorescence.</li><li><strong>Électronique à transmission (MET)</strong> : résolution ~0.2 nm. Coupes ultrafines, coloration métaux lourds. Ultrastructure (organites, virus).</li><li><strong>Électronique à balayage (MEB)</strong> : surface 3D. Topographie cellulaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Cytométrie en flux (FACS)</h4><p class="mb-3">Cellules en suspension passent une par une devant un laser. Mesure de la fluorescence (anticorps couplés à des fluorochromes) et de la diffusion lumineuse (taille, granularité). Permet le <strong>phénotypage</strong> (CD4, CD8, CD19), le tri cellulaire, l'analyse du cycle cellulaire (contenu en ADN), la détection d'apoptose (annexine V).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Culture cellulaire</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Culture primaire</strong> : directement du tissu. Durée de vie limitée (limite de Hayflick ~50 divisions).</li><li><strong>Lignées immortalisées</strong> : transformation spontanée ou induite (SV40, HPV E6/E7). Prolifèrent indéfiniment. HeLa (1re lignée humaine, carcinome du col, 1951).</li><li>Conditions : milieu (DMEM, RPMI), sérum (SVF 10%), 37°C, 5% CO2, stérilité.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">PCR et biologie moléculaire</h4><p class="mb-3"><strong>PCR</strong> : dénaturation (95°C) → hybridation amorces → élongation (Taq polymérase, 72°C). 2^n copies en n cycles. <strong>RT-qPCR</strong> : quantification de l'ARNm (rétrotranscription + PCR temps réel). CRISPR-Cas9 : édition génomique ciblée (guide RNA + Cas9 nucléase → coupure double brin → réparation/insertion).</p><div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-violet-800">Point clé concours : L'immunofluorescence utilise des anticorps couplés à des fluorochromes pour localiser des protéines in situ. La GFP (Green Fluorescent Protein) permet de suivre des protéines en temps réel dans les cellules vivantes. Le Southern blot = ADN, le Northern blot = ARN, le Western blot = protéines.</p></div>` },

  // ===== BIOSTATISTIQUES — EXTENSION PROGRAMME COMPLET =====
  { id: 'biostats-echantillonnage', subject: 'biostats', title: 'Échantillonnage et estimation', summary: 'Méthodes d\'échantillonnage, biais de sélection et estimation ponctuelle.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Échantillonnage</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Population et échantillon</h4><p class="mb-3">La <strong>population cible</strong> est l'ensemble des individus visés par l'étude. L'<strong>échantillon</strong> est un sous-groupe de la population, sélectionné pour être représentatif. Les résultats de l'échantillon sont généralisés à la population (inférence statistique).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Méthodes d'échantillonnage</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Aléatoire simple</strong> : chaque individu a la même probabilité d'être sélectionné (tirage au sort). Gold standard.</li><li><strong>Stratifié</strong> : division en strates (âge, sexe) puis tirage aléatoire dans chaque strate. Garantit la représentativité des sous-groupes.</li><li><strong>Par grappes (clusters)</strong> : tirage aléatoire de groupes entiers (hôpitaux, classes). Plus pratique mais moins précis (effet grappe).</li><li><strong>Systématique</strong> : sélection régulière (1 individu sur k). Attention au biais si périodicité dans la liste.</li><li><strong>De convenance</strong> : non probabiliste (volontaires, consultants). Biais de sélection majeur → résultats peu généralisables.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Estimation</h4><p class="mb-3"><strong>Estimation ponctuelle</strong> : valeur unique (ex : moyenne de l'échantillon pour estimer la moyenne de la population). <strong>Estimation par intervalle</strong> : intervalle de confiance (IC). Propriétés d'un bon estimateur : sans biais (E[estimateur] = paramètre), convergent (précision augmente avec n), efficace (variance minimale).</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : L'erreur d'échantillonnage (fluctuation) est inévitable mais quantifiable (IC). Le biais de sélection est systématique et non quantifiable → plus dangereux. La taille d'échantillon doit être calculée a priori (puissance, risque alpha, taille d'effet, variabilité).</p></div>` },
  { id: 'biostats-ic', subject: 'biostats', title: 'Intervalles de confiance', summary: 'IC à 95%, interprétation, calcul et lien avec les tests.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Intervalles de confiance</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">Un IC à 95% est un intervalle calculé à partir des données de l'échantillon tel que, si on répétait l'étude un grand nombre de fois, <strong>95% des IC calculés contiendraient la vraie valeur du paramètre</strong>. Ce n'est PAS la probabilité que le paramètre soit dans cet intervalle particulier.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Formule générale</h4><p class="mb-3"><strong>IC = estimation ± z × erreur standard</strong>. Pour un IC à 95% : z = 1.96. Pour 99% : z = 2.576. Pour 90% : z = 1.645. Si n petit et variance inconnue → t de Student (ddl = n-1) au lieu de z.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">IC pour une moyenne</h4><p class="mb-3">IC95% = x-barre ± 1.96 × (s/racine(n)). L'<strong>erreur standard</strong> (SEM = s/racine(n)) diminue quand n augmente. Multiplier n par 4 → diviser la largeur de l'IC par 2.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">IC pour une proportion</h4><p class="mb-3">IC95% = p ± 1.96 × racine(p(1-p)/n). Condition d'application : np > 5 et n(1-p) > 5 (approximation normale).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Lien avec les tests d'hypothèse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Si l'IC à 95% d'une <strong>différence</strong> ne contient pas 0 → p < 0.05 → significatif.</li><li>Si l'IC à 95% d'un <strong>RR ou OR</strong> ne contient pas 1 → association significative.</li><li>L'IC est plus informatif que le seul p : il donne la <strong>précision de l'estimation</strong> et la <strong>signification clinique</strong> (un effet significatif peut être cliniquement négligeable).</li></ul><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Confiance = 1 - alpha. Un IC large traduit un manque de précision (échantillon trop petit ou grande variabilité). L'IC ne dépend pas de la prévalence dans la population, contrairement aux VPP/VPN.</p></div>` },
  { id: 'biostats-meta-analyse', subject: 'biostats', title: 'Méta-analyse', summary: 'Forest plot, hétérogénéité, funnel plot et niveaux de preuve.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Méta-analyse</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définition</h4><p class="mb-3">Synthèse quantitative des résultats de <strong>plusieurs études indépendantes</strong> portant sur la même question. Plus haut niveau de preuve dans la hiérarchie de l'EBM (si bien conduite). La <strong>revue systématique</strong> est la recherche exhaustive et critique de la littérature ; la méta-analyse en est la synthèse statistique.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Forest plot</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Représentation graphique standard. Chaque étude = un carré (taille proportionnelle au poids/taille de l'échantillon) avec son IC (ligne horizontale).</li><li><strong>Diamant</strong> (losange) en bas = effet combiné global. Sa largeur = IC de l'estimation combinée.</li><li>Ligne verticale de <strong>non-effet</strong> : OR=1 ou différence=0. Si le diamant ne touche pas cette ligne → effet significatif.</li><li>Modèle à effets fixes (hypothèse d'un effet unique) vs <strong>modèle à effets aléatoires</strong> (hétérogénéité entre études, plus conservateur).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Hétérogénéité</h4><p class="mb-3">Variabilité des résultats entre études au-delà du hasard. Test Q de Cochran (Chi-2) et statistique <strong>I²</strong> : 0-25% faible, 25-50% modérée, 50-75% substantielle, >75% considérable. Si I² élevé → explorer les sources d'hétérogénéité (analyses en sous-groupes, méta-régression).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Biais de publication et funnel plot</h4><p class="mb-3">Les études avec résultats positifs/significatifs sont plus publiées que les négatives. <strong>Funnel plot</strong> : taille de l'effet vs précision (1/SE). Symétrique si pas de biais. Asymétrie → suspicion de biais de publication. Tests formels : Egger, Begg.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : La qualité d'une méta-analyse dépend de la qualité des études incluses ("garbage in, garbage out"). PRISMA est le guide de reporting des revues systématiques. L'approche GRADE évalue la qualité des preuves (de très faible à élevée).</p></div>` },
  { id: 'biostats-biais', subject: 'biostats', title: 'Biais et facteurs de confusion', summary: 'Biais de sélection, d\'information, de classement et confusion.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Biais et confusion</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Biais de sélection</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Erreur systématique liée à la <strong>sélection des sujets</strong>. L'échantillon n'est pas représentatif de la population cible.</li><li><strong>Biais de survie sélective</strong> : ne sont étudiés que les survivants (ex : étude de prévalence qui manque les cas rapidement fatals).</li><li><strong>Biais de Berkson</strong> (admission) : en milieu hospitalier, association artificielle entre 2 maladies (chacune augmente la probabilité d'hospitalisation).</li><li><strong>Biais de volontariat</strong> : les volontaires diffèrent des non-volontaires (plus sains, plus motivés).</li><li><strong>Biais d'attrition</strong> (perdus de vue) : les perdus de vue diffèrent des restants → résultats biaisés.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Biais d'information (classement)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Erreur dans la <strong>mesure de l'exposition ou de l'événement</strong>.</li><li><strong>Biais de mémoire</strong> (recall bias) : les cas se souviennent mieux de leur exposition que les témoins (cas-témoins).</li><li><strong>Biais de mesure</strong> : instrument mal calibré, variabilité inter-observateur.</li><li><strong>Biais de classement différentiel</strong> : l'erreur dépend du groupe → surestimation ou sous-estimation de l'association. Non différentiel → atténuation vers le nul.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Facteur de confusion (confounding)</h4><p class="mb-3">Variable liée à la fois à l'<strong>exposition ET à la maladie</strong>, sans être sur le chemin causal. Crée une association fausse ou masque une vraie. Ex : l'alcool confond l'association tabac-cancer du poumon (corrélé au tabac et facteur de risque de cancer). Contrôle : <strong>randomisation</strong> (le meilleur), stratification, appariement, ajustement multivarié (régression).</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Les 3 critères d'un facteur de confusion : (1) associé à l'exposition, (2) facteur de risque de la maladie, (3) n'est pas un intermédiaire sur le chemin causal. La randomisation répartit équitablement TOUS les facteurs de confusion (connus et inconnus).</p></div>` },
  { id: 'biostats-non-parametriques', subject: 'biostats', title: 'Tests non paramétriques', summary: 'Wilcoxon, Mann-Whitney, Kruskal-Wallis et corrélation de Spearman.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Tests non paramétriques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Quand les utiliser ?</h4><p class="mb-3">Quand les <strong>conditions d'application des tests paramétriques</strong> ne sont pas remplies : distribution non normale (petits échantillons, données asymétriques), variances inégales, données <strong>ordinales</strong> (scores, stades), ou présence de valeurs aberrantes. Basés sur les <strong>rangs</strong> (classement des valeurs) plutôt que sur les valeurs brutes.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Comparaison de 2 groupes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Mann-Whitney U</strong> (= Wilcoxon rang-sum) : 2 groupes <strong>indépendants</strong>. Alternative au t de Student. Compare la distribution des rangs entre les 2 groupes.</li><li><strong>Wilcoxon signé</strong> (signed-rank) : 2 mesures <strong>appariées</strong>. Alternative au t apparié. Analyse les rangs des différences.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Comparaison de k groupes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Kruskal-Wallis</strong> : k groupes <strong>indépendants</strong>. Alternative à l'ANOVA à un facteur. Si significatif → tests post-hoc (Dunn) pour identifier les paires différentes.</li><li><strong>Friedman</strong> : k mesures <strong>appariées</strong>. Alternative à l'ANOVA à mesures répétées.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Corrélation</h4><p class="mb-3"><strong>Spearman (rho)</strong> : corrélation basée sur les rangs. Alternative à Pearson. Valide pour les relations monotones (pas nécessairement linéaires) et les variables ordinales. rho = 1 - (6 × somme(di²))/(n(n²-1)).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Tableau récapitulatif</h4><p class="mb-3">t indépendant → Mann-Whitney. t apparié → Wilcoxon signé. ANOVA → Kruskal-Wallis. ANOVA répétée → Friedman. Pearson → Spearman.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Les tests non paramétriques sont moins puissants que les paramétriques quand les conditions sont remplies (risque beta plus élevé = plus de faux négatifs). Mais ils sont plus robustes face aux violations d'hypothèses et aux outliers.</p></div>` },
  { id: 'biostats-multivariee', subject: 'biostats', title: 'Analyse multivariée', summary: 'Régression logistique, modèle multivarié et ajustement.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Analyse multivariée</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">Étudier simultanément l'effet de <strong>plusieurs variables explicatives</strong> (indépendantes) sur une variable réponse (dépendante). Permet d'<strong>ajuster</strong> sur les facteurs de confusion et d'identifier les facteurs indépendamment associés à l'événement.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Régression linéaire multiple</h4><p class="mb-3">Variable dépendante <strong>quantitative continue</strong>. Y = beta0 + beta1X1 + beta2X2 + ... + epsilon. Chaque betai = effet de Xi sur Y à valeurs constantes des autres variables. R² = part de variance expliquée (0 à 1).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Régression logistique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Variable dépendante <strong>binaire</strong> (0/1, malade/non malade). Modélise le logit de la probabilité : ln(p/(1-p)) = beta0 + beta1X1 + beta2X2 + ...</li><li>Résultat : <strong>OR ajusté</strong> = exp(betai). OR > 1 = facteur de risque, OR < 1 = facteur protecteur.</li><li>Analyse la plus utilisée en épidémiologie et en recherche clinique.</li><li>Conditions : absence de multicolinéarité, au moins 10 événements par variable explicative (règle EPV).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Modèle de Cox (régression de survie)</h4><p class="mb-3">Variable dépendante = <strong>délai jusqu'à un événement</strong>. h(t) = h0(t) × exp(beta1X1 + ...). Résultat : <strong>HR ajusté</strong> (Hazard Ratio). Hypothèse de proportionnalité des risques.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Stratégies de modélisation</h4><p class="mb-3">Sélection des variables : descendante (backward, retrait progressif), ascendante (forward, ajout progressif), pas à pas (stepwise). Critères : AIC (Akaike), BIC, p-value (seuil souvent 0.20 en univarié pour entrer dans le modèle multivarié).</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Un OR brut qui change de >10% après ajustement sur un facteur → ce facteur est un confondeur. La régression logistique est l'outil de choix pour les études cas-témoins. Le modèle de Cox est l'outil de choix pour les études de cohorte avec suivi temporel.</p></div>` },
  { id: 'biostats-descriptives-avancees', subject: 'biostats', title: 'Statistiques descriptives avancées', summary: 'Box plots, quantiles, coefficients d\'asymétrie et de kurtosis.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Statistiques descriptives avancées</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Mesures de position (quantiles)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Médiane (Q2)</strong> : valeur qui partage la distribution en 2 parties égales. Robuste aux valeurs extrêmes (contrairement à la moyenne).</li><li><strong>Quartiles</strong> : Q1 (25%), Q2 (50%), Q3 (75%). <strong>IQR</strong> (interquartile range) = Q3 - Q1. Mesure de dispersion robuste.</li><li><strong>Percentiles</strong> : P10, P90 souvent utilisés en pédiatrie (courbes de croissance).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Box plot (boîte à moustaches)</h4><p class="mb-3">Représentation graphique des quartiles. La boîte va de Q1 à Q3 (IQR), la ligne médiane = Q2. Moustaches = Q1 - 1.5×IQR à Q3 + 1.5×IQR. Points au-delà = <strong>valeurs aberrantes (outliers)</strong>. Permet de comparer visuellement la distribution entre groupes.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Forme de la distribution</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Asymétrie (skewness)</strong> : 0 = symétrique. Positive = queue à droite (moyenne > médiane). Négative = queue à gauche (moyenne < médiane).</li><li><strong>Aplatissement (kurtosis)</strong> : 0 = distribution normale (mésokurtique). Positif = pics et queues épaisses (leptokurtique). Négatif = aplatie (platykurtique).</li><li>Tests de normalité : <strong>Shapiro-Wilk</strong> (le plus puissant pour n < 50), Kolmogorov-Smirnov, D'Agostino-Pearson. QQ-plot : si les points suivent la diagonale → distribution normale.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Variables qualitatives</h4><p class="mb-3">Tableaux de fréquences (effectifs, pourcentages). Diagramme en barres (qualitatives) ou secteurs (circulaire). Mode = valeur la plus fréquente.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Si la distribution est asymétrique, on décrit par la médiane et l'IQR (et non la moyenne et l'écart-type). Le coefficient de variation (CV = ET/moyenne × 100) permet de comparer la dispersion entre variables d'unités différentes.</p></div>` },
  { id: 'biostats-protocole-essai', subject: 'biostats', title: 'Protocole d\'un essai clinique', summary: 'Design, critères, monitoring, effets indésirables et bonnes pratiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Protocole d'essai clinique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Phases de développement</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Phase I</strong> : première administration chez l'homme (volontaires sains sauf oncologie). Tolérance, pharmacocinétique, dose maximale tolérée. ~20-80 sujets.</li><li><strong>Phase II</strong> : efficacité préliminaire chez des patients. Dose optimale. ~100-300 patients.</li><li><strong>Phase III</strong> : essai comparatif randomisé (vs placebo ou traitement de référence). Confirme l'efficacité et la sécurité. ~1000-3000 patients. Base de l'AMM.</li><li><strong>Phase IV</strong> : post-AMM. Pharmacovigilance, conditions réelles d'utilisation, effets rares et à long terme.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Éléments clés du protocole</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Question PICO</strong> : Population, Intervention, Comparateur, Outcome (critère de jugement).</li><li><strong>Critères d'inclusion/exclusion</strong> : définissent la population éligible.</li><li><strong>Critère de jugement principal</strong> : unique, pertinent cliniquement, mesurable objectivement. Critères secondaires : exploratoires.</li><li><strong>Calcul du nombre de sujets nécessaires</strong> : alpha (5%), puissance (80-90%), différence cliniquement pertinente, variabilité attendue.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Randomisation et insu</h4><p class="mb-3"><strong>Randomisation</strong> : allocation aléatoire → groupes comparables (confondeurs contrôlés). Stratification possible. <strong>Simple aveugle</strong> : patient ignorant. <strong>Double aveugle</strong> : patient ET médecin. <strong>Triple aveugle</strong> : + analyste. Lève de l'insu en cas d'urgence médicale.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Analyse</h4><p class="mb-3"><strong>Intention de traiter (ITT)</strong> : analyse tous les randomisés dans leur groupe d'origine (même s'ils n'ont pas reçu le traitement). Préserve la randomisation. <strong>Per protocole (PP)</strong> : seulement les compléteurs. <strong>CONSORT</strong> : guide de reporting des essais randomisés.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : L'analyse en ITT est l'analyse principale (conservatrice, préserve la randomisation). L'essai de non-infériorité utilise une marge prédéfinie : le nouveau traitement est "non inférieur" si l'IC de la différence ne dépasse pas cette marge.</p></div>` },
  { id: 'biostats-pharmacovigilance', subject: 'biostats', title: 'Pharmacovigilance et iatrogénie', summary: 'Imputabilité, notification, effets indésirables et centres régionaux.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Pharmacovigilance</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Définition</h4><p class="mb-3">Surveillance des <strong>effets indésirables médicamenteux (EIM)</strong> après commercialisation (phase IV). Objectif : détecter les signaux d'alerte, évaluer la causalité, informer les professionnels et les patients. En France : <strong>ANSM</strong> + réseau des 31 centres régionaux de pharmacovigilance (CRPV).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Notification</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Obligation de déclaration</strong> : tout professionnel de santé doit notifier les EIM graves ou inattendus au CRPV. Les patients peuvent aussi déclarer (depuis 2011).</li><li>EIM <strong>grave</strong> : décès, mise en jeu du pronostic vital, hospitalisation ou prolongation, incapacité, anomalie congénitale.</li><li>EIM <strong>inattendu</strong> : non mentionné dans le RCP (résumé des caractéristiques du produit).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Imputabilité</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Imputabilité intrinsèque</strong> : chronologique (délai compatible, évolution à l'arrêt, réintroduction) + sémiologique (tableau clinique évocateur, facteurs favorisants, diagnostic différentiel).</li><li><strong>Imputabilité extrinsèque</strong> : données bibliographiques (effet connu ou non). Échelle de Bégaud.</li><li>Niveaux : exclu, douteux, plausible, vraisemblable, très vraisemblable.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Iatrogénie</h4><p class="mb-3">Ensemble des conséquences néfastes liées aux soins. ~130 000 hospitalisations/an liées aux EIM en France. Facteurs de risque : <strong>polymédication</strong> (>5 médicaments), âge avancé, insuffisance rénale/hépatique, interactions médicamenteuses. Les anticoagulants, AINS, psychotropes et antibiotiques sont les plus impliqués.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Le plan de gestion des risques (PGR) est obligatoire pour tout nouveau médicament. La réadmission test positive (dechallenge/rechallenge) est le critère le plus fort d'imputabilité chronologique. La iatrogénie est la 3e cause de mortalité dans les pays développés.</p></div>` },
  { id: 'biostats-indices-avances', subject: 'biostats', title: 'Indices épidémiologiques avancés', summary: 'RAR, NNT, NNH, fraction attribuable et rapport de cotes.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Indices épidémiologiques avancés</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Réduction absolue du risque (RAR)</h4><p class="mb-3">RAR = Risque dans le groupe contrôle - Risque dans le groupe traité. Ex : mortalité 10% vs 8% → RAR = 2% = 0.02. Mesure l'<strong>impact clinique</strong> du traitement.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Réduction relative du risque (RRR)</h4><p class="mb-3">RRR = RAR / Risque contrôle = 1 - RR. Ex : RRR = 0.02/0.10 = 20%. Attention : la RRR est souvent "impressionnante" même quand le RAR est faible (ex : RRR de 50% pour passer de 0.002 à 0.001 → RAR = 0.001).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">NNT (Number Needed to Treat)</h4><p class="mb-3"><strong>NNT = 1 / RAR</strong>. Nombre de patients à traiter pour éviter 1 événement. Ex : RAR = 0.02 → NNT = 50. Plus le NNT est bas, plus le traitement est efficace. NNT = 1 → traitement parfait. NNT > 100 → bénéfice faible.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">NNH (Number Needed to Harm)</h4><p class="mb-3">NNH = 1 / (Risque EIM traitement - Risque EIM contrôle). Nombre de patients traités pour provoquer 1 effet indésirable supplémentaire. Le rapport <strong>NNT/NNH</strong> donne le bénéfice-risque.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Fraction attribuable</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Fraction étiologique du risque (FER)</strong> chez les exposés = (RR-1)/RR. Part des cas chez les exposés attribuable à l'exposition.</li><li><strong>Fraction attribuable dans la population (FAP)</strong> = Pe × (RR-1) / (Pe × (RR-1) + 1). Pe = prévalence de l'exposition. Part des cas dans la population attribuable à l'exposition. Utile en santé publique (ex : si on supprime le tabac, quel % de cancers du poumon serait évité ?).</li></ul><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Le NNT est l'indice le plus utile en pratique clinique pour évaluer l'intérêt d'un traitement. La RRR seule est trompeuse (toujours demander le RAR ou le NNT). La FAP du tabac pour le cancer du poumon est d'environ 85%.</p></div>` },
  { id: 'biostats-categoriel', subject: 'biostats', title: 'Analyse de données catégorielles', summary: 'Tableaux croisés, test exact de Fisher et Chi-2.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Données catégorielles</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Tableau de contingence</h4><p class="mb-3">Tableau croisé 2×2 (ou plus) croisant 2 variables qualitatives. Cellules a, b, c, d (exposés malades, exposés non malades, non exposés malades, non exposés non malades). Effectifs marginaux et total.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Test du Chi-2 de Pearson</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Compare les effectifs <strong>observés vs attendus</strong> (sous H0 d'indépendance). Chi-2 = somme((O-E)²/E).</li><li>ddl = (lignes-1) × (colonnes-1). Pour un tableau 2×2 : ddl = 1.</li><li>Conditions : <strong>effectifs attendus ≥ 5</strong> dans toutes les cellules. Si non → test exact de Fisher.</li><li><strong>Correction de Yates</strong> : pour tableau 2×2, soustrait 0.5 à |O-E| avant de mettre au carré. Corrige la surestimation du Chi-2 quand les effectifs sont limites.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Test exact de Fisher</h4><p class="mb-3">Calcul exact de la probabilité sous H0 (basé sur la loi hypergéométrique). Utilisé quand les <strong>effectifs sont petits</strong> (attendus < 5). Pas d'approximation. Plus conservateur que le Chi-2.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Test de McNemar</h4><p class="mb-3">Pour données appariées (avant/après, jumeaux). Tableau 2×2 apparié. Compare les cellules discordantes. Chi-2 = (b-c)²/(b+c). Si b+c < 25 → test exact binomial.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Mesures d'association</h4><p class="mb-3"><strong>OR</strong> = (a×d)/(b×c) : cas-témoins et transversales. <strong>RR</strong> = [a/(a+b)] / [c/(c+d)] : cohortes. V de Cramer : force d'association pour tableaux > 2×2.</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Le Chi-2 de tendance (Cochran-Armitage) teste une tendance linéaire pour une variable ordinale. Pour les tableaux plus grands (r×c), le Chi-2 de Pearson teste l'indépendance globale, pas la direction de l'association.</p></div>` },
  { id: 'biostats-graphiques', subject: 'biostats', title: 'Représentations graphiques', summary: 'Histogrammes, diagrammes, courbes de tendance et pièges visuels.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Représentations graphiques</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Variables quantitatives</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Histogramme</strong> : fréquence vs classes de valeurs. Les barres sont accolées (variable continue). Permet de visualiser la forme de la distribution (normale, bimodale, asymétrique).</li><li><strong>Diagramme en boîte (box plot)</strong> : médiane, Q1, Q3, IQR, outliers. Idéal pour comparer plusieurs groupes.</li><li><strong>Scatter plot (nuage de points)</strong> : corrélation entre 2 variables quantitatives. Droite de régression possible.</li><li><strong>Courbe de Kaplan-Meier</strong> : survie en fonction du temps. Marches d'escalier décroissantes. Censures marquées par un trait.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Variables qualitatives</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Diagramme en barres</strong> : hauteur proportionnelle à la fréquence. Barres séparées (vs histogramme). Horizontal ou vertical.</li><li><strong>Diagramme circulaire (camembert)</strong> : proportion de chaque catégorie. Limité à peu de catégories (≤ 6). Critiqué car difficile à lire précisément.</li><li><strong>Diagramme en barres empilées</strong> : composition de chaque groupe. 100% stacked pour comparer les proportions.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Pièges à éviter</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Axe des ordonnées tronqué</strong> : ne commence pas à 0 → amplifie visuellement les différences.</li><li><strong>Échelle non linéaire</strong> (log) non signalée → interprétation erronée.</li><li><strong>Diagramme 3D</strong> : distorsion perspective → catégories au premier plan semblent plus grandes.</li><li><strong>Cherry-picking temporel</strong> : sélection d'une période favorisant une conclusion.</li></ul><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Le forest plot (méta-analyse) et la courbe ROC (performance diagnostique) sont les graphiques les plus fréquemment demandés en LCA. Un bon graphique doit avoir un titre, des légendes d'axes, une unité, et une source.</p></div>` },
  { id: 'biostats-ethique-donnees', subject: 'biostats', title: 'Éthique et réglementation des données', summary: 'RGPD, CNIL, données de santé et consentement numérique.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Protection des données de santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">RGPD (Règlement Général sur la Protection des Données, 2018)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Règlement européen. S'applique à tout traitement de données personnelles.</li><li>Principes : <strong>licéité, loyauté, transparence</strong>, limitation des finalités, minimisation, exactitude, limitation de conservation, intégrité et confidentialité, responsabilité.</li><li>Droits des personnes : information, accès, rectification, effacement (droit à l'oubli), portabilité, opposition, limitation du traitement.</li><li>Données de santé = <strong>données sensibles</strong> : traitement interdit sauf exceptions (consentement explicite, recherche avec dérogation, intérêt vital, santé publique).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">CNIL et données de santé</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>CNIL</strong> : autorité de contrôle française. Veille au respect du RGPD. Peut sanctionner (amendes jusqu'à 4% du CA mondial ou 20 millions d'euros).</li><li>Recherche en santé : MR (méthodologies de référence) de la CNIL. MR-001 : recherches interventionnelles, MR-003 : recherches non interventionnelles, MR-004 : études à partir de données existantes.</li><li><strong>SNDS</strong> (Système National des Données de Santé) : entrepôt national regroupant les données de l'Assurance Maladie, hospitalières (PMSI), causes de décès. Accès encadré par le CESREES et la CNIL.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Anonymisation vs pseudonymisation</h4><p class="mb-3"><strong>Anonymisation</strong> : irréversible, la personne n'est plus identifiable → hors RGPD. <strong>Pseudonymisation</strong> : table de correspondance séparée, réversible → toujours soumis au RGPD. En recherche : les données sont généralement pseudonymisées (code d'inclusion).</p><div class="bg-cyan-50 border border-cyan-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-cyan-800">Point clé concours : Le DPO (Data Protection Officer / Délégué à la Protection des Données) est obligatoire dans les hôpitaux et organismes de recherche. L'AIPD (Analyse d'Impact relative à la Protection des Données) est requise pour les traitements à risque élevé (données de santé à grande échelle).</p></div>` },

  // ===== BIOPHYSIQUE — EXTENSION PROGRAMME COMPLET =====
  { id: 'biophysique-ecg', subject: 'biophysique', title: 'Électrophysiologie : ECG', summary: 'Dérivations, ondes PQRST, interprétation et pathologies.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Électrocardiogramme</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">L'ECG enregistre l'activité électrique du cœur via des électrodes cutanées. Chaque onde correspond à une phase de dépolarisation ou repolarisation du myocarde.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Dérivations</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>6 dérivations frontales</strong> : DI, DII, DIII (bipolaires, triangle d'Einthoven) + aVR, aVL, aVF (unipolaires augmentées). Explorent le plan frontal.</li><li><strong>6 dérivations précordiales</strong> : V1-V6 (unipolaires). Explorent le plan horizontal. V1-V2 (septum/VD), V3-V4 (apex/paroi antérieure), V5-V6 (paroi latérale).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Ondes et intervalles</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Onde P</strong> : dépolarisation auriculaire. Durée &lt;120 ms, amplitude &lt;2.5 mm.</li><li><strong>Intervalle PR</strong> : conduction AV. Normal : 120-200 ms. Allongé → BAV 1er degré.</li><li><strong>Complexe QRS</strong> : dépolarisation ventriculaire. Durée &lt;120 ms. Élargi → bloc de branche.</li><li><strong>Segment ST</strong> : isoélectrique normalement. Sus-décalage → infarctus (STEMI), sous-décalage → ischémie.</li><li><strong>Onde T</strong> : repolarisation ventriculaire.</li><li><strong>Intervalle QT</strong> : dépolarisation + repolarisation ventriculaire. QT corrigé (QTc, formule de Bazett). Allongé → risque de torsade de pointes.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Loi d'Einthoven : DII = DI + DIII. L'axe électrique normal du cœur est entre 0° et +90°. La fibrillation auriculaire : disparition des ondes P, irrégularité des QRS. La fibrillation ventriculaire est une urgence vitale (défibrillation immédiate).</p></div>` },
  { id: 'biophysique-eeg', subject: 'biophysique', title: 'EEG et potentiels évoqués', summary: 'Ondes cérébrales, sommeil, épilepsie et potentiels évoqués.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Électroencéphalogramme</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">L'EEG enregistre l'activité électrique corticale via des électrodes sur le scalp. Signal = somme des potentiels postsynaptiques des neurones pyramidaux corticaux. Système 10-20 (placement standardisé des électrodes).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Rythmes cérébraux</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Alpha</strong> (8-13 Hz) : éveil calme, yeux fermés, régions postérieures. Bloqué à l'ouverture des yeux.</li><li><strong>Beta</strong> (13-30 Hz) : éveil actif, concentration, régions frontales.</li><li><strong>Thêta</strong> (4-8 Hz) : somnolence, sommeil léger. Pathologique si excessif à l'éveil (souffrance cérébrale).</li><li><strong>Delta</strong> (&lt;4 Hz) : sommeil profond (stades 3-4). Pathologique à l'éveil (lésion cérébrale).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Applications cliniques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Épilepsie</strong> : pointes, pointes-ondes, polypointes. EEG intercritique (entre les crises) et percritique (pendant). Stimulation lumineuse intermittente.</li><li><strong>Sommeil</strong> : polysomnographie (EEG + EOG + EMG). Stades : N1 (endormissement), N2 (fuseaux, complexes K), N3 (ondes delta lentes), REM (activité rapide, atonie musculaire, rêves).</li><li><strong>Mort encéphalique</strong> : 2 EEG plats de 30 min à 4h d'intervalle → confirmation du décès.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Potentiels évoqués</h4><p class="mb-3">Réponse cérébrale à une stimulation sensorielle. Visuels (PEV), auditifs (PEA), somesthésiques (PES). Permettent d'explorer les voies nerveuses. Latence augmentée = ralentissement de la conduction (SEP, compression médullaire).</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : L'EMG (électromyogramme) explore le nerf périphérique et le muscle. Vitesse de conduction nerveuse diminuée → démyélinisation. Amplitude diminuée → atteinte axonale. L'EEG a une excellente résolution temporelle (ms) mais une mauvaise résolution spatiale (vs IRM fonctionnelle).</p></div>` },
  { id: 'biophysique-laser', subject: 'biophysique', title: 'Laser médical', summary: 'Principe, types de lasers et applications thérapeutiques.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Laser médical</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">LASER = Light Amplification by Stimulated Emission of Radiation. <strong>Émission stimulée</strong> : un photon incident provoque l'émission d'un photon identique (même longueur d'onde, phase, direction). Inversion de population nécessaire (pompage). Propriétés : monochromatique, cohérent, directif, intense.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Types de lasers médicaux</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>CO2</strong> (10 600 nm, IR) : absorption par l'eau → effet thermique de coupe/vaporisation. Chirurgie, dermatologie.</li><li><strong>Nd:YAG</strong> (1 064 nm, IR proche) : pénétration profonde. Photocoagulation, endoscopie, urologie.</li><li><strong>Argon</strong> (488-514 nm, visible bleu-vert) : absorbé par l'hémoglobine et la mélanine. Ophtalmologie (rétine), dermatologie (angiomes).</li><li><strong>Excimer</strong> (193 nm, UV) : photoablation sans effet thermique. Chirurgie réfractive (LASIK) → remodelage de la cornée.</li><li><strong>Diode</strong> : compact, versatile. Épilation, phlébologie.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Effets tissulaires</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Photochimique</strong> : basse puissance, photodynamique (photosensibilisant + lumière → ROS → destruction tumorale).</li><li><strong>Thermique</strong> : coagulation (60-100°C), vaporisation (&gt;100°C), carbonisation (&gt;300°C).</li><li><strong>Photoablatif</strong> : rupture des liaisons moléculaires sans chaleur (UV, excimer).</li><li><strong>Photomécanique</strong> : impulsions très courtes → onde de choc. Lithotripsie laser.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : La longueur d'onde détermine l'absorption tissulaire et donc l'effet. La PDT (photothérapie dynamique) est utilisée en cancérologie (tumeurs superficielles). Les classes de laser (1 à 4) définissent le niveau de dangerosité.</p></div>` },
  { id: 'biophysique-dosimetrie-radiobio', subject: 'biophysique', title: 'Dosimétrie et radiobiologie', summary: 'Effets biologiques, dose-réponse, radiosensibilité et radioprotection.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Dosimétrie et radiobiologie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Grandeurs dosimétriques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Dose absorbée D</strong> (Gray, Gy) : énergie déposée par unité de masse. 1 Gy = 1 J/kg.</li><li><strong>Dose équivalente H</strong> (Sievert, Sv) : H = D × wR. wR = facteur de pondération du rayonnement (1 pour X/gamma/beta, 20 pour alpha, 5-20 pour neutrons).</li><li><strong>Dose efficace E</strong> (Sv) : E = somme(wT × HT). wT = facteur de pondération tissulaire (gonades 0.08, moelle 0.12, poumon 0.12, sein 0.12). Tient compte de la radiosensibilité des organes.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Effets biologiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Effets déterministes</strong> (obligatoires) : seuil de dose, gravité proportionnelle à la dose, précoces. Érythème (3-5 Gy), radiodermite, aplasie médullaire (1-2 Gy), syndrome d'irradiation aiguë. Réversibles si dose modérée.</li><li><strong>Effets stochastiques</strong> (aléatoires) : pas de seuil, probabilité proportionnelle à la dose (pas la gravité), tardifs. Cancers radio-induits, effets héréditaires. Relation linéaire sans seuil (LNT) : modèle de précaution.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Radiosensibilité</h4><p class="mb-3">Loi de <strong>Bergonié et Tribondeau</strong> : les cellules sont d'autant plus radiosensibles qu'elles se divisent rapidement, ont un long avenir de division et sont peu différenciées. Les plus sensibles : lymphocytes, cellules souches hématopoïétiques, spermatogonies, cellules de la crypte intestinale. Les plus résistantes : neurones, cellules musculaires.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Principes de radioprotection</h4><p class="mb-3"><strong>Justification</strong> (bénéfice > risque), <strong>Optimisation</strong> (ALARA : As Low As Reasonably Achievable), <strong>Limitation</strong> des doses (public : 1 mSv/an, travailleurs : 20 mSv/an). Moyens : temps (réduire), distance (augmenter, loi en 1/d²), écran (plomb, béton).</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : L'irradiation naturelle moyenne en France est ~2.5 mSv/an (radon, cosmique, tellurique, alimentation). Un scanner thoracique ~7 mSv, une radio pulmonaire ~0.02 mSv. La dose létale 50 (DL50) en irradiation corporelle totale est de ~4-5 Gy sans traitement.</p></div>` },
  { id: 'biophysique-fluides', subject: 'biophysique', title: 'Mécanique des fluides biologiques', summary: 'Viscosité, loi de Poiseuille, hémodynamique et pression artérielle.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Mécanique des fluides</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Propriétés des fluides</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Viscosité (eta)</strong> : résistance à l'écoulement. Unité : Pa.s. Eau ~10⁻³ Pa.s, sang ~3-4 × 10⁻³ Pa.s. Dépend de l'hématocrite, T°, protéines plasmatiques.</li><li><strong>Fluide newtonien</strong> : viscosité constante (indépendante du cisaillement). Eau, plasma.</li><li><strong>Fluide non newtonien</strong> : viscosité variable. Le sang est pseudoplastique (viscosité diminue avec le cisaillement → rouleaux de GR se défont).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi de Poiseuille</h4><p class="mb-3">Q = pi × r⁴ × DeltaP / (8 × eta × L). Le débit est proportionnel à la <strong>puissance 4 du rayon</strong> → une vasoconstriction de 50% réduit le débit de 94%. Résistance R = 8etaL/(pi×r⁴). Delta P = R × Q (analogue de la loi d'Ohm).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Hémodynamique</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Débit cardiaque Q = FC × VES ≈ 5 L/min au repos. PA moyenne ≈ PAD + 1/3(PAS - PAD).</li><li><strong>Nombre de Reynolds</strong> : Re = rho × v × d / eta. Re &lt;2000 → écoulement laminaire. Re &gt;3000 → turbulent (bruit = souffle). Turbulence aux bifurcations et sténoses.</li><li>La vitesse diminue et la surface totale augmente dans les capillaires (des artères aux capillaires : surface ×1000) → échanges optimaux.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Pression artérielle</h4><p class="mb-3">PA = DC × RPT (résistance périphérique totale). Régulation : barorécepteurs (court terme), SRAA et ADH (long terme). La compliance artérielle diminue avec l'âge → HTA systolique isolée du sujet âgé.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : L'athérosclérose réduit r → augmentation majeure de la résistance (r⁴). Une sténose de 50% du diamètre = 94% de réduction du débit si pas de compensation. La polyglobulie augmente la viscosité → risque de thrombose.</p></div>` },
  { id: 'biophysique-bioenergetique', subject: 'biophysique', title: 'Bioénergétique et calorimétrie', summary: 'Métabolisme basal, thermogenèse, calorimétrie directe et indirecte.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Bioénergétique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Métabolisme basal (MB)</h4><p class="mb-3">Dépense énergétique minimale pour maintenir les fonctions vitales au repos, à jeun, en thermoneutralité. ~1 kcal/kg/h chez l'homme adulte. Dépend de la masse maigre, l'âge, le sexe, la fonction thyroïdienne. Formule de Harris-Benedict. MB représente 60-70% de la dépense énergétique totale.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Dépense énergétique totale</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>MB</strong> (60-70%) : fonctions vitales.</li><li><strong>Thermogenèse alimentaire</strong> (10%) : énergie pour digérer/absorber/métaboliser les nutriments (effet thermique des aliments). Protéines &gt; glucides &gt; lipides.</li><li><strong>Activité physique</strong> (20-30%) : seule composante volontairement modifiable.</li><li><strong>NAP</strong> (Niveau d'Activité Physique) = DET/MB. Sédentaire ~1.4, actif ~1.7-2.0.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Calorimétrie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Directe</strong> : mesure la chaleur produite (chambre calorimétrique). Précise mais lourde.</li><li><strong>Indirecte</strong> : mesure VO2 et VCO2. <strong>QR</strong> (quotient respiratoire) = VCO2/VO2. Glucides : QR = 1.0, lipides : QR = 0.7, protéines : QR = 0.8, mixte : QR ≈ 0.82. Formule de Weir : DER (kcal/j) = (3.94 × VO2 + 1.11 × VCO2) × 1440.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Thermorégulation</h4><p class="mb-3">Thermostat hypothalamique (set point ~37°C). Production de chaleur : frisson (muscle), thermogenèse sans frisson (tissu adipeux brun, UCP1). Perte de chaleur : vasodilatation cutanée, sudation, convection, radiation. La fièvre = élévation du set point (pyrogènes → PGE2 hypothalamique).</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : 1 g de glucides = 4 kcal, 1 g de lipides = 9 kcal, 1 g de protéines = 4 kcal, 1 g d'alcool = 7 kcal. Un QR > 1 indique une lipogenèse de novo (conversion glucides → lipides). L'hypothermie maligne peranesthésique est due à une mutation du récepteur de la ryanodine (RyR1).</p></div>` },
  { id: 'biophysique-separation', subject: 'biophysique', title: 'Techniques de séparation', summary: 'Chromatographie, électrophorèse, centrifugation et ultracentrifugation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Techniques de séparation</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Centrifugation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Force centrifuge relative (g) = omega² × r / g. Accélère la sédimentation.</li><li><strong>Centrifugation différentielle</strong> : vitesses croissantes → sépare noyaux (600g), mitochondries (10 000g), microsomes/RE (100 000g), ribosomes (300 000g).</li><li><strong>Ultracentrifugation en gradient de densité</strong> : saccharose (vitesse de sédimentation, coefficient S en Svedberg) ou CsCl (densité d'équilibre). Ribosome 70S (procaryote) = 50S + 30S, 80S (eucaryote) = 60S + 40S.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Électrophorèse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Migration de molécules chargées dans un champ électrique. Vitesse = charge × E / friction.</li><li><strong>Gel d'agarose</strong> : ADN (taille, charge proportionnelle → séparation par taille). Coloration BET ou SYBR. Marqueur de taille.</li><li><strong>SDS-PAGE</strong> : protéines (séparation par masse). <strong>Isoélectrofocalisation</strong> : séparation par pHi.</li><li><strong>Électrophorèse capillaire</strong> : haute résolution, petits volumes. Diagnostic : hémoglobinopathies.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Chromatographie</h4><p class="mb-3">Séparation basée sur la distribution entre une phase mobile et une phase stationnaire. Types : exclusion de taille, échange d'ions, affinité, phase inverse (HPLC). Paramètres : temps de rétention, résolution, facteur de capacité.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Dialyse et ultrafiltration</h4><p class="mb-3"><strong>Dialyse</strong> : membrane semi-perméable, passage des petites molécules par diffusion (dessalage, changement de tampon). <strong>Ultrafiltration</strong> : membrane sous pression → retient les macromolécules (concentration). <strong>Hémodialyse</strong> (rein artificiel) : élimine urée, créatinine, K⁺ excédentaire du sang.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Les unités Svedberg ne sont pas additives car elles dépendent de la forme ET de la masse (50S + 30S = 70S, pas 80S). L'électrophorèse des protéines sériques est un examen de routine : pic monoclonal en gamma → suspicion de myélome → immunofixation pour typer.</p></div>` },
  { id: 'biophysique-echo-avancee', subject: 'biophysique', title: 'Physique de l\'échographie avancée', summary: 'Modes A/B/M/TM, Doppler couleur, pulsé et continu.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Échographie avancée</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Rappel physique</h4><p class="mb-3">Ultrasons (2-15 MHz) émis par un transducteur piézoélectrique. Se propagent dans les tissus, sont réfléchis aux interfaces d'impédance acoustique différente (Z = rho × c). Fréquence haute → meilleure résolution mais moindre pénétration. Fréquence basse → pénétration profonde.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Modes d'imagerie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Mode A</strong> (amplitude) : signal 1D. Pics d'amplitude selon la profondeur. Utilisé en ophtalmologie (biométrie oculaire).</li><li><strong>Mode B</strong> (brightness, 2D) : image en coupe. Chaque écho = point lumineux (brillance proportionnelle à l'amplitude). Mode le plus utilisé (imagerie anatomique temps réel).</li><li><strong>Mode M</strong> (mouvement, TM) : ligne de tir unique vs temps. Étudie les structures mobiles : valves cardiaques, paroi ventriculaire (échocardiographie).</li><li><strong>Mode 3D/4D</strong> : reconstruction volumétrique. 4D = 3D en temps réel. Obstétrique, cardiologie.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Effet Doppler</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Delta f = 2 × f0 × v × cos(theta) / c. Mesure la vitesse du sang.</li><li><strong>Doppler continu</strong> : émission/réception continues. Mesure les hautes vitesses (pas d'aliasing) mais pas de localisation en profondeur.</li><li><strong>Doppler pulsé</strong> : émission par salves → localisation précise (volume d'échantillonnage). Limite : vitesse maximale mesurable (critère de Nyquist : fmax = PRF/2). Si dépassée → aliasing.</li><li><strong>Doppler couleur</strong> : cartographie 2D des flux. Rouge = vers la sonde, bleu = s'éloigne (convention). Mosaïque de couleurs = flux turbulent (sténose, insuffisance valvulaire).</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Le gel d'échographie élimine l'air entre la sonde et la peau (l'interface air-tissu réfléchit quasi 100% des US). Les calculs et l'os apparaissent hyperéchogènes avec cône d'ombre postérieur. Les liquides (urine, bile, kyste) sont anéchogènes avec renforcement postérieur.</p></div>` },
  { id: 'biophysique-interactions-rayonnements', subject: 'biophysique', title: 'Interactions rayonnements-matière', summary: 'Effet photoélectrique, Compton, création de paires et atténuation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Interactions photons-matière</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Effet photoélectrique</h4><p class="mb-3">Le photon incident est <strong>totalement absorbé</strong> par un atome → éjection d'un électron de couche interne (photoélectron). E cinétique du photoélectron = E photon - E liaison. Prédomine pour les <strong>basses énergies</strong> et les <strong>Z élevés</strong> (proportionnel à Z⁴/E³). Responsable du contraste en radiologie conventionnelle (os Z=20 vs tissu mou Z=7).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Effet Compton</h4><p class="mb-3">Le photon interagit avec un électron des couches externes → <strong>diffusion</strong> du photon (énergie réduite, direction changée) + éjection de l'électron (électron Compton). Prédomine pour les <strong>énergies intermédiaires</strong> (100 keV - 10 MeV). Indépendant de Z. Principal mode d'interaction en radiothérapie. Source de bruit et de dose diffusée en imagerie.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Création de paires</h4><p class="mb-3">Photon d'énergie > <strong>1.022 MeV</strong> → se matérialise en une paire électron-positon (e⁻/e⁺) au voisinage d'un noyau. Le positon s'annihile avec un e⁻ → 2 photons de 511 keV à 180° (base de la TEP). Prédomine aux très hautes énergies et Z élevés.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Atténuation d'un faisceau</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Loi d'atténuation</strong> : I = I₀ × e^(-mu × x). mu = coefficient d'atténuation linéaire (cm⁻¹). Dépend de l'énergie et du matériau.</li><li><strong>CDA</strong> (couche de demi-atténuation) = ln2/mu. Épaisseur qui réduit l'intensité de moitié.</li><li>mu/rho = coefficient d'atténuation massique (indépendant de l'état physique).</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : En radiologie diagnostique (30-150 keV) : effet photoélectrique prédomine (contraste). En radiothérapie (MeV) : effet Compton prédomine (dose en profondeur). Les produits de contraste iodés (Z=53) et barytés (Z=56) augmentent l'absorption photoélectrique.</p></div>` },
  { id: 'biophysique-detecteurs', subject: 'biophysique', title: 'Détecteurs de rayonnements', summary: 'Compteur Geiger, chambre d\'ionisation, scintillateur et dosimètre.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Détecteurs de rayonnements</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe général</h4><p class="mb-3">Les détecteurs convertissent l'énergie du rayonnement en un signal mesurable (courant électrique, lumière). Deux modes : comptage (nombre d'événements) ou mesure de dose (énergie déposée).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Détecteurs à ionisation gazeuse</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Chambre d'ionisation</strong> : collecte les ions créés par le rayonnement dans un gaz. Signal proportionnel à la dose absorbée. Référence en dosimétrie clinique (radiothérapie). Faible sensibilité.</li><li><strong>Compteur proportionnel</strong> : tension plus élevée → amplification par avalanche. Discrimine l'énergie des particules.</li><li><strong>Compteur Geiger-Müller</strong> : haute tension → décharge totale pour chaque événement. Très sensible mais ne discrimine pas l'énergie. Utilisé en radioprotection (contamination de surface).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Détecteurs à scintillation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Le rayonnement excite un scintillateur → émission de photons lumineux → photomultiplicateur (PM) → signal électrique.</li><li><strong>NaI(Tl)</strong> : cristal inorganique. Utilisé en gamma-caméra (scintigraphie). Bonne efficacité de détection pour les gamma.</li><li><strong>BGO, LSO, LYSO</strong> : scintillateurs rapides pour la TEP (détection en coïncidence des photons de 511 keV).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Dosimètres personnels</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Film badge</strong> : noircissement proportionnel à la dose. Lecture différée. En voie de disparition.</li><li><strong>TLD</strong> (thermoluminescent) : cristal (LiF) stocke l'énergie → libérée sous forme de lumière par chauffage. Dosimètre passif de référence.</li><li><strong>OSL</strong> (luminescence stimulée optiquement) : similaire au TLD mais stimulation par lumière. Al2O3:C.</li><li><strong>Dosimètre électronique</strong> : lecture en temps réel. Alarme si débit de dose excessif. Utilisé en plus du dosimètre passif.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : Le port du dosimètre est obligatoire pour tous les travailleurs exposés. Dosimètre passif (TLD/OSL) = dose sur 1-3 mois. Dosimètre opérationnel (électronique) = surveillance en temps réel. La dosimétrie in vivo (diodes, MOSFET) vérifie la dose réellement reçue par le patient en radiothérapie.</p></div>` },
  { id: 'biophysique-irm-avancee', subject: 'biophysique', title: 'IRM avancée', summary: 'Séquences, pondérations, artéfacts et agents de contraste.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">IRM avancée</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Séquences principales</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Spin écho (SE)</strong> : impulsion 90° → 180° (refocalisation). Pondération T1 (TR court, TE court) ou T2 (TR long, TE long). Robuste mais lente.</li><li><strong>Écho de gradient (GRE)</strong> : impulsion &lt;90°, pas de 180° → plus rapide. Sensible aux inhomogénéités de champ (T2*). Base des séquences rapides.</li><li><strong>Inversion-récupération</strong> : 180° → TI → 90°. STIR (TI court → suppression graisse), FLAIR (TI long → suppression liquide, essentielle en neurologie pour les lésions périventriculaires).</li><li><strong>Diffusion (DWI)</strong> : sensible au mouvement brownien de l'eau. AVC aigu : restriction de diffusion (hypersignal DWI, hyposignal ADC) dans les premières minutes.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Pondérations et contraste</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>T1</strong> : graisse = blanc (hypersignal), eau = noir (hyposignal). Anatomie, post-gadolinium.</li><li><strong>T2</strong> : eau = blanc, graisse = gris. Pathologie (œdème, inflammation, tumeur).</li><li><strong>Densité de protons</strong> : TR long, TE court. Bonne visualisation des structures articulaires.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Artéfacts</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Mouvement</strong> : flou, fantômes. Compensation : synchronisation ECG/respiratoire, séquences rapides.</li><li><strong>Susceptibilité magnétique</strong> : distorsion aux interfaces air-tissu ou près de matériel métallique. Effet blooming en T2*.</li><li><strong>Déplacement chimique</strong> : décalage graisse-eau en fréquence → bandes noires/blanches aux interfaces.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Agents de contraste</h4><p class="mb-3"><strong>Gadolinium</strong> : paramagnétique, raccourcit T1 → rehaussement en T1. Utilisé pour tumeurs, inflammation, angiographie. CI : insuffisance rénale sévère (risque de fibrose systémique néphrogénique). Chélaté pour réduire la toxicité.</p><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : L'IRM de diffusion est l'examen le plus précoce pour détecter un AVC ischémique (hypersignal dès 30 min vs scanner normal pendant les premières heures). Le mismatch diffusion-perfusion estime la pénombre ischémique (tissu récupérable). CI absolue de l'IRM : pacemaker non compatible, implants ferromagnétiques, corps étrangers métalliques intraoculaires.</p></div>` },
  { id: 'biophysique-radio-interventionnelle', subject: 'biophysique', title: 'Radiologie interventionnelle', summary: 'Angiographie, embolisation, pose de stent et guidage par imagerie.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Radiologie interventionnelle</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Principe</h4><p class="mb-3">Actes diagnostiques et thérapeutiques <strong>mini-invasifs guidés par l'imagerie</strong> (fluoroscopie RX, échographie, scanner, IRM). Alternative à la chirurgie ouverte pour de nombreuses indications. Avantages : moins invasif, anesthésie locale, récupération rapide.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Techniques vasculaires</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Angiographie</strong> : cathétérisme artériel (Seldinger : ponction → guide → cathéter) + injection de produit de contraste iodé → visualisation des vaisseaux. Angioplastie : dilatation par ballonnet d'une sténose.</li><li><strong>Pose de stent</strong> : endoprothèse métallique déployée dans un vaisseau pour maintenir la lumière ouverte. Nu ou actif (drug-eluting : libère un médicament anti-resténose).</li><li><strong>Embolisation</strong> : occlusion volontaire d'un vaisseau. Agents : coils (spirales métalliques), particules (PVA), gélatine, colle. Indications : hémorragies, malformations artério-veineuses, fibromes utérins, chimio-embolisation hépatique (TACE).</li><li><strong>TIPS</strong> (Transjugular Intrahepatic Portosystemic Shunt) : shunt porto-cave par voie transjugulaire. Hypertension portale réfractaire.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Techniques non vasculaires</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Biopsie guidée</strong> : prélèvement tissulaire sous guidage écho ou scanner. Foie, rein, poumon, os.</li><li><strong>Drainage</strong> : collections, abcès, voies biliaires obstruées (drainage biliaire percutané).</li><li><strong>Thermoablation</strong> : destruction tumorale par radiofréquence (RF), micro-ondes ou cryothérapie. Tumeurs hépatiques, rénales, pulmonaires petites.</li><li><strong>Vertébroplastie/Kyphoplastie</strong> : injection de ciment dans un corps vertébral fracturé (tassement ostéoporotique).</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : La thrombectomie mécanique est le traitement de référence de l'AVC ischémique avec occlusion d'un gros vaisseau (dans les 6-24h selon les critères). L'embolisation des artères utérines est une alternative à l'hystérectomie pour les fibromes symptomatiques.</p></div>` },
  { id: 'biophysique-electricite-cardiaque', subject: 'biophysique', title: 'Électricité cardiaque', summary: 'Dipôle cardiaque, vecteur instantané et triangle d\'Einthoven.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Bases physiques de l'électricité cardiaque</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le cœur comme dipôle</h4><p class="mb-3">La dépolarisation du myocarde crée un <strong>dipôle électrique</strong> (front de dépolarisation = charge + en avant, - en arrière). Le <strong>vecteur instantané</strong> représente la direction et l'amplitude du dipôle à chaque instant. L'ECG enregistre la projection de ce vecteur sur les axes des dérivations.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Triangle d'Einthoven</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Triangle équilatéral formé par les 3 dérivations bipolaires (DI, DII, DIII). Le cœur est au centre.</li><li><strong>DI</strong> : bras droit → bras gauche (0°). <strong>DII</strong> : bras droit → jambe gauche (+60°). <strong>DIII</strong> : bras gauche → jambe gauche (+120°).</li><li><strong>Loi d'Einthoven</strong> : DII = DI + DIII (somme vectorielle).</li><li>Dérivations unipolaires augmentées : aVR (-150°), aVL (-30°), aVF (+90°).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Axe électrique du cœur</h4><p class="mb-3">Direction moyenne du vecteur QRS. Normal : <strong>0° à +90°</strong> (pointe en bas et à gauche). Déviation axiale gauche (&lt;0°) : HVG, hémibloc antérieur gauche. Déviation droite (&gt;+90°) : HVD, hémibloc postérieur gauche, cœur vertical.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Potentiels d'action cardiaques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Cellules à réponse rapide</strong> (contractiles, His-Purkinje) : phase 0 (Na⁺ rapide), phase 1 (K⁺), phase 2 (plateau, Ca²⁺ L entrant = K⁺ sortant), phase 3 (repolarisation K⁺), phase 4 (repos -90 mV).</li><li><strong>Cellules à réponse lente</strong> (nœud sinusal, nœud AV) : phase 0 (Ca²⁺ lente), pas de phase 1-2 nettes, phase 4 = <strong>dépolarisation diastolique spontanée</strong> (If = courant funny, Na⁺/K⁺). Pacemaker naturel.</li><li>Période réfractaire absolue (PRA) → insensibilité aux stimuli → protection contre la fibrillation.</li></ul><div class="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-amber-800">Point clé concours : L'ivabradine inhibe le courant If → ralentit le nœud sinusal (bradycardisant pur). Les anti-arythmiques de classe I bloquent Na⁺ (phase 0), classe III allongent la repolarisation (K⁺), classe IV bloquent Ca²⁺. L'amiodarone a des propriétés des 4 classes.</p></div>` },

  // ===== SSH/ÉTHIQUE — EXTENSION PROGRAMME COMPLET =====
  { id: 'ssh-economie-sante', subject: 'ssh', title: 'Économie de la santé', summary: 'Offre, demande, régulation, coût-efficacité et QALY.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Économie de la santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Particularités du marché de la santé</h4><p class="mb-3">Le marché de la santé ne fonctionne pas comme un marché classique : <strong>asymétrie d'information</strong> (le médecin sait, le patient subit), demande induite par l'offre, incertitude (on ne sait pas quand on sera malade), <strong>bien tutélaire</strong> (l'État garantit l'accès), aléa moral (surconsommation car assuré).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Évaluations médico-économiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Coût-efficacité</strong> (CEA) : ratio ICER = Delta Coût / Delta Efficacité. Efficacité en unités naturelles (années de vie gagnées, événements évités). Ex : coût par année de vie gagnée.</li><li><strong>Coût-utilité</strong> (CUA) : efficacité en <strong>QALY</strong> (Quality-Adjusted Life Year). 1 QALY = 1 an en parfaite santé. Intègre la qualité de vie. Seuil d'acceptabilité : ~50 000-100 000 euros/QALY (variable selon les pays).</li><li><strong>Coût-bénéfice</strong> (CBA) : tout est monétisé. Bénéfice net si bénéfices > coûts. Éthiquement controversé (monétiser la santé).</li><li><strong>Minimisation des coûts</strong> : quand l'efficacité est identique → on choisit le moins cher.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Financement et régulation</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>ONDAM</strong> (Objectif National des Dépenses d'Assurance Maladie) : voté chaque année en PLFSS. Taux de progression contraint.</li><li><strong>HAS</strong> : évalue le SMR (Service Médical Rendu → remboursement) et l'ASMR (Amélioration du SMR → prix) des médicaments.</li><li><strong>CEPS</strong> (Comité Économique des Produits de Santé) : fixe les prix des médicaments en négociation avec les industriels.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Le paradoxe de l'assurance maladie : elle est nécessaire (protection contre le risque) mais génère un aléa moral (surconsommation). Le ticket modérateur, les franchises et la participation forfaitaire visent à responsabiliser le patient.</p></div>` },
  { id: 'ssh-fin-de-vie', subject: 'ssh', title: 'Fin de vie et soins palliatifs', summary: 'Loi Claeys-Leonetti, directives anticipées, sédation et euthanasie.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Fin de vie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Cadre législatif</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Loi Leonetti (2005)</strong> : interdit l'obstination déraisonnable. Droit de refuser un traitement. Soins palliatifs. Procédure collégiale pour les patients inconscients. Double effet (soulager même si risque d'abréger la vie).</li><li><strong>Loi Claeys-Leonetti (2016)</strong> : <strong>sédation profonde et continue</strong> jusqu'au décès (à la demande du patient en phase terminale, souffrance réfractaire). Directives anticipées <strong>contraignantes</strong> (sauf urgence vitale ou inadaptées). Personne de confiance renforcée.</li><li>L'<strong>euthanasie active</strong> reste interdite en France (acte délibéré pour provoquer la mort). Le suicide assisté aussi. Débat sociétal en cours.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Soins palliatifs</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Définition OMS : soins actifs dans une approche globale (physique, psychologique, sociale, spirituelle) de la personne atteinte d'une maladie grave, évolutive ou terminale. Objectif : qualité de vie, dignité.</li><li>Structures : <strong>USP</strong> (unités de soins palliatifs), EMSP (équipes mobiles), lits identifiés en service, HAD.</li><li>Prise en charge : douleur (paliers OMS, morphine), symptômes (dyspnée, nausées, anxiété), accompagnement psychologique, soutien de l'entourage, deuil.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Directives anticipées</h4><p class="mb-3">Document écrit, daté et signé. Exprime les volontés de la personne concernant sa fin de vie (traitements, réanimation, ventilation, nutrition artificielle). Révisables à tout moment. <strong>S'imposent au médecin</strong> (sauf urgence vitale le temps d'évaluer, ou jugées manifestement inappropriées après procédure collégiale).</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Distinction clé : laisser mourir (arrêt des traitements, légal) vs faire mourir (euthanasie, illégal en France). La sédation profonde et continue n'est pas une euthanasie : elle vise à soulager la souffrance, pas à provoquer la mort (le patient meurt de sa maladie).</p></div>` },
  { id: 'ssh-deontologie', subject: 'ssh', title: 'Déontologie médicale', summary: 'Code de déontologie, secret professionnel et responsabilité médicale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Déontologie médicale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Code de déontologie</h4><p class="mb-3">Ensemble de règles professionnelles encadrant l'exercice médical. Intégré au Code de la santé publique (articles R.4127-1 à R.4127-112). Élaboré par le <strong>Conseil National de l'Ordre des Médecins (CNOM)</strong>. Valeur réglementaire (décret). L'Ordre peut sanctionner les manquements (avertissement, blâme, interdiction temporaire ou définitive d'exercer).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Principes fondamentaux</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Respect de la vie et de la dignité</strong> : art. 2. Le médecin exerce dans le respect de la vie humaine, de la personne et de sa dignité.</li><li><strong>Non-discrimination</strong> : art. 7. Soigner sans discrimination aucune.</li><li><strong>Indépendance professionnelle</strong> : art. 5. Le médecin ne peut aliéner son indépendance sous quelque forme que ce soit.</li><li><strong>Compétence</strong> : art. 11. Formation continue, entretien des connaissances.</li><li><strong>Confraternité</strong> : art. 56. Respect entre confrères, pas de dénigrement.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Secret professionnel</h4><p class="mb-3">Art. 4 du code de déontologie + art. 226-13 du code pénal. <strong>Général et absolu</strong>. Couvre tout ce que le médecin a vu, entendu, compris, constaté dans l'exercice. Dérogations légales : déclaration obligatoire (maladies à DO), signalement de maltraitance (mineurs, personnes vulnérables), certificats obligatoires. Secret partagé entre professionnels de santé de la même équipe (avec le consentement du patient).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Responsabilité médicale</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Disciplinaire</strong> (Ordre) : manquement au code de déontologie.</li><li><strong>Civile</strong> (tribunal civil) : faute + dommage + lien de causalité → indemnisation. Obligation de moyens (pas de résultat).</li><li><strong>Pénale</strong> (tribunal correctionnel) : homicide involontaire, blessures involontaires, non-assistance à personne en danger.</li><li><strong>Administrative</strong> (tribunal administratif) : pour les praticiens hospitaliers publics.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La loi Kouchner (2002) a inversé la charge de la preuve en matière d'information : c'est au médecin de prouver qu'il a informé le patient (et non au patient de prouver qu'il n'a pas été informé). L'aléa thérapeutique est indemnisé par l'ONIAM (Office National d'Indemnisation des Accidents Médicaux).</p></div>` },
  { id: 'ssh-inegalites', subject: 'ssh', title: 'Inégalités sociales de santé', summary: 'Gradient social, déterminants sociaux, accès aux soins et précarité.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Inégalités sociales de santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le gradient social de santé</h4><p class="mb-3">Les inégalités de santé suivent un <strong>gradient continu</strong> : plus on descend dans l'échelle sociale, plus les indicateurs de santé se dégradent. Ce n'est pas qu'une question de pauvreté : chaque catégorie socioprofessionnelle a une espérance de vie inférieure à celle immédiatement au-dessus. En France : <strong>13 ans d'écart d'espérance de vie</strong> entre les 5% les plus aisés et les 5% les plus pauvres (hommes).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Déterminants sociaux (modèle de Dahlgren & Whitehead)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Facteurs individuels</strong> : âge, sexe, patrimoine génétique.</li><li><strong>Comportements</strong> : tabac, alcool, alimentation, activité physique. Socialement déterminés (marketing, prix, normes sociales).</li><li><strong>Réseaux sociaux</strong> : isolement social = facteur de risque de mortalité (comparable au tabac).</li><li><strong>Conditions de vie et de travail</strong> : logement insalubre, emploi précaire, exposition professionnelle, accès aux soins.</li><li><strong>Conditions socio-économiques, culturelles et environnementales</strong> : éducation, revenus, politiques sociales, environnement.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Mécanismes</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Exposition différentielle</strong> : les plus défavorisés sont plus exposés aux facteurs de risque.</li><li><strong>Vulnérabilité différentielle</strong> : à exposition égale, l'impact est plus grand (moins de ressources pour faire face).</li><li><strong>Accès différentiel aux soins</strong> : renoncement aux soins, déserts médicaux, reste à charge, littératie en santé.</li><li><strong>Conséquences différentielles</strong> : une même maladie a un pronostic plus sombre en situation de précarité.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Politiques de réduction</h4><p class="mb-3">CSS (Complémentaire Santé Solidaire), PASS (Permanences d'Accès aux Soins de Santé), AME (Aide Médicale d'État), centres de santé communautaire, universalisme proportionné (actions universelles mais intensité proportionnelle aux besoins).</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Les ISS sont évitables et injustes (≠ inégalités biologiques). Le rapport Black (1980, UK) a été le premier à documenter le gradient social de santé. Marmot (études Whitehall) a montré que le gradient existe même parmi les fonctionnaires (pas que pauvreté vs richesse).</p></div>` },
  { id: 'ssh-anthropologie', subject: 'ssh', title: 'Anthropologie de la maladie', summary: 'Représentations, illness/disease/sickness et pluralisme médical.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Anthropologie de la maladie</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Trois dimensions de la maladie (Kleinman)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Disease</strong> : la maladie biomédicale, le dysfonctionnement objectif diagnostiqué par le médecin (perspective du soignant).</li><li><strong>Illness</strong> : l'expérience subjective du malade, la maladie vécue (souffrance, sens donné, impact sur la vie quotidienne).</li><li><strong>Sickness</strong> : la dimension sociale de la maladie (rôle de malade, reconnaissance par la société, arrêt de travail, stigmatisation).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Modèles explicatifs</h4><p class="mb-3"><strong>Modèle explicatif du patient</strong> (Explanatory Model, Kleinman) : ce que le patient pense de l'étiologie, de l'évolution et du traitement de sa maladie. Peut différer radicalement du modèle biomédical. Le médecin doit explorer le modèle du patient pour adapter la prise en charge.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Pluralisme médical</h4><p class="mb-3">Coexistence de plusieurs systèmes de soins : biomédecine, médecines traditionnelles (chinoise, ayurvédique), médecines alternatives/complémentaires, tradipraticiens, guérisseurs. L'itinéraire thérapeutique du patient est souvent pluriel (consultation biomédicale + tradipraticien + automédication).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Concepts clés</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Rôle de malade</strong> (Parsons) : le malade est exempté de ses obligations sociales mais doit chercher à guérir et coopérer avec le médecin. Modèle critiqué (passivité du patient, maladies chroniques).</li><li><strong>Stigmate</strong> (Goffman) : attribut disqualifiant. Stigmatisation des malades (VIH, psychiatrie, handicap) → renoncement aux soins.</li><li><strong>Médicalisation</strong> : processus par lequel des problèmes non médicaux (tristesse, timidité, vieillissement) sont redéfinis comme des pathologies. Expansion de l'autorité médicale.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La compétence culturelle en médecine = capacité à adapter sa pratique à la diversité culturelle des patients. L'ethnocentrisme médical = juger les pratiques de santé d'autres cultures selon les critères de la biomédecine occidentale.</p></div>` },
  { id: 'ssh-esante', subject: 'ssh', title: 'E-santé et numérique', summary: 'Télémédecine, DMP, IA en santé et données massives.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">E-santé et numérique</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Télémédecine</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Téléconsultation</strong> : consultation à distance (vidéo). Remboursée depuis 2018. Conditions : patient connu, parcours de soins respecté (sauf exceptions).</li><li><strong>Téléexpertise</strong> : un médecin sollicite l'avis d'un spécialiste à distance (sans le patient).</li><li><strong>Télésurveillance</strong> : suivi à distance de paramètres (glycémie, pression artérielle, poids). Dispositifs connectés → alertes automatiques.</li><li><strong>Téléassistance</strong> : un médecin assiste un autre professionnel à distance pour un acte.</li><li><strong>Régulation</strong> : centre 15 (SAMU) = télémédecine historique.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Mon Espace Santé (DMP)</h4><p class="mb-3">Carnet de santé numérique. Contient les comptes rendus, ordonnances, résultats de biologie, imagerie, carnet de vaccination. Accessible au patient et aux professionnels de santé autorisés. Objectif : continuité et coordination des soins.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Intelligence artificielle en santé</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Aide au diagnostic</strong> : deep learning pour l'imagerie (détection de rétinopathie diabétique, cancers cutanés, nodules pulmonaires). Performances parfois supérieures au spécialiste sur des tâches ciblées.</li><li><strong>Aide à la décision</strong> : algorithmes de prédiction (risque cardiovasculaire, score de sepsis, détection de détérioration clinique).</li><li><strong>Découverte de médicaments</strong> : prédiction de cibles, screening virtuel.</li><li>Enjeux éthiques : <strong>biais algorithmiques</strong> (données d'entraînement non représentatives → inégalités amplifiées), explicabilité ("boîte noire"), responsabilité en cas d'erreur, consentement, impact sur la relation médecin-patient.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La e-santé peut réduire les inégalités (accès aux soins en zone rurale via télémédecine) ou les aggraver (fracture numérique des personnes âgées ou précaires). L'IA est un outil d'aide à la décision : le médecin reste responsable de la décision finale.</p></div>` },
  { id: 'ssh-droit-patients', subject: 'ssh', title: 'Droits des patients', summary: 'Loi Kouchner 2002, information, consentement et accès au dossier.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Droits des patients</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Loi Kouchner (4 mars 2002)</h4><p class="mb-3">Loi fondatrice des droits des patients en France. Consacre la <strong>démocratie sanitaire</strong> : le patient n'est plus passif mais acteur de sa santé. Droits individuels et collectifs.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Droit à l'information</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Information <strong>claire, loyale et appropriée</strong> sur l'état de santé, les traitements proposés, les alternatives, les risques et les conséquences du refus.</li><li>La charge de la preuve de l'information incombe au <strong>médecin</strong> (pas au patient).</li><li>Exception : urgence, impossibilité d'informer, refus du patient d'être informé (droit de ne pas savoir).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Consentement</h4><p class="mb-3"><strong>Consentement libre et éclairé</strong> : préalable à tout acte médical. Peut être retiré à tout moment. Le patient peut refuser un traitement, même vital (le médecin doit l'informer des conséquences et respecter sa volonté). Mineurs : consentement des titulaires de l'autorité parentale + recherche de l'avis du mineur selon sa maturité.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Personne de confiance</h4><p class="mb-3">Désignée par écrit par le patient. Rôle : accompagnement, aide à la compréhension, consultation par l'équipe si le patient ne peut exprimer sa volonté. Son témoignage prévaut sur celui de la famille.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Accès au dossier médical</h4><p class="mb-3">Droit d'accès direct (depuis 2002). Délai : 8 jours (ou 2 mois si dossier &gt; 5 ans). Possible par l'intermédiaire d'un médecin. Ayants droit : accès limité (cause du décès, défense de la mémoire du défunt, droits).</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Avant la loi Kouchner, le médecin avait un "privilège thérapeutique" (droit de ne pas tout dire). Depuis 2002, le principe est l'information complète. Les représentants des usagers siègent dans les instances hospitalières (commission des usagers, conseil de surveillance).</p></div>` },
  { id: 'ssh-epistemologie', subject: 'ssh', title: 'Épistémologie médicale', summary: 'EBM, niveaux de preuve, paradigmes et limites de la science médicale.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Épistémologie médicale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">EBM (Evidence-Based Medicine)</h4><p class="mb-3">Médecine fondée sur les preuves (Sackett, 1996). Intégration de 3 composantes : <strong>meilleures preuves scientifiques</strong> + <strong>expertise clinique du médecin</strong> + <strong>préférences du patient</strong>. Ce n'est pas la dictature des essais randomisés : c'est un cadre de décision intégratif.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Niveaux de preuve (HAS)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Niveau 1</strong> (grade A) : essais randomisés de forte puissance, méta-analyses d'essais. Preuve établie.</li><li><strong>Niveau 2</strong> (grade B) : essais randomisés de faible puissance, études comparatives non randomisées bien menées. Présomption scientifique.</li><li><strong>Niveau 3</strong> (grade C) : études cas-témoins, études comparatives avec biais importants. Faible niveau de preuve.</li><li><strong>Niveau 4</strong> : études descriptives, séries de cas, avis d'experts. Très faible niveau de preuve.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Paradigmes (Kuhn)</h4><p class="mb-3">La science progresse par <strong>révolutions</strong> : science normale (résolution de puzzles dans le paradigme dominant) → accumulation d'anomalies → crise → changement de paradigme. En médecine : passage du modèle humoriste au modèle anatomoclinique (Morgagni), puis au modèle biologique (Pasteur, Virchow), puis au modèle biopsychosocial (Engel, 1977).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Limites et critiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Réductionnisme</strong> : le modèle biomédical réduit la maladie à une dysfonction biologique (ignore le psychologique et le social).</li><li><strong>Scientisme</strong> : croire que tout est mesurable et objectivable. La médecine est aussi un art (relation, jugement clinique).</li><li><strong>Biais de publication</strong> : les études négatives ne sont pas publiées → surestimation de l'efficacité des traitements.</li><li><strong>Conflits d'intérêts</strong> : financement industriel des essais → résultats biaisés. Nécessité de transparence (déclarations d'intérêts).</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Popper : une théorie scientifique doit être réfutable (falsifiable). L'EBM ne dit pas "faites ce que dit l'essai randomisé" mais "intégrez les meilleures preuves dans votre raisonnement clinique en tenant compte du patient".</p></div>` },
  { id: 'ssh-demographie', subject: 'ssh', title: 'Démographie et vieillissement', summary: 'Transition démographique, pyramide des âges et enjeux du vieillissement.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Démographie et vieillissement</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Transition démographique</h4><p class="mb-3">Passage d'un régime de forte natalité/mortalité à un régime de faible natalité/mortalité. 4 phases : (1) pré-transition (natalité et mortalité élevées → croissance lente), (2) début (mortalité baisse, natalité élevée → croissance rapide), (3) fin (natalité baisse aussi → ralentissement), (4) post-transition (natalité et mortalité basses → vieillissement).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Indicateurs démographiques</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Taux de natalité</strong> : naissances / population × 1000. France ~10-11 pour mille.</li><li><strong>Taux de fécondité</strong> : naissances / femmes en âge de procréer (15-49 ans). ISF (indice synthétique de fécondité) France ~1.8 enfants/femme (seuil de renouvellement : 2.1).</li><li><strong>Taux de mortalité</strong> : brut vs standardisé (ajusté sur l'âge pour comparer des populations).</li><li><strong>Espérance de vie</strong> à la naissance : France ~85 ans (F), ~79 ans (H). EVSI (espérance de vie sans incapacité) : ~65 ans.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Vieillissement de la population</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>En 2030 : ~20 millions de Français > 60 ans. Les 75+ sont le segment à croissance la plus rapide.</li><li><strong>Ratio de dépendance</strong> : (jeunes + vieux) / actifs. Augmente → pression sur les systèmes de retraite et de santé.</li><li><strong>Silver économie</strong> : marché des services et produits pour les personnes âgées.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Enjeux sanitaires</h4><p class="mb-3">Maladies chroniques (diabète, HTA, cancer), maladies neurodégénératives (Alzheimer, Parkinson), <strong>fragilité</strong> (Fried : perte de poids, fatigue, faiblesse, lenteur, sédentarité), polypathologie et polymédication, <strong>dépendance</strong> (GIR, APA), isolement social, maltraitance des personnes âgées.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La transition épidémiologique (Omran) accompagne la transition démographique : passage des maladies infectieuses (1re cause) aux maladies chroniques (cancer, cardiovasculaire). Le "papy-boom" = baby-boomers (1946-1964) qui arrivent à 65+ ans → pic de vieillissement.</p></div>` },
  { id: 'ssh-psychiatrie', subject: 'ssh', title: 'Psychiatrie et société', summary: 'Histoire de la folie, loi de 2011, soins sans consentement et stigmatisation.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Psychiatrie et société</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Histoire de la psychiatrie</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Antiquité/Moyen Âge</strong> : folie = possession démoniaque ou punition divine. Enfermement, exorcisme.</li><li><strong>Pinel (1793)</strong> : libère les aliénés de leurs chaînes à Bicêtre. Naissance de la psychiatrie comme discipline médicale. "Traitement moral".</li><li><strong>Loi de 1838</strong> : obligation pour chaque département d'avoir un asile. Placement volontaire ou d'office.</li><li><strong>Mouvement antipsychiatrique (1960-70)</strong> : Foucault ("Histoire de la folie"), Szasz, Basaglia. Critique de l'enfermement et du pouvoir psychiatrique.</li><li><strong>Sectorisation (1960)</strong> : organisation territoriale des soins psychiatriques. Développement de l'ambulatoire (CMP, CATTP, hôpital de jour).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Soins sans consentement (loi du 5 juillet 2011, modifiée 2013)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Conditions : troubles mentaux + nécessité de soins immédiats + impossibilité de consentir.</li><li><strong>SDRE</strong> (Soins à la Demande d'un Représentant de l'État) : danger pour l'ordre public. Arrêté préfectoral. 2 certificats médicaux.</li><li><strong>SDT</strong> (Soins à la Demande d'un Tiers) : demande d'un proche + 2 certificats de médecins différents. Péril imminent : 1 seul certificat, pas de tiers.</li><li><strong>Contrôle du JLD</strong> (Juge des Libertés et de la Détention) : obligatoire avant 12 jours puis tous les 6 mois. Garantie des libertés individuelles.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Stigmatisation et discrimination</h4><p class="mb-3">Les troubles psychiatriques sont parmi les plus stigmatisés. Conséquences : retard de diagnostic, non-recours aux soins, discrimination à l'emploi/logement, rejet social, autoStigmatisation (intériorisation). Campagnes de déstigmatisation : information, contact social, témoignages de patients.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Foucault ("Naissance de la clinique", 1963 ; "Histoire de la folie", 1961) a montré comment la société a construit la notion de folie et comment l'enfermement servait le contrôle social autant que le soin. En France, ~13 millions de personnes sont concernées par un trouble psychique (1 Français sur 5 dans sa vie).</p></div>` },
  { id: 'ssh-genre-sante', subject: 'ssh', title: 'Genre et santé', summary: 'Médecine genrée, biais de genre, santé reproductive et intersectionnalité.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Genre et santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Sexe vs genre</h4><p class="mb-3"><strong>Sexe</strong> : caractéristiques biologiques (chromosomes, hormones, anatomie). <strong>Genre</strong> : construction sociale (rôles, comportements, identités assignés par la société). Les deux interagissent pour influencer la santé. La médecine a longtemps été androcentrée (homme blanc comme "norme").</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Biais de genre en médecine</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Recherche</strong> : les femmes ont longtemps été exclues des essais cliniques (risque tératogène). Les posologies sont calibrées sur un homme de 70 kg. Depuis 1993 (NIH) : inclusion obligatoire des femmes.</li><li><strong>Diagnostic</strong> : symptômes atypiques chez les femmes (infarctus sans douleur thoracique typique → diagnostic retardé). Maladies "féminines" sous-étudiées (endométriose : 7 ans de retard diagnostic moyen).</li><li><strong>Prise en charge</strong> : les douleurs des femmes sont plus souvent attribuées à des causes psychologiques. Prescription plus fréquente d'anxiolytiques aux femmes vs investigations complémentaires aux hommes pour les mêmes symptômes.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Différences de santé selon le sexe/genre</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Mortalité</strong> : les hommes meurent plus tôt (espérance de vie inférieure de ~6 ans). Causes : comportements à risque (tabac, alcool, accidents), recours aux soins plus tardif, professions plus dangereuses.</li><li><strong>Morbidité</strong> : les femmes vivent plus longtemps mais en moins bonne santé perçue. Plus de maladies chroniques, dépression (2x), maladies auto-immunes (3x).</li><li><strong>Santé reproductive</strong> : contraception (charge principalement féminine), violences obstétricales, ménopause.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : L'intersectionnalité (Crenshaw) montre que les inégalités se cumulent : être une femme + racisée + précaire amplifie les inégalités de santé. La médecine de genre (gender medicine) est un champ émergent qui vise à intégrer le sexe et le genre dans la recherche et la pratique clinique.</p></div>` },
  { id: 'ssh-ecologie-sante', subject: 'ssh', title: 'Écologie et santé', summary: 'One Health, perturbateurs endocriniens, changement climatique et santé.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Écologie et santé</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">One Health (Une seule santé)</h4><p class="mb-3">Approche intégrée : la santé humaine, animale et environnementale sont <strong>interdépendantes</strong>. 60% des maladies infectieuses humaines sont d'origine animale (zoonoses). 75% des maladies infectieuses émergentes sont zoonotiques (Ebola, SARS-CoV-2, grippe aviaire). La déforestation, l'urbanisation et l'élevage intensif augmentent les contacts homme-animal.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Changement climatique et santé</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li><strong>Effets directs</strong> : canicules (surmortalité, 15 000 décès en 2003 en France), catastrophes naturelles (inondations, tempêtes).</li><li><strong>Effets indirects</strong> : extension des maladies vectorielles (dengue, chikungunya → sud de la France), insécurité alimentaire (sécheresses, rendements agricoles), qualité de l'eau, pollution de l'air.</li><li><strong>Santé mentale</strong> : éco-anxiété, stress post-traumatique post-catastrophe, solastalgie.</li><li><strong>Populations vulnérables</strong> : enfants, personnes âgées, populations précaires, pays en développement.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Perturbateurs endocriniens (PE)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Substances chimiques qui interfèrent avec le système hormonal. Même à <strong>faibles doses</strong> (effet non monotone, courbe en U inversé).</li><li>Sources : pesticides, plastifiants (bisphénol A, phtalates), cosmétiques (parabènes), retardateurs de flamme.</li><li>Effets : troubles de la reproduction (baisse du sperme, puberté précoce), cancers hormono-dépendants (sein, prostate), troubles thyroïdiens, obésité, troubles neuro-développementaux.</li><li>Principe de précaution appliqué (ex : interdiction du BPA dans les contenants alimentaires en France depuis 2015).</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Pollution atmosphérique</h4><p class="mb-3">48 000 décès/an en France (particules fines PM2.5). Effets : maladies cardiovasculaires, respiratoires (asthme, BPCO), cancers du poumon, issues défavorables de grossesse. PM2.5 &lt; 2.5 microns → pénètrent dans les alvéoles et le sang.</p><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : La santé environnementale est devenue un enjeu majeur du PNSE (Plan National Santé Environnement). L'exposome = totalité des expositions environnementales d'un individu de la conception à la mort (complément du génome). Le Lancet a qualifié le changement climatique de "plus grande menace pour la santé mondiale au XXIe siècle".</p></div>` },
  { id: 'ssh-pharmacologie-sociale', subject: 'ssh', title: 'Pharmacologie sociale', summary: 'Observance, automédication, médicament comme objet social et placebo.', content: `<h3 class="text-xl font-bold text-gray-900 mb-4">Pharmacologie sociale</h3><h4 class="text-lg font-semibold text-gray-800 mb-2">Le médicament comme objet social</h4><p class="mb-3">Le médicament n'est pas qu'une molécule active : c'est aussi un <strong>objet symbolique</strong> (confiance, espoir, pouvoir médical), un <strong>objet économique</strong> (industrie pharmaceutique, brevets, génériques) et un <strong>objet politique</strong> (accès aux médicaments, prix, remboursement). La prescription est un acte social (valide le rôle de malade, marque la fin de la consultation).</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Observance (adhésion thérapeutique)</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Degré de concordance entre le comportement du patient et les recommandations du médecin. En moyenne, <strong>50% des patients chroniques</strong> ne suivent pas correctement leur traitement (OMS).</li><li>Facteurs d'inobservance : complexité du traitement, effets indésirables, absence de symptômes (HTA), coût (reste à charge), relation médecin-patient, croyances et représentations du patient.</li><li>On parle désormais d'<strong>adhésion</strong> (patient acteur) plutôt que d'observance (patient passif). Concordance = décision partagée médecin-patient.</li></ul><h4 class="text-lg font-semibold text-gray-800 mb-2">Automédication</h4><p class="mb-3">Utilisation de médicaments sans prescription médicale. En augmentation. Risques : interactions, surdosage, retard de diagnostic, masquage de symptômes. Encouragée par la vente en accès libre en pharmacie (paracétamol, AINS). Rôle du pharmacien dans le conseil.</p><h4 class="text-lg font-semibold text-gray-800 mb-2">Effet placebo</h4><ul class="list-disc pl-5 space-y-1 mb-4 text-gray-700"><li>Amélioration due à la <strong>croyance dans le traitement</strong>, pas à la substance elle-même. Mécanismes : endorphines, dopamine (récompense), conditionnement, attentes.</li><li>Effet nocebo : effets indésirables dus aux attentes négatives.</li><li>30% d'effet placebo moyen dans les essais cliniques. Plus important pour la douleur, les troubles fonctionnels, la dépression.</li><li>Le placebo n'est pas "rien" : la relation thérapeutique, l'empathie et le rituel de soin sont des composantes actives.</li></ul><div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mt-4"><p class="text-sm font-semibold text-rose-800">Point clé concours : Le brevet protège une molécule pendant 20 ans. Après expiration → génériques (même principe actif, bioéquivalence). Les biosimilaires sont l'équivalent des génériques pour les médicaments biologiques (pas identiques mais similaires). L'accès aux médicaments essentiels est un droit humain (OMS).</p></div>` },
];

